from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH432_sqlalchemy_13036'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH432_sqlalchemy_13036'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('abcense', 'abcense' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH432_sqlalchemy_13036',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'sqlalchemy/sqlalchemy',
                "pr_number": 13036,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/sqlalchemy/sqlalchemy/pull/13036",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'doc/build/core/connections.rst': '.. _connections_toplevel:\n\n====================================\nWorking with Engines and Connections\n====================================\n\n.. module:: sqlalchemy.engine\n\nThis section details direct usage of the :class:`_engine.Engine`,\n:class:`_engine.Connection`, and related objects. Its important to note that when\nusing the SQLAlchemy ORM, these objects are not generally accessed; instead,\nthe :class:`.Session` object is used as the interface to the database.\nHowever, for applications that are built around direct usage of textual SQL\nstatements and/or SQL expression constructs without involvement by the ORM\'s\nhigher level management services, the :class:`_engine.Engine` and\n:class:`_engine.Connection` are king (and queen?) - read on.\n\nBasic Usage\n-----------\n\nRecall from :doc:`/core/engines` that an :class:`_engine.Engine` is created via\nthe :func:`_sa.create_engine` call::\n\n    engine = create_engine("mysql+mysqldb://scott:tiger@localhost/test")\n\nThe typical usage of :func:`_sa.create_engine` is once per particular database\nURL, held globally for the lifetime of a single application process. A single\n:class:`_engine.Engine` manages many individual :term:`DBAPI` connections on behalf of\nthe process and is intended to be called upon in a concurrent fashion. The\n:class:`_engine.Engine` is **not** synonymous to the DBAPI ``connect()`` function, which\nrepresents just one connection resource - the :class:`_engine.Engine` is most\nefficient when created just once at the module level of an application, not\nper-object or per-function call.\n\n.. sidebar:: tip\n\n    When using an :class:`_engine.Engine` with multiple Python processes, such as when\n    using ``os.fork`` or Python ``multiprocessing``, it\'s important that the\n    engine is initialized per process.  See :ref:`pooling_multiprocessing` for\n    details.\n\nThe most basic function of the :class:`_engine.Engine` is to provide access to a\n:class:`_engine.Connection`, which can then invoke SQL statements.   To emit\na textual statement to the database looks like::\n\n    from sqlalchemy import text\n\n    with engine.connect() as connection:\n        result = connection.execute(text("select username from users"))\n        for row in result:\n            print("username:", row.username)\n\nAbove, the :meth:`_engine.Engine.connect` method returns a :class:`_engine.Connection`\nobject, and by using it in a Python context manager (e.g. the ``with:``\nstatement) the :meth:`_engine.Connection.close` method is automatically invoked at the\nend of the block.  The :class:`_engine.Connection`, is a **proxy** object for an\nactual DBAPI connection. The DBAPI connection is retrieved from the connection\npool at the point at which :class:`_engine.Connection` is created.\n\nThe object returned is known as :class:`_engine.CursorResult`, which\nreferences a DBAPI cursor and provides methods for fetching rows\nsimilar to that of the DBAPI cursor.   The DBAPI cursor will be closed\nby the :class:`_engine.CursorResult` when all of its result rows (if any) are\nexhausted.  A :class:`_engine.CursorResult` that returns no rows, such as that of\nan UPDATE statement (without any returned rows),\nreleases cursor resources immediately upon construction.\n\nWhen the :class:`_engine.Connection` is closed at the end of the ``with:`` block, the\nreferenced DBAPI connection is :term:`released` to the connection pool.   From\nthe perspective of the database itself, the connection pool will not actually\n"close" the connection assuming the pool has room to store this connection  for\nthe next use.  When the connection is returned to the pool for re-use, the\npooling mechanism issues a ``rollback()`` call on the DBAPI connection so that\nany transactional state or locks are removed (this is known as\n:ref:`pool_reset_on_return`), and the connection is ready for its next use.\n\nOur example above illustrated the execution of a textual SQL string, which\nshould be invoked by using the :func:`_expression.text` construct to indicate that\nwe\'d like to use textual SQL.  The :meth:`_engine.Connection.execute` method can of\ncourse accommodate more than that; see :ref:`tutorial_working_with_data`\nin the :ref:`unified_tutorial` for a tutorial.\n\n\nUsing Transactions\n------------------\n\n.. note::\n\n  This section describes how to use transactions when working directly\n  with :class:`_engine.Engine` and :class:`_engine.Connection` objects. When using the\n  SQLAlchemy ORM, the public API for transaction control is via the\n  :class:`.Session` object, which makes usage of the :class:`.Transaction`\n  object internally. See :ref:`unitofwork_transaction` for further\n  information.\n\nCommit As You Go\n~~~~~~~~~~~~~~~~\n\nThe :class:`~sqlalchemy.engine.Connection` object always emits SQL statements\nwithin the context of a transaction block.   The first time the\n:meth:`_engine.Connection.execute` method is called to execute a SQL\nstatement, this transaction is begun automatically, using a behavior known\nas **autobegin**.  The transaction remains in place for the scope of the\n:class:`_engine.Connection` object until the :meth:`_engine.Connection.commit`\nor :meth:`_engine.Connection.rollback` methods are called.  Subsequent\nto the transaction ending, the :class:`_engine.Connection` waits for the\n:meth:`_engine.Connection.execute` method to be called again, at which point\nit autobegins again.\n\nThis calling style is known as **commit as you go**, and is\nillustrated in the example below::\n\n    with engine.connect() as connection:\n        connection.execute(some_table.insert(), {"x": 7, "y": "this is some data"})\n        connection.execute(\n            some_other_table.insert(), {"q": 8, "p": "this is some more data"}\n        )\n\n        connection.commit()  # commit the transaction\n\n.. topic::  the Python DBAPI is where autobegin actually happens\n\n    The design of "commit as you go" is intended to be complementary to the\n    design of the :term:`DBAPI`, which is the underlying database interface\n    that SQLAlchemy interacts with. In the DBAPI, the ``connection`` object does\n    not assume changes to the database will be automatically committed, instead\n    requiring in the default case that the ``connection.commit()`` method is\n    called in order to commit changes to the database. It should be noted that\n    the DBAPI itself **does not have a begin() method at all**.  All\n    Python DBAPIs implement "autobegin" as the primary means of managing\n    transactions, and handle the job of emitting a statement like BEGIN on the\n    connection when SQL statements are first emitted.\n    SQLAlchemy\'s API is basically re-stating this behavior in terms of higher\n    level Python objects.\n\nIn "commit as you go" style, we can call upon :meth:`_engine.Connection.commit`\nand :meth:`_engine.Connection.rollback` methods freely within an ongoing\nsequence of other statements emitted using :meth:`_engine.Connection.execute`;\neach time the transaction is ended, and a new statement is\nemitted, a new transaction begins implicitly::\n\n    with engine.connect() as connection:\n        connection.execute(text("<some statement>"))\n        connection.commit()  # commits "some statement"\n\n        # new transaction starts\n        connection.execute(text("<some other statement>"))\n        connection.rollback()  # rolls back "some other statement"\n\n        # new transaction starts\n        connection.execute(text("<a third statement>"))\n        connection.commit()  # commits "a third statement"\n\n.. versionadded:: 2.0 "commit as you go" style is a new feature of\n   SQLAlchemy 2.0.  It is also available in SQLAlchemy 1.4\'s "transitional"\n   mode when using a "future" style engine.\n\nBegin Once\n~~~~~~~~~~\n\nThe :class:`_engine.Connection` object provides a more explicit transaction\nmanagement style known as **begin once**. In contrast to "commit as\nyou go", "begin once" allows the start point of the transaction to be\nstated explicitly,\nand allows that the transaction itself may be framed out as a context manager\nblock so that the end of the transaction is instead implicit. To use\n"begin once", the :meth:`_engine.Connection.begin` method is used, which returns a\n:class:`.Transaction` object which represents the DBAPI transaction.\nThis object also supports explicit management via its own\n:meth:`_engine.Transaction.commit` and :meth:`_engine.Transaction.rollback`\nmethods, but as a preferred practice also supports the context manager interface,\nwhere it will commit itself when\nthe block ends normally and emit a rollback if an exception is raised, before\npropagating the exception outwards. Below illustrates the form of a "begin\nonce" block::\n\n    with engine.connect() as connection:\n        with connection.begin():\n            connection.execute(some_table.insert(), {"x": 7, "y": "this is some data"})\n            connection.execute(\n                some_other_table.insert(), {"q": 8, "p": "this is some more data"}\n            )\n\n        # transaction is committed\n\nConnect and Begin Once from the Engine\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nA convenient shorthand form for the above "begin once" block is to use\nthe :meth:`_engine.Engine.begin` method at the level of the originating\n:class:`_engine.Engine` object, rather than performing the two separate\nsteps of :meth:`_engine.Engine.connect` and :meth:`_engine.Connection.begin`;\nthe :meth:`_engine.Engine.begin` method returns a special context manager\nthat internally maintains both the context manager for the :class:`_engine.Connection`\nas well as the context manager for the :class:`_engine.Transaction` normally\nreturned by the :meth:`_engine.Connection.begin` method::\n\n    with engine.begin() as connection:\n        connection.execute(some_table.insert(), {"x": 7, "y": "this is some data"})\n        connection.execute(\n            some_other_table.insert(), {"q": 8, "p": "this is some more data"}\n        )\n\n    # transaction is committed, and Connection is released to the connection\n    # pool\n\n.. tip::\n\n    Within the :meth:`_engine.Engine.begin` block, we can call upon the\n    :meth:`_engine.Connection.commit` or :meth:`_engine.Connection.rollback`\n    methods, which will end the transaction normally demarcated by the block\n    ahead of time.  However, if we do so, no further SQL operations may be\n    emitted on the :class:`_engine.Connection` until the block ends::\n\n        >>> from sqlalchemy import create_engine\n        >>> e = create_engine("sqlite://", echo=True)\n        >>> with e.begin() as conn:\n        ...     conn.commit()\n        ...     conn.begin()\n        2021-11-08 09:49:07,517 INFO sqlalchemy.engine.Engine BEGIN (implicit)\n        2021-11-08 09:49:07,517 INFO sqlalchemy.engine.Engine COMMIT\n        Traceback (most recent call last):\n        ...\n        sqlalchemy.exc.InvalidRequestError: Can\'t operate on closed transaction inside\n        context manager.  Please complete the context manager before emitting\n        further commands.\n\nMixing Styles\n~~~~~~~~~~~~~\n\nThe "commit as you go" and "begin once" styles can be freely mixed within\na single :meth:`_engine.Engine.connect` block, provided that the call to\n:meth:`_engine.Connection.begin` does not conflict with the "autobegin"\nbehavior.  To accomplish this, :meth:`_engine.Connection.begin` should only\nbe called either before any SQL statements have been emitted, or directly\nafter a previous call to :meth:`_engine.Connection.commit` or :meth:`_engine.Connection.rollback`::\n\n    with engine.connect() as connection:\n        with connection.begin():\n            # run statements in a "begin once" block\n            connection.execute(some_table.insert(), {"x": 7, "y": "this is some data"})\n\n        # transaction is committed\n\n        # run a new statement outside of a block. The connection\n        # autobegins\n        connection.execute(\n            some_other_table.insert(), {"q": 8, "p": "this is some more data"}\n        )\n\n        # commit explicitly\n        connection.commit()\n\n        # can use a "begin once" block here\n        with connection.begin():\n            # run more statements\n            connection.execute(...)\n\nWhen developing code that uses "begin once", the library will raise\n:class:`_exc.InvalidRequestError` if a transaction was already "autobegun".\n\n.. _dbapi_autocommit:\n\nSetting Transaction Isolation Levels including DBAPI Autocommit\n---------------------------------------------------------------\n\nMost DBAPIs support the concept of configurable transaction :term:`isolation` levels.\nThese are traditionally the four levels "READ UNCOMMITTED", "READ COMMITTED",\n"REPEATABLE READ" and "SERIALIZABLE".  These are usually applied to a\nDBAPI connection before it begins a new transaction, noting that most\nDBAPIs will begin this transaction implicitly when SQL statements are first\nemitted.\n\nDBAPIs that support isolation levels also usually support the concept of true\n"autocommit", which means that the DBAPI connection itself will be placed into\na non-transactional autocommit mode. This usually means that the typical DBAPI\nbehavior of emitting "BEGIN" to the database automatically no longer occurs,\nbut it may also include other directives. SQLAlchemy treats the concept of\n"autocommit" like any other isolation level; in that it is an isolation level\nthat loses not only "read committed" but also loses atomicity.\n\n.. tip::\n\n  It is important to note, as will be discussed further in the section below at\n  :ref:`dbapi_autocommit_understanding`, that "autocommit" isolation level like\n  any other isolation level does **not** affect the "transactional" behavior of\n  the :class:`_engine.Connection` object, which continues to call upon DBAPI\n  ``.commit()`` and ``.rollback()`` methods (they just have no net effect under\n  autocommit), and for which the ``.begin()`` method assumes the DBAPI will\n  start a transaction implicitly (which means that SQLAlchemy\'s "begin" **does\n  not change autocommit mode**).\n\nSQLAlchemy dialects should support these isolation levels as well as autocommit\nto as great a degree as possible.\n\nSetting Isolation Level or DBAPI Autocommit for a Connection\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nFor an individual :class:`_engine.Connection` object that\'s acquired from\n:meth:`.Engine.connect`, the isolation level can be set for the duration of\nthat :class:`_engine.Connection` object using the\n:meth:`_engine.Connection.execution_options` method. The parameter is known as\n:paramref:`_engine.Connection.execution_options.isolation_level` and the values\nare strings which are typically a subset of the following names::\n\n    # possible values for Connection.execution_options(isolation_level="<value>")\n\n    "AUTOCOMMIT"\n    "READ COMMITTED"\n    "READ UNCOMMITTED"\n    "REPEATABLE READ"\n    "SERIALIZABLE"\n\nNot every DBAPI supports every value; if an unsupported value is used for a\ncertain backend, an error is raised.\n\nFor example, to force REPEATABLE READ on a specific connection, then\nbegin a transaction::\n\n    with engine.connect().execution_options(\n        isolation_level="REPEATABLE READ"\n    ) as connection:\n        with connection.begin():\n            connection.execute(text("<statement>"))\n\n.. tip::  The return value of\n   the :meth:`_engine.Connection.execution_options` method is the same\n   :class:`_engine.Connection` object upon which the method was called,\n   meaning, it modifies the state of the :class:`_engine.Connection`\n   object in place.  This is a new behavior as of SQLAlchemy 2.0.\n   This behavior does not apply to the :meth:`_engine.Engine.execution_options`\n   method; that method still returns a copy of the :class:`.Engine` and\n   as described below may be used to construct multiple :class:`.Engine`\n   objects with different execution options, which nonetheless share the same\n   dialect and connection pool.\n\n.. note:: The :paramref:`_engine.Connection.execution_options.isolation_level`\n   parameter necessarily does not apply to statement level options, such as\n   that of :meth:`_sql.Executable.execution_options`, and will be rejected if\n   set at this level. This because the option must be set on a DBAPI connection\n   on a per-transaction basis.\n\n.. _dbapi_autocommit_engine:\n\nSetting Isolation Level or DBAPI Autocommit for an Engine\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe :paramref:`_engine.Connection.execution_options.isolation_level` option may\nalso be set engine wide, as is often preferable.  This may be\nachieved by passing the :paramref:`_sa.create_engine.isolation_level`\nparameter to :func:`.sa.create_engine`::\n\n    from sqlalchemy import create_engine\n\n    eng = create_engine(\n        "postgresql://scott:tiger@localhost/test", isolation_level="REPEATABLE READ"\n    )\n\nWith the above setting, each new DBAPI connection the moment it\'s created will\nbe set to use a ``"REPEATABLE READ"`` isolation level setting for all\nsubsequent operations.\n\n.. tip::\n\n    Prefer to set frequently used isolation levels engine wide as illustrated\n    above compared to using per-engine or per-connection execution options for\n    maximum performance.\n\n.. _dbapi_autocommit_multiple:\n\nMaintaining Multiple Isolation Levels for a Single Engine\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe isolation level may also be set per engine, with a potentially greater\nlevel of flexibility but with a small per-connection performance overhead,\nusing either the :paramref:`_sa.create_engine.execution_options` parameter to\n:func:`_sa.create_engine` or the :meth:`_engine.Engine.execution_options`\nmethod, the latter of which will create a copy of the :class:`.Engine` that\nshares the dialect and connection pool of the original engine, but has its own\nper-connection isolation level setting::\n\n    from sqlalchemy import create_engine\n\n    eng = create_engine(\n        "postgresql+psycopg2://scott:tiger@localhost/test",\n        execution_options={"isolation_level": "REPEATABLE READ"},\n    )\n\nWith the above setting, the DBAPI connection will be set to use a\n``"REPEATABLE READ"`` isolation level setting for each new transaction\nbegun; but the connection as pooled will be reset to the original isolation\nlevel that was present when the connection first occurred.   At the level\nof :func:`_sa.create_engine`, the end effect is not any different\nfrom using the :paramref:`_sa.create_engine.isolation_level` parameter.\n\nHowever, an application that frequently chooses to run operations within\ndifferent isolation levels may wish to create multiple "sub-engines" of a lead\n:class:`_engine.Engine`, each of which will be configured to a different\nisolation level. One such use case is an application that has operations that\nbreak into "transactional" and "read-only" operations, a separate\n:class:`_engine.Engine` that makes use of ``"AUTOCOMMIT"`` may be separated off\nfrom the main engine::\n\n    from sqlalchemy import create_engine\n\n    eng = create_engine("postgresql+psycopg2://scott:tiger@localhost/test")\n\n    autocommit_engine = eng.execution_options(isolation_level="AUTOCOMMIT")\n\nAbove, the :meth:`_engine.Engine.execution_options` method creates a shallow\ncopy of the original :class:`_engine.Engine`.  Both ``eng`` and\n``autocommit_engine`` share the same dialect and connection pool.  However, the\n"AUTOCOMMIT" mode will be set upon connections when they are acquired from the\n``autocommit_engine``.\n\nThe isolation level setting, regardless of which one it is, is unconditionally\nreverted when a connection is returned to the connection pool.\n\n.. note::\n\n    The execution options approach, whether used engine wide or per connection,\n    incurs a small performance penalty as isolation level instructions\n    are sent on connection acquire as well as connection release.   Consider\n    the engine-wide isolation setting at :ref:`dbapi_autocommit_engine` so\n    that connections are configured at the target isolation level permanently\n    as they are pooled.\n\n.. seealso::\n\n      :ref:`SQLite Transaction Isolation <sqlite_isolation_level>`\n\n      :ref:`PostgreSQL Transaction Isolation <postgresql_isolation_level>`\n\n      :ref:`MySQL Transaction Isolation <mysql_isolation_level>`\n\n      :ref:`SQL Server Transaction Isolation <mssql_isolation_level>`\n\n      :ref:`Oracle Database Transaction Isolation <oracle_isolation_level>`\n\n      :ref:`session_transaction_isolation` - for the ORM\n\n      :ref:`faq_execute_retry_autocommit` - a recipe that uses DBAPI autocommit\n      to transparently reconnect to the database for read-only operations\n\n.. _dbapi_autocommit_understanding:\n\nUnderstanding the DBAPI-Level Autocommit Isolation Level\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nIn the parent section, we introduced the concept of the\n:paramref:`_engine.Connection.execution_options.isolation_level`\nparameter and how it can be used to set database isolation levels, including\nDBAPI-level "autocommit" which is treated by SQLAlchemy as another transaction\nisolation level.   In this section we will attempt to clarify the implications\nof this approach.\n\nIf we wanted to check out a :class:`_engine.Connection` object and use it\n"autocommit" mode, we would proceed as follows::\n\n    with engine.connect() as connection:\n        connection.execution_options(isolation_level="AUTOCOMMIT")\n        connection.execute(text("<statement>"))\n        connection.execute(text("<statement>"))\n\nAbove illustrates normal usage of "DBAPI autocommit" mode.   There is no\nneed to make use of methods such as :meth:`_engine.Connection.begin`\nor :meth:`_engine.Connection.commit`, as all statements are committed\nto the database immediately.  When the block ends, the :class:`_engine.Connection`\nobject will revert the "autocommit" isolation level, and the DBAPI connection\nis released to the connection pool where the DBAPI ``connection.rollback()``\nmethod will normally be invoked, but as the above statements were already\ncommitted, this rollback has no change on the state of the database.\n\nIt is important to note that "autocommit" mode\npersists even when the :meth:`_engine.Connection.begin` method is called;\nthe DBAPI will not emit any BEGIN to the database.   When\n:meth:`_engine.Connection.commit` is called, the DBAPI may still emit the\n"COMMIT" instruction, but this is a no-op at the database level.  This usage is also\nnot an error scenario, as it is expected that the "autocommit" isolation level\nmay be applied to code that otherwise was written assuming a transactional context;\nthe "isolation level" is, after all, a configurational detail of the transaction\nitself just like any other isolation level.\n\nIn the example below, statements remain\n**autocommitting** regardless of SQLAlchemy-level transaction blocks::\n\n    with engine.connect() as connection:\n        connection = connection.execution_options(isolation_level="AUTOCOMMIT")\n\n        # this begin() does not affect the DBAPI connection, isolation stays at AUTOCOMMIT\n        with connection.begin() as trans:\n            connection.execute(text("<statement>"))\n            connection.execute(text("<statement>"))\n\nWhen we run a block like the above with logging turned on, the logging\nwill attempt to indicate that while a DBAPI level ``.commit()`` is called,\nit probably will have no effect due to autocommit mode:\n\n.. sourcecode:: text\n\n    INFO sqlalchemy.engine.Engine BEGIN (implicit)\n    ...\n    INFO sqlalchemy.engine.Engine COMMIT using DBAPI connection.commit(), has no effect due to autocommit mode\n\nAt the same time, even though we are using "DBAPI autocommit", SQLAlchemy\'s\ntransactional semantics, that is, the in-Python behavior of :meth:`_engine.Connection.begin`\nas well as the behavior of "autobegin", **remain in place, even though these\ndon\'t impact the DBAPI connection itself**.  To illustrate, the code\nbelow will raise an error, as :meth:`_engine.Connection.begin` is being\ncalled after autobegin has already occurred::\n\n    with engine.connect() as connection:\n        connection = connection.execution_options(isolation_level="AUTOCOMMIT")\n\n        # "transaction" is autobegin (but has no effect due to autocommit)\n        connection.execute(text("<statement>"))\n\n        # this will raise; "transaction" is already begun\n        with connection.begin() as trans:\n            connection.execute(text("<statement>"))\n\nThe above example also demonstrates the same theme that the "autocommit"\nisolation level is a configurational detail of the underlying database\ntransaction, and is independent of the begin/commit behavior of the SQLAlchemy\nConnection object. The "autocommit" mode will not interact with\n:meth:`_engine.Connection.begin` in any way and the :class:`_engine.Connection`\ndoes not consult this status when performing its own state changes with regards\nto the transaction (with the exception of suggesting within engine logging that\nthese blocks are not actually committing). The rationale for this design is to\nmaintain a completely consistent usage pattern with the\n:class:`_engine.Connection` where DBAPI-autocommit mode can be changed\nindependently without indicating any code changes elsewhere.\n\n.. _dbapi_autocommit_skip_rollback:\n\nFully preventing ROLLBACK calls under autocommit\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n.. versionadded:: 2.0.43\n\nA common use case is to use AUTOCOMMIT isolation mode to improve performance,\nand this is a particularly common practice on MySQL / MariaDB databases.\nWhen seeking this pattern, it should be preferred to set AUTOCOMMIT engine\nwide using the :paramref:`.create_engine.isolation_level` so that pooled\nconnections are permanently set in autocommit mode.   The SQLAlchemy connection\npool as well as the :class:`.Connection` will still seek to invoke the DBAPI\n``.rollback()`` method upon connection :term:`release`, as their behavior\nremains agonstic of the isolation level that\'s configured on the connection.\nAs this rollback still incurs a network round trip under most if not all\nDBAPI drivers, this additional network trip may be disabled using the\n:paramref:`.create_engine.skip_autocommit_rollback` parameter, which will\napply a rule at the basemost portion of the dialect that invokes DBAPI\n``.rollback()`` to first check if the connection is configured in autocommit,\nusing a method of detection that does not itself incur network overhead::\n\n    autocommit_engine = create_engine(\n        "mysql+mysqldb://scott:tiger@mysql80/test",\n        skip_autocommit_rollback=True,\n        isolation_level="AUTOCOMMIT",\n    )\n\nWhen DBAPI connections are returned to the pool by the :class:`.Connection`,\nwhether the :class:`.Connection` or the pool attempts to reset the\n"transaction", the underlying DBAPI ``.rollback()`` method will be blocked\nbased on a positive test of "autocommit".\n\nIf the dialect in use does not support a no-network means of detecting\nautocommit, the dialect will raise ``NotImplementedError`` when a connection\nrelease is attempted.\n\nChanging Between Isolation Levels\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n.. topic:: TL;DR;\n\n    prefer to use individual :class:`_engine.Connection` objects\n    each with just one isolation level, rather than switching isolation on a single\n    :class:`_engine.Connection`.  The code will be easier to read and less\n    error prone.\n\nIsolation level settings, including autocommit mode, are reset automatically\nwhen the connection is released back to the connection pool. Therefore it is\npreferable to avoid trying to switch isolation levels on a single\n:class:`_engine.Connection` object as this leads to excess verbosity.\n\nTo illustrate how to use "autocommit" in an ad-hoc mode within the scope of a\nsingle :class:`_engine.Connection` checkout, the\n:paramref:`_engine.Connection.execution_options.isolation_level` parameter\nmust be re-applied with the previous isolation level.\nThe previous section illustrated an attempt to call :meth:`_engine.Connection.begin`\nin order to start a transaction while autocommit was taking place; we can\nrewrite that example to actually do so by first reverting the isolation level\nbefore we call upon :meth:`_engine.Connection.begin`::\n\n    # if we wanted to flip autocommit on and off on a single connection/\n    # which... we usually don\'t.\n\n    with engine.connect() as connection:\n        connection.execution_options(isolation_level="AUTOCOMMIT")\n\n        # run statement(s) in autocommit mode\n        connection.execute(text("<statement>"))\n\n        # "commit" the autobegun "transaction"\n        connection.commit()\n\n        # switch to default isolation level\n        connection.execution_options(isolation_level=connection.default_isolation_level)\n\n        # use a begin block\n        with connection.begin() as trans:\n            connection.execute(text("<statement>"))\n\nAbove, to manually revert the isolation level we made use of\n:attr:`_engine.Connection.default_isolation_level` to restore the default\nisolation level (assuming that\'s what we want here). However, it\'s\nprobably a better idea to work with the architecture of of the\n:class:`_engine.Connection` which already handles resetting of isolation level\nautomatically upon checkin. The **preferred** way to write the above is to\nuse two blocks ::\n\n    # use an autocommit block\n    with engine.connect().execution_options(isolation_level="AUTOCOMMIT") as connection:\n        # run statement in autocommit mode\n        connection.execute(text("<statement>"))\n\n    # use a regular block\n    with engine.begin() as connection:\n        connection.execute(text("<statement>"))\n\nTo sum up:\n\n1. "DBAPI level autocommit" isolation level is entirely independent of the\n   :class:`_engine.Connection` object\'s notion of "begin" and "commit"\n2. use individual :class:`_engine.Connection` checkouts per isolation level.\n   Avoid trying to change back and forth between "autocommit" on a single\n   connection checkout; let the engine do the work of restoring default\n   isolation levels\n\n.. _engine_stream_results:\n\nUsing Server Side Cursors (a.k.a. stream results)\n-------------------------------------------------\n\nSome backends feature explicit support for the concept of "server side cursors"\nversus "client side cursors".  A client side cursor here means that the\ndatabase driver fully fetches all rows from a result set into memory before\nreturning from a statement execution.  Drivers such as those of PostgreSQL and\nMySQL/MariaDB generally use client side cursors by default.  A server side\ncursor, by contrast, indicates that result rows remain pending within the\ndatabase server\'s state as result rows are consumed by the client.  The drivers\nfor Oracle Database generally use a "server side" model, for example, and the\nSQLite dialect, while not using a real "client / server" architecture, still\nuses an unbuffered result fetching approach that will leave result rows outside\nof process memory before they are consumed.\n\n.. topic:: What we really mean is "buffered" vs. "unbuffered" results\n\n  Server side cursors also imply a wider set of features with relational\n  databases, such as the ability to "scroll" a cursor forwards and backwards.\n  SQLAlchemy does not include any explicit support for these behaviors; within\n  SQLAlchemy itself, the general term "server side cursors" should be considered\n  to mean "unbuffered results" and "client side cursors" means "result rows\n  are buffered into memory before the first row is returned".   To work with\n  a richer "server side cursor" featureset specific to a certain DBAPI driver,\n  see the section :ref:`dbapi_connections_cursor`.\n\nFrom this basic architecture it follows that a "server side cursor" is more\nmemory efficient when fetching very large result sets, while at the same time\nmay introduce more complexity in the client/server communication process\nand be less efficient for small result sets (typically less than 10000 rows).\n\nFor those dialects that have conditional support for buffered or unbuffered\nresults, there are usually caveats to the use of the "unbuffered", or server\nside cursor mode.   When using the psycopg2 dialect for example, an error is\nraised if a server side cursor is used with any kind of DML or DDL statement.\nWhen using MySQL drivers with a server side cursor, the DBAPI connection is in\na more fragile state and does not recover as gracefully from error conditions\nnor will it allow a rollback to proceed until the cursor is fully closed.\n\nFor this reason, SQLAlchemy\'s dialects will always default to the less error\nprone version of a cursor, which means for PostgreSQL and MySQL dialects\nit defaults to a buffered, "client side" cursor where the full set of results\nis pulled into memory before any fetch methods are called from the cursor.\nThis mode of operation is appropriate in the **vast majority** of cases;\nunbuffered cursors are not generally useful except in the uncommon case\nof an application fetching a very large number of rows in chunks, where\nthe processing of these rows can be complete before more rows are fetched.\n\nFor database drivers that provide client and server side cursor options,\nthe :paramref:`_engine.Connection.execution_options.stream_results`\nand :paramref:`_engine.Connection.execution_options.yield_per` execution\noptions provide access to "server side cursors" on a per-:class:`_engine.Connection`\nor per-statement basis.    Similar options exist when using an ORM\n:class:`_orm.Session` as well.\n\n\nStreaming with a fixed buffer via yield_per\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nAs individual row-fetch operations with fully unbuffered server side cursors\nare typically more expensive than fetching batches of rows at once, The\n:paramref:`_engine.Connection.execution_options.yield_per` execution option\nconfigures a :class:`_engine.Connection` or statement to make use of\nserver-side cursors as are available, while at the same time configuring a\nfixed-size buffer of rows that will retrieve rows from the server in batches as\nthey are consumed. This parameter may be to a positive integer value using the\n:meth:`_engine.Connection.execution_options` method on\n:class:`_engine.Connection` or on a statement using the\n:meth:`.Executable.execution_options` method.\n\n.. versionadded:: 1.4.40 :paramref:`_engine.Connection.execution_options.yield_per` as a\n   Core-only option is new as of SQLAlchemy 1.4.40; for prior 1.4 versions,\n   use :paramref:`_engine.Connection.execution_options.stream_results`\n   directly in combination with :meth:`_engine.Result.yield_per`.\n\nUsing this option is equivalent to manually setting the\n:paramref:`_engine.Connection.execution_options.stream_results` option,\ndescribed in the next section, and then invoking the\n:meth:`_engine.Result.yield_per` method on the :class:`_engine.Result`\nobject with the given integer value.   In both cases, the effect this\ncombination has includes:\n\n* server side cursors mode is selected for the given backend, if available\n  and not already the default behavior for that backend\n* as result rows are fetched, they will be buffered in batches, where the\n  size of each batch up until the last batch will be equal to the integer\n  argument passed to the\n  :paramref:`_engine.Connection.execution_options.yield_per` option or the\n  :meth:`_engine.Result.yield_per` method; the last batch is then sized against\n  the remaining rows fewer than this size\n* The default partition size used by the :meth:`_engine.Result.partitions`\n  method, if used, will be made equal to this integer size as well.\n\nThese three behaviors are illustrated in the example below::\n\n    with engine.connect() as conn:\n        with conn.execution_options(yield_per=100).execute(\n            text("select * from table")\n        ) as result:\n            for partition in result.partitions():\n                # partition is an iterable that will be at most 100 items\n                for row in partition:\n                    print(f"{row}")\n\nThe above example illustrates the combination of ``yield_per=100`` along\nwith using the :meth:`_engine.Result.partitions` method to run processing\non rows in batches that match the size fetched from the server.   The\nuse of :meth:`_engine.Result.partitions` is optional, and if the\n:class:`_engine.Result` is iterated directly, a new batch of rows will be\nbuffered for each 100 rows fetched.    Calling a method such as\n:meth:`_engine.Result.all` should **not** be used, as this will fully\nfetch all remaining rows at once and defeat the purpose of using ``yield_per``.\n\n.. tip::\n\n    The :class:`.Result` object may be used as a context manager as illustrated\n    above.  When iterating with a server-side cursor, this is the best way to\n    ensure the :class:`.Result` object is closed, even if exceptions are\n    raised within the iteration process.\n\nThe :paramref:`_engine.Connection.execution_options.yield_per` option\nis portable to the ORM as well, used by a :class:`_orm.Session` to fetch\nORM objects, where it also limits the amount of ORM objects generated at once.\nSee the section :ref:`orm_queryguide_yield_per` - in the :ref:`queryguide_toplevel`\nfor further background on using\n:paramref:`_engine.Connection.execution_options.yield_per` with the ORM.\n\n.. versionadded:: 1.4.40 Added\n   :paramref:`_engine.Connection.execution_options.yield_per`\n   as a Core level execution option to conveniently set streaming results,\n   buffer size, and partition size all at once in a manner that is transferrable\n   to that of the ORM\'s similar use case.\n\n.. _engine_stream_results_sr:\n\nStreaming with a dynamically growing buffer using stream_results\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nTo enable server side cursors without a specific partition size, the\n:paramref:`_engine.Connection.execution_options.stream_results` option may be\nused, which like :paramref:`_engine.Connection.execution_options.yield_per` may\nbe called on the :class:`_engine.Connection` object or the statement object.\n\nWhen a :class:`_engine.Result` object delivered using the\n:paramref:`_engine.Connection.execution_options.stream_results` option\nis iterated directly, rows are fetched internally\nusing a default buffering scheme that buffers first a small set of rows,\nthen a larger and larger buffer on each fetch up to a pre-configured limit\nof 1000 rows.   The maximum size of this buffer can be affected using the\n:paramref:`_engine.Connection.execution_options.max_row_buffer` execution option::\n\n    with engine.connect() as conn:\n        with conn.execution_options(stream_results=True, max_row_buffer=100).execute(\n            text("select * from table")\n        ) as result:\n            for row in result:\n                print(f"{row}")\n\nWhile the :paramref:`_engine.Connection.execution_options.stream_results`\noption may be combined with use of the :meth:`_engine.Result.partitions`\nmethod, a specific partition size should be passed to\n:meth:`_engine.Result.partitions` so that the entire result is not fetched.\nIt is usually more straightforward to use the\n:paramref:`_engine.Connection.execution_options.yield_per` option when setting\nup to use the :meth:`_engine.Result.partitions` method.\n\n.. seealso::\n\n    :ref:`orm_queryguide_yield_per` - in the :ref:`queryguide_toplevel`\n\n    :meth:`_engine.Result.partitions`\n\n    :meth:`_engine.Result.yield_per`\n\n\n.. _schema_translating:\n\nTranslation of Schema Names\n---------------------------\n\nTo support multi-tenancy applications that distribute common sets of tables\ninto multiple schemas, the\n:paramref:`.Connection.execution_options.schema_translate_map`\nexecution option may be used to repurpose a set of :class:`_schema.Table` objects\nto render under different schema names without any changes.\n\nGiven a table::\n\n    user_table = Table(\n        "user",\n        metadata_obj,\n        Column("id", Integer, primary_key=True),\n        Column("name", String(50)),\n    )\n\nThe "schema" of this :class:`_schema.Table` as defined by the\n:paramref:`_schema.Table.schema` attribute is ``None``.  The\n:paramref:`.Connection.execution_options.schema_translate_map` can specify\nthat all :class:`_schema.Table` objects with a schema of ``None`` would instead\nrender the schema as ``user_schema_one``::\n\n    connection = engine.connect().execution_options(\n        schema_translate_map={None: "user_schema_one"}\n    )\n\n    result = connection.execute(user_table.select())\n\nThe above code will invoke SQL on the database of the form:\n\n.. sourcecode:: sql\n\n    SELECT user_schema_one.user.id, user_schema_one.user.name FROM\n    user_schema_one.user\n\nThat is, the schema name is substituted with our translated name.  The\nmap can specify any number of target->destination schemas::\n\n    connection = engine.connect().execution_options(\n        schema_translate_map={\n            None: "user_schema_one",  # no schema name -> "user_schema_one"\n            "special": "special_schema",  # schema="special" becomes "special_schema"\n            "public": None,  # Table objects with schema="public" will render with no schema\n        }\n    )\n\nThe :paramref:`.Connection.execution_options.schema_translate_map` parameter\naffects all DDL and SQL constructs generated from the SQL expression language,\nas derived from the :class:`_schema.Table` or :class:`.Sequence` objects.\nIt does **not** impact literal string SQL used via the :func:`_expression.text`\nconstruct nor via plain strings passed to :meth:`_engine.Connection.execute`.\n\nThe feature takes effect **only** in those cases where the name of the\nschema is derived directly from that of a :class:`_schema.Table` or :class:`.Sequence`;\nit does not impact methods where a string schema name is passed directly.\nBy this pattern, it takes effect within the "can create" / "can drop" checks\nperformed by methods such as :meth:`_schema.MetaData.create_all` or\n:meth:`_schema.MetaData.drop_all` are called, and it takes effect when\nusing table reflection given a :class:`_schema.Table` object.  However it does\n**not** affect the operations present on the :class:`_reflection.Inspector` object,\nas the schema name is passed to these methods explicitly.\n\n.. tip::\n\n  To use the schema translation feature with the ORM :class:`_orm.Session`,\n  set this option at the level of the :class:`_engine.Engine`, then pass that engine\n  to the :class:`_orm.Session`.  The :class:`_orm.Session` uses a new\n  :class:`_engine.Connection` for each transaction::\n\n      schema_engine = engine.execution_options(schema_translate_map={...})\n\n      session = Session(schema_engine)\n\n      ...\n\n  .. warning::\n\n    When using the ORM :class:`_orm.Session` without extensions, the schema\n    translate feature is only supported as\n    **a single schema translate map per Session**.   It will **not work** if\n    different schema translate maps are given on a per-statement basis, as\n    the ORM :class:`_orm.Session` does not take current schema translate\n    values into account for individual objects.\n\n    To use a single :class:`_orm.Session` with multiple ``schema_translate_map``\n    configurations, the :ref:`horizontal_sharding_toplevel` extension may\n    be used.  See the example at :ref:`examples_sharding`.\n\n.. _sql_caching:\n\n\nSQL Compilation Caching\n-----------------------\n\n.. versionadded:: 1.4  SQLAlchemy now has a transparent query caching system\n   that substantially lowers the Python computational overhead involved in\n   converting SQL statement constructs into SQL strings across both\n   Core and ORM.   See the introduction at :ref:`change_4639`.\n\nSQLAlchemy includes a comprehensive caching system for the SQL compiler as well\nas its ORM variants.   This caching system is transparent within the\n:class:`.Engine` and provides that the SQL compilation process for a given Core\nor ORM SQL statement, as well as related computations which assemble\nresult-fetching mechanics for that statement, will only occur once for that\nstatement object and all others with the identical\nstructure, for the duration that the particular structure remains within the\nengine\'s "compiled cache". By "statement objects that have the identical\nstructure", this generally corresponds to a SQL statement that is\nconstructed within a function and is built each time that function runs::\n\n    def run_my_statement(connection, parameter):\n        stmt = select(table)\n        stmt = stmt.where(table.c.col == parameter)\n        stmt = stmt.order_by(table.c.id)\n        return connection.execute(stmt)\n\nThe above statement will generate SQL resembling\n``SELECT id, col FROM table WHERE col = :col ORDER BY id``, noting that\nwhile the value of ``parameter`` is a plain Python object such as a string\nor an integer, the string SQL form of the statement does not include this\nvalue as it uses bound parameters.  Subsequent invocations of the above\n``run_my_statement()`` function will use a cached compilation construct\nwithin the scope of the ``connection.execute()`` call for enhanced performance.\n\n.. note:: it is important to note that the SQL compilation cache is caching\n   the **SQL string that is passed to the database only**, and **not the data**\n   returned by a query.   It is in no way a data cache and does not\n   impact the results returned for a particular SQL statement nor does it\n   imply any memory use linked to fetching of result rows.\n\nWhile SQLAlchemy has had a rudimentary statement cache since the early 1.x\nseries, and additionally has featured the "Baked Query" extension for the ORM,\nboth of these systems required a high degree of special API use in order for\nthe cache to be effective.  The new cache as of 1.4 is instead completely\nautomatic and requires no change in programming style to be effective.\n\nThe cache is automatically used without any configurational changes and no\nspecial steps are needed in order to enable it. The following sections\ndetail the configuration and advanced usage patterns for the cache.\n\n\nConfiguration\n~~~~~~~~~~~~~\n\nThe cache itself is a dictionary-like object called an ``LRUCache``, which is\nan internal SQLAlchemy dictionary subclass that tracks the usage of particular\nkeys and features a periodic "pruning" step which removes the least recently\nused items when the size of the cache reaches a certain threshold.  The size\nof this cache defaults to 500 and may be configured using the\n:paramref:`_sa.create_engine.query_cache_size` parameter::\n\n    engine = create_engine(\n        "postgresql+psycopg2://scott:tiger@localhost/test", query_cache_size=1200\n    )\n\nThe size of the cache can grow to be a factor of 150% of the size given, before\nit\'s pruned back down to the target size.  A cache of size 1200 above can therefore\ngrow to be 1800 elements in size at which point it will be pruned to 1200.\n\nThe sizing of the cache is based on a single entry per unique SQL statement rendered,\nper engine.   SQL statements generated from both the Core and the ORM are\ntreated equally.  DDL statements will usually not be cached.  In order to determine\nwhat the cache is doing, engine logging will include details about the\ncache\'s behavior, described in the next section.\n\n\n.. _sql_caching_logging:\n\nEstimating Cache Performance Using Logging\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe above cache size of 1200 is actually fairly large.   For small applications,\na size of 100 is likely sufficient.  To estimate the optimal size of the cache,\nassuming enough memory is present on the target host, the size of the cache\nshould be based on the number of unique SQL strings that may be rendered for the\ntarget engine in use.    The most expedient way to see this is to use\nSQL echoing, which is most directly enabled by using the\n:paramref:`_sa.create_engine.echo` flag, or by using Python logging; see the\nsection :ref:`dbengine_logging` for background on logging configuration.\n\nAs an example, we will examine the logging produced by the following program::\n\n    from sqlalchemy import Column\n    from sqlalchemy import create_engine\n    from sqlalchemy import ForeignKey\n    from sqlalchemy import Integer\n    from sqlalchemy import select\n    from sqlalchemy import String\n    from sqlalchemy.ext.declarative import declarative_base\n    from sqlalchemy.orm import relationship\n    from sqlalchemy.orm import Session\n\n    Base = declarative_base()\n\n\n    class A(Base):\n        __tablename__ = "a"\n\n        id = Column(Integer, primary_key=True)\n        data = Column(String)\n        bs = relationship("B")\n\n\n    class B(Base):\n        __tablename__ = "b"\n        id = Column(Integer, primary_key=True)\n        a_id = Column(ForeignKey("a.id"))\n        data = Column(String)\n\n\n    e = create_engine("sqlite://", echo=True)\n    Base.metadata.create_all(e)\n\n    s = Session(e)\n\n    s.add_all([A(bs=[B(), B(), B()]), A(bs=[B(), B(), B()]), A(bs=[B(), B(), B()])])\n    s.commit()\n\n    for a_rec in s.scalars(select(A)):\n        print(a_rec.bs)\n\nWhen run, each SQL statement that\'s logged will include a bracketed\ncache statistics badge to the left of the parameters passed.   The four\ntypes of message we may see are summarized as follows:\n\n* ``[raw sql]`` - the driver or the end-user emitted raw SQL using\n  :meth:`.Connection.exec_driver_sql` - caching does not apply\n\n* ``[no key]`` - the statement object is a DDL statement that is not cached, or\n  the statement object contains uncacheable elements such as user-defined\n  constructs or arbitrarily large VALUES clauses.\n\n* ``[generated in Xs]`` - the statement was a **cache miss** and had to be\n  compiled, then stored in the cache.  it took X seconds to produce the\n  compiled construct.  The number X will be in the small fractional seconds.\n\n* ``[cached since Xs ago]`` - the statement was a **cache hit** and did not\n  have to be recompiled.  The statement has been stored in the cache since\n  X seconds ago.  The number X will be proportional to how long the application\n  has been running and how long the statement has been cached, so for example\n  would be 86400 for a 24 hour period.\n\nEach badge is described in more detail below.\n\nThe first statements we see for the above program will be the SQLite dialect\nchecking for the existence of the "a" and "b" tables:\n\n.. sourcecode:: text\n\n  INFO sqlalchemy.engine.Engine PRAGMA temp.table_info("a")\n  INFO sqlalchemy.engine.Engine [raw sql] ()\n  INFO sqlalchemy.engine.Engine PRAGMA main.table_info("b")\n  INFO sqlalchemy.engine.Engine [raw sql] ()\n\nFor the above two SQLite PRAGMA statements, the badge reads ``[raw sql]``,\nwhich indicates the driver is sending a Python string directly to the\ndatabase using :meth:`.Connection.exec_driver_sql`.  Caching does not apply\nto such statements because they already exist in string form, and there\nis nothing known about what kinds of result rows will be returned since\nSQLAlchemy does not parse SQL strings ahead of time.\n\nThe next statements we see are the CREATE TABLE statements:\n\n.. sourcecode:: sql\n\n  INFO sqlalchemy.engine.Engine\n  CREATE TABLE a (\n    id INTEGER NOT NULL,\n    data VARCHAR,\n    PRIMARY KEY (id)\n  )\n\n  INFO sqlalchemy.engine.Engine [no key 0.00007s] ()\n  INFO sqlalchemy.engine.Engine\n  CREATE TABLE b (\n    id INTEGER NOT NULL,\n    a_id INTEGER,\n    data VARCHAR,\n    PRIMARY KEY (id),\n    FOREIGN KEY(a_id) REFERENCES a (id)\n  )\n\n  INFO sqlalchemy.engine.Engine [no key 0.00006s] ()\n\nFor each of these statements, the badge reads ``[no key 0.00006s]``.  This\nindicates that these two particular statements, caching did not occur because\nthe DDL-oriented :class:`_schema.CreateTable` construct did not produce a\ncache key.  DDL constructs generally do not participate in caching because\nthey are not typically subject to being repeated a second time and DDL\nis also a database configurational step where performance is not as critical.\n\nThe ``[no key]`` badge is important for one other reason, as it can be produced\nfor SQL statements that are cacheable except for some particular sub-construct\nthat is not currently cacheable.   Examples of this include custom user-defined\nSQL elements that don\'t define caching parameters, as well as some constructs\nthat generate arbitrarily long and non-reproducible SQL strings, the main\nexamples being the :class:`.Values` construct as well as when using "multivalued\ninserts" with the :meth:`.Insert.values` method.\n\nSo far our cache is still empty.  The next statements will be cached however,\na segment looks like:\n\n.. sourcecode:: sql\n\n  INFO sqlalchemy.engine.Engine INSERT INTO a (data) VALUES (?)\n  INFO sqlalchemy.engine.Engine [generated in 0.00011s] (None,)\n  INFO sqlalchemy.engine.Engine INSERT INTO a (data) VALUES (?)\n  INFO sqlalchemy.engine.Engine [cached since 0.0003533s ago] (None,)\n  INFO sqlalchemy.engine.Engine INSERT INTO a (data) VALUES (?)\n  INFO sqlalchemy.engine.Engine [cached since 0.0005326s ago] (None,)\n  INFO sqlalchemy.engine.Engine INSERT INTO b (a_id, data) VALUES (?, ?)\n  INFO sqlalchemy.engine.Engine [generated in 0.00010s] (1, None)\n  INFO sqlalchemy.engine.Engine INSERT INTO b (a_id, data) VALUES (?, ?)\n  INFO sqlalchemy.engine.Engine [cached since 0.0003232s ago] (1, None)\n  INFO sqlalchemy.engine.Engine INSERT INTO b (a_id, data) VALUES (?, ?)\n  INFO sqlalchemy.engine.Engine [cached since 0.0004887s ago] (1, None)\n\nAbove, we see essentially two unique SQL strings; ``"INSERT INTO a (data) VALUES (?)"``\nand ``"INSERT INTO b (a_id, data) VALUES (?, ?)"``.  Since SQLAlchemy uses\nbound parameters for all literal values, even though these statements are\nrepeated many times for different objects, because the parameters are separate,\nthe actual SQL string stays the same.\n\n.. note:: the above two statements are generated by the ORM unit of work\n   process, and in fact will be caching these in a separate cache that is\n   local to each mapper.  However the mechanics and terminology are the same.\n   The section :ref:`engine_compiled_cache` below will describe how user-facing\n   code can also use an alternate caching container on a per-statement basis.\n\nThe caching badge we see for the first occurrence of each of these two\nstatements is ``[generated in 0.00011s]``. This indicates that the statement\nwas **not in the cache, was compiled into a String in .00011s and was then\ncached**.   When we see the ``[generated]`` badge, we know that this means\nthere was a **cache miss**.  This is to be expected for the first occurrence of\na particular statement.  However, if lots of new ``[generated]`` badges are\nobserved for a long-running application that is generally using the same series\nof SQL statements over and over, this may be a sign that the\n:paramref:`_sa.create_engine.query_cache_size` parameter is too small.  When a\nstatement that was cached is then evicted from the cache due to the LRU\ncache pruning lesser used items, it will display the ``[generated]`` badge\nwhen it is next used.\n\nThe caching badge that we then see for the subsequent occurrences of each of\nthese two statements looks like ``[cached since 0.0003533s ago]``.  This\nindicates that the statement **was found in the cache, and was originally\nplaced into the cache .0003533 seconds ago**.   It is important to note that\nwhile the ``[generated]`` and ``[cached since]`` badges refer to a number of\nseconds, they mean different things; in the case of ``[generated]``, the number\nis a rough timing of how long it took to compile the statement, and will be an\nextremely small amount of time.   In the case of ``[cached since]``, this is\nthe total time that a statement has been present in the cache.  For an\napplication that\'s been running for six hours, this number may read ``[cached\nsince 21600 seconds ago]``, and that\'s a good thing.    Seeing high numbers for\n"cached since" is an indication that these statements have not been subject to\ncache misses for a long time.  Statements that frequently have a low number of\n"cached since" even if the application has been running a long time may\nindicate these statements are too frequently subject to cache misses, and that\nthe\n:paramref:`_sa.create_engine.query_cache_size` may need to be increased.\n\nOur example program then performs some SELECTs where we can see the same\npattern of "generated" then "cached", for the SELECT of the "a" table as well\nas for subsequent lazy loads of the "b" table:\n\n.. sourcecode:: text\n\n  INFO sqlalchemy.engine.Engine SELECT a.id AS a_id, a.data AS a_data\n  FROM a\n  INFO sqlalchemy.engine.Engine [generated in 0.00009s] ()\n  INFO sqlalchemy.engine.Engine SELECT b.id AS b_id, b.a_id AS b_a_id, b.data AS b_data\n  FROM b\n  WHERE ? = b.a_id\n  INFO sqlalchemy.engine.Engine [generated in 0.00010s] (1,)\n  INFO sqlalchemy.engine.Engine SELECT b.id AS b_id, b.a_id AS b_a_id, b.data AS b_data\n  FROM b\n  WHERE ? = b.a_id\n  INFO sqlalchemy.engine.Engine [cached since 0.0005922s ago] (2,)\n  INFO sqlalchemy.engine.Engine SELECT b.id AS b_id, b.a_id AS b_a_id, b.data AS b_data\n  FROM b\n  WHERE ? = b.a_id\n\nFrom our above program, a full run shows a total of four distinct SQL strings\nbeing cached.   Which indicates a cache size of **four** would be sufficient.   This is\nobviously an extremely small size, and the default size of 500 is fine to be left\nat its default.\n\nHow much memory does the cache use?\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe previous section detailed some techniques to check if the\n:paramref:`_sa.create_engine.query_cache_size` needs to be bigger.   How do we know\nif the cache is not too large?   The reason we may want to set\n:paramref:`_sa.create_engine.query_cache_size` to not be higher than a certain\nnumber would be because we have an application that may make use of a very large\nnumber of different statements, such as an application that is building queries\non the fly from a search UX, and we don\'t want our host to run out of memory\nif for example, a hundred thousand different queries were run in the past 24 hours\nand they were all cached.\n\nIt is extremely difficult to measure how much memory is occupied by Python\ndata structures, however using a process to measure growth in memory via ``top`` as a\nsuccessive series of 250 new statements are added to the cache suggest a\nmoderate Core statement takes up about 12K while a small ORM statement takes about\n20K, including result-fetching structures which for the ORM will be much greater.\n\n\n.. _engine_compiled_cache:\n\nDisabling or using an alternate dictionary to cache some (or all) statements\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe internal cache used is known as ``LRUCache``, but this is mostly just\na dictionary.  Any dictionary may be used as a cache for any series of\nstatements by using the :paramref:`.Connection.execution_options.compiled_cache`\noption as an execution option.  Execution options may be set on a statement,\non an :class:`_engine.Engine` or :class:`_engine.Connection`, as well as\nwhen using the ORM :meth:`_orm.Session.execute` method for SQLAlchemy-2.0\nstyle invocations.   For example, to run a series of SQL statements and have\nthem cached in a particular dictionary::\n\n    my_cache = {}\n    with engine.connect().execution_options(compiled_cache=my_cache) as conn:\n        conn.execute(table.select())\n\nThe SQLAlchemy ORM uses the above technique to hold onto per-mapper caches\nwithin the unit of work "flush" process that are separate from the default\ncache configured on the :class:`_engine.Engine`, as well as for some\nrelationship loader queries.\n\nThe cache can also be disabled with this argument by sending a value of\n``None``::\n\n    # disable caching for this connection\n    with engine.connect().execution_options(compiled_cache=None) as conn:\n        conn.execute(table.select())\n\n.. _engine_thirdparty_caching:\n\nCaching for Third Party Dialects\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe caching feature requires that the dialect\'s compiler produces SQL\nstrings that are safe to reuse for many statement invocations, given\na particular cache key that is keyed to that SQL string.  This means\nthat any literal values in a statement, such as the LIMIT/OFFSET values for\na SELECT, can not be hardcoded in the dialect\'s compilation scheme, as\nthe compiled string will not be re-usable.   SQLAlchemy supports rendered\nbound parameters using the :meth:`_sql.BindParameter.render_literal_execute`\nmethod which can be applied to the existing ``Select._limit_clause`` and\n``Select._offset_clause`` attributes by a custom compiler, which\nare illustrated later in this section.\n\nAs there are many third party dialects, many of which may be generating literal\nvalues from SQL statements without the benefit of the newer "literal execute"\nfeature, SQLAlchemy as of version 1.4.5 has added an attribute to dialects\nknown as :attr:`_engine.Dialect.supports_statement_cache`. This attribute is\nchecked at runtime for its presence directly on a particular dialect\'s class,\neven if it\'s already present on a superclass, so that even a third party\ndialect that subclasses an existing cacheable SQLAlchemy dialect such as\n``sqlalchemy.dialects.postgresql.PGDialect`` must still explicitly include this\nattribute for caching to be enabled. The attribute should **only** be enabled\nonce the dialect has been altered as needed and tested for reusability of\ncompiled SQL statements with differing parameters.\n\nFor all third party dialects that don\'t support this attribute, the logging for\nsuch a dialect will indicate ``dialect does not support caching``.\n\nWhen a dialect has been tested against caching, and in particular the SQL\ncompiler has been updated to not render any literal LIMIT / OFFSET within\na SQL string directly, dialect authors can apply the attribute as follows::\n\n    from sqlalchemy.engine.default import DefaultDialect\n\n\n    class MyDialect(DefaultDialect):\n        supports_statement_cache = True\n\nThe flag needs to be applied to all subclasses of the dialect as well::\n\n    class MyDBAPIForMyDialect(MyDialect):\n        supports_statement_cache = True\n\n.. versionadded:: 1.4.5\n\n    Added the :attr:`.Dialect.supports_statement_cache` attribute.\n\nThe typical case for dialect modification follows.\n\nExample: Rendering LIMIT / OFFSET with post compile parameters\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nAs an example, suppose a dialect overrides the :meth:`.SQLCompiler.limit_clause`\nmethod, which produces the "LIMIT / OFFSET" clause for a SQL statement,\nlike this::\n\n    # pre 1.4 style code\n    def limit_clause(self, select, **kw):\n        text = ""\n        if select._limit is not None:\n            text += " \\n LIMIT %d" % (select._limit,)\n        if select._offset is not None:\n            text += " \\n OFFSET %d" % (select._offset,)\n        return text\n\nThe above routine renders the :attr:`.Select._limit` and\n:attr:`.Select._offset` integer values as literal integers embedded in the SQL\nstatement. This is a common requirement for databases that do not support using\na bound parameter within the LIMIT/OFFSET clauses of a SELECT statement.\nHowever, rendering the integer value within the initial compilation stage is\ndirectly **incompatible** with caching as the limit and offset integer values\nof a :class:`.Select` object are not part of the cache key, so that many\n:class:`.Select` statements with different limit/offset values would not render\nwith the correct value.\n\nThe correction for the above code is to move the literal integer into\nSQLAlchemy\'s :ref:`post-compile <change_4808>` facility, which will render the\nliteral integer outside of the initial compilation stage, but instead at\nexecution time before the statement is sent to the DBAPI.  This is accessed\nwithin the compilation stage using the :meth:`_sql.BindParameter.render_literal_execute`\nmethod, in conjunction with using the :attr:`.Select._limit_clause` and\n:attr:`.Select._offset_clause` attributes, which represent the LIMIT/OFFSET\nas a complete SQL expression, as follows::\n\n    # 1.4 cache-compatible code\n    def limit_clause(self, select, **kw):\n        text = ""\n\n        limit_clause = select._limit_clause\n        offset_clause = select._offset_clause\n\n        if select._simple_int_clause(limit_clause):\n            text += " \\n LIMIT %s" % (\n                self.process(limit_clause.render_literal_execute(), **kw)\n            )\n        elif limit_clause is not None:\n            # assuming the DB doesn\'t support SQL expressions for LIMIT.\n            # Otherwise render here normally\n            raise exc.CompileError(\n                "dialect \'mydialect\' can only render simple integers for LIMIT"\n            )\n        if select._simple_int_clause(offset_clause):\n            text += " \\n OFFSET %s" % (\n                self.process(offset_clause.render_literal_execute(), **kw)\n            )\n        elif offset_clause is not None:\n            # assuming the DB doesn\'t support SQL expressions for OFFSET.\n            # Otherwise render here normally\n            raise exc.CompileError(\n                "dialect \'mydialect\' can only render simple integers for OFFSET"\n            )\n\n        return text\n\nThe approach above will generate a compiled SELECT statement that looks like:\n\n.. sourcecode:: sql\n\n    SELECT x FROM y\n    LIMIT __[POSTCOMPILE_param_1]\n    OFFSET __[POSTCOMPILE_param_2]\n\nWhere above, the ``__[POSTCOMPILE_param_1]`` and ``__[POSTCOMPILE_param_2]``\nindicators will be populated with their corresponding integer values at\nstatement execution time, after the SQL string has been retrieved from the\ncache.\n\nAfter changes like the above have been made as appropriate, the\n:attr:`.Dialect.supports_statement_cache` flag should be set to ``True``.\nIt is strongly recommended that third party dialects make use of the\n`dialect third party test suite <https://github.com/sqlalchemy/sqlalchemy/blob/main/README.dialects.rst>`_\nwhich will assert that operations like\nSELECTs with LIMIT/OFFSET are correctly rendered and cached.\n\n.. seealso::\n\n    :ref:`faq_new_caching` - in the :ref:`faq_toplevel` section\n\n\n.. _engine_lambda_caching:\n\nUsing Lambdas to add significant speed gains to statement production\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\n.. deepalchemy:: This technique is generally non-essential except in very performance\n   intensive scenarios, and intended for experienced Python programmers.\n   While fairly straightforward, it involves metaprogramming concepts that are\n   not appropriate for novice Python developers.  The lambda approach can be\n   applied to at a later time to existing code with a minimal amount of effort.\n\nPython functions, typically expressed as lambdas, may be used to generate\nSQL expressions which are cacheable based on the Python code location of\nthe lambda function itself as well as the closure variables within the\nlambda.   The rationale is to allow caching of not only the SQL string-compiled\nform of a SQL expression construct as is SQLAlchemy\'s normal behavior when\nthe lambda system isn\'t used, but also the in-Python composition\nof the SQL expression construct itself, which also has some degree of\nPython overhead.\n\nThe lambda SQL expression feature is available as a performance enhancing\nfeature, and is also optionally used in the :func:`_orm.with_loader_criteria`\nORM option in order to provide a generic SQL fragment.\n\nSynopsis\n^^^^^^^^\n\nLambda statements are constructed using the :func:`_sql.lambda_stmt` function,\nwhich returns an instance of :class:`_sql.StatementLambdaElement`, which is\nitself an executable statement construct.    Additional modifiers and criteria\nare added to the object using the Python addition operator ``+``, or\nalternatively the :meth:`_sql.StatementLambdaElement.add_criteria` method which\nallows for more options.\n\nIt is assumed that the :func:`_sql.lambda_stmt` construct is being invoked\nwithin an enclosing function or method that expects to be used many times\nwithin an application, so that subsequent executions beyond the first one\ncan take advantage of the compiled SQL being cached.  When the lambda is\nconstructed inside of an enclosing function in Python it is then subject\nto also having closure variables, which are significant to the whole\napproach::\n\n    from sqlalchemy import lambda_stmt\n\n\n    def run_my_statement(connection, parameter):\n        stmt = lambda_stmt(lambda: select(table))\n        stmt += lambda s: s.where(table.c.col == parameter)\n        stmt += lambda s: s.order_by(table.c.id)\n\n        return connection.execute(stmt)\n\n\n    with engine.connect() as conn:\n        result = run_my_statement(some_connection, "some parameter")\n\nAbove, the three ``lambda`` callables that are used to define the structure\nof a SELECT statement are invoked exactly once, and the resulting SQL\nstring cached in the compilation cache of the engine.   From that point\nforward, the ``run_my_statement()`` function may be invoked any number\nof times and the ``lambda`` callables within it will not be called, only\nused as cache keys to retrieve the already-compiled SQL.\n\n.. note::  It is important to note that there is already SQL caching in place\n   when the lambda system is not used.   The lambda system only adds an\n   additional layer of work reduction per SQL statement invoked by caching\n   the building up of the SQL construct itself and also using a simpler\n   cache key.\n\n\nQuick Guidelines for Lambdas\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nAbove all, the emphasis within the lambda SQL system is ensuring that there\nis never a mismatch between the cache key generated for a lambda and the\nSQL string it will produce.   The :class:`_sql.LambdaElement` and related\nobjects will run and analyze the given lambda in order to calculate how\nit should be cached on each run, trying to detect any potential problems.\nBasic guidelines include:\n\n* **Any kind of statement is supported** - while it\'s expected that\n  :func:`_sql.select` constructs are the prime use case for :func:`_sql.lambda_stmt`,\n  DML statements such as :func:`_sql.insert` and :func:`_sql.update` are\n  equally usable::\n\n    def upd(id_, newname):\n        stmt = lambda_stmt(lambda: users.update())\n        stmt += lambda s: s.values(name=newname)\n        stmt += lambda s: s.where(users.c.id == id_)\n        return stmt\n\n\n    with engine.begin() as conn:\n        conn.execute(upd(7, "foo"))\n\n  ..\n\n* **ORM use cases directly supported as well** - the :func:`_sql.lambda_stmt`\n  can accommodate ORM functionality completely and used directly with\n  :meth:`_orm.Session.execute`::\n\n    def select_user(session, name):\n        stmt = lambda_stmt(lambda: select(User))\n        stmt += lambda s: s.where(User.name == name)\n\n        row = session.execute(stmt).first()\n        return row\n\n  ..\n\n* **Bound parameters are automatically accommodated** - in contrast to SQLAlchemy\'s\n  previous "baked query" system, the lambda SQL system accommodates for\n  Python literal values which become SQL bound parameters automatically.\n  This means that even though a given lambda runs only once, the values that\n  become bound parameters are extracted from the **closure** of the lambda\n  on every run:\n\n  .. sourcecode:: pycon+sql\n\n        >>> def my_stmt(x, y):\n        ...     stmt = lambda_stmt(lambda: select(func.max(x, y)))\n        ...     return stmt\n        >>> engine = create_engine("sqlite://", echo=True)\n        >>> with engine.connect() as conn:\n        ...     print(conn.scalar(my_stmt(5, 10)))\n        ...     print(conn.scalar(my_stmt(12, 8)))\n        {execsql}SELECT max(?, ?) AS max_1\n        [generated in 0.00057s] (5, 10){stop}\n        10\n        {execsql}SELECT max(?, ?) AS max_1\n        [cached since 0.002059s ago] (12, 8){stop}\n        12\n\n  Above, :class:`_sql.StatementLambdaElement` extracted the values of ``x``\n  and ``y`` from the **closure** of the lambda that is generated each time\n  ``my_stmt()`` is invoked; these were substituted into the cached SQL\n  construct as the values of the parameters.\n\n* **The lambda should ideally produce an identical SQL structure in all cases** -\n  Avoid using conditionals or custom callables inside of lambdas that might make\n  it produce different SQL based on inputs; if a function might conditionally\n  use two different SQL fragments, use two separate lambdas::\n\n        # **Don\'t** do this:\n\n\n        def my_stmt(parameter, thing=False):\n            stmt = lambda_stmt(lambda: select(table))\n            stmt += lambda s: (\n                s.where(table.c.x > parameter) if thing else s.where(table.c.y == parameter)\n            )\n            return stmt\n\n\n        # **Do** do this:\n\n\n        def my_stmt(parameter, thing=False):\n            stmt = lambda_stmt(lambda: select(table))\n            if thing:\n                stmt += lambda s: s.where(table.c.x > parameter)\n            else:\n                stmt += lambda s: s.where(table.c.y == parameter)\n            return stmt\n\n  There are a variety of failures which can occur if the lambda does not\n  produce a consistent SQL construct and some are not trivially detectable\n  right now.\n\n* **Don\'t use functions inside the lambda to produce bound values** - the\n  bound value tracking approach requires that the actual value to be used in\n  the SQL statement be locally present in the closure of the lambda.  This is\n  not possible if values are generated from other functions, and the\n  :class:`_sql.LambdaElement` should normally raise an error if this is\n  attempted::\n\n    >>> def my_stmt(x, y):\n    ...     def get_x():\n    ...         return x\n    ...\n    ...     def get_y():\n    ...         return y\n    ...\n    ...     stmt = lambda_stmt(lambda: select(func.max(get_x(), get_y())))\n    ...     return stmt\n    >>> with engine.connect() as conn:\n    ...     print(conn.scalar(my_stmt(5, 10)))\n    Traceback (most recent call last):\n      # ...\n    sqlalchemy.exc.InvalidRequestError: Can\'t invoke Python callable get_x()\n    inside of lambda expression argument at\n    <code object <lambda> at 0x7fed15f350e0, file "<stdin>", line 6>;\n    lambda SQL constructs should not invoke functions from closure variables\n    to produce literal values since the lambda SQL system normally extracts\n    bound values without actually invoking the lambda or any functions within it.\n\n  Above, the use of ``get_x()`` and ``get_y()``, if they are necessary, should\n  occur **outside** of the lambda and assigned to a local closure variable::\n\n    >>> def my_stmt(x, y):\n    ...     def get_x():\n    ...         return x\n    ...\n    ...     def get_y():\n    ...         return y\n    ...\n    ...     x_param, y_param = get_x(), get_y()\n    ...     stmt = lambda_stmt(lambda: select(func.max(x_param, y_param)))\n    ...     return stmt\n\n  ..\n\n* **Avoid referring to non-SQL constructs inside of lambdas as they are not\n  cacheable by default** - this issue refers to how the :class:`_sql.LambdaElement`\n  creates a cache key from other closure variables within the statement.  In order\n  to provide the best guarantee of an accurate cache key, all objects located\n  in the closure of the lambda are considered to be significant, and none\n  will be assumed to be appropriate for a cache key by default.\n  So the following example will also raise a rather detailed error message::\n\n    >>> class Foo:\n    ...     def __init__(self, x, y):\n    ...         self.x = x\n    ...         self.y = y\n    >>> def my_stmt(foo):\n    ...     stmt = lambda_stmt(lambda: select(func.max(foo.x, foo.y)))\n    ...     return stmt\n    >>> with engine.connect() as conn:\n    ...     print(conn.scalar(my_stmt(Foo(5, 10))))\n    Traceback (most recent call last):\n      # ...\n    sqlalchemy.exc.InvalidRequestError: Closure variable named \'foo\' inside of\n    lambda callable <code object <lambda> at 0x7fed15f35450, file\n    "<stdin>", line 2> does not refer to a cacheable SQL element, and also\n    does not appear to be serving as a SQL literal bound value based on the\n    default SQL expression returned by the function.  This variable needs to\n    remain outside the scope of a SQL-generating lambda so that a proper cache\n    key may be generated from the lambda\'s state.  Evaluate this variable\n    outside of the lambda, set track_on=[<elements>] to explicitly select\n    closure elements to track, or set track_closure_variables=False to exclude\n    closure variables from being part of the cache key.\n\n  The above error indicates that :class:`_sql.LambdaElement` will not assume\n  that the ``Foo`` object passed in will continue to behave the same in all\n  cases.    It also won\'t assume it can use ``Foo`` as part of the cache key\n  by default; if it were to use the ``Foo`` object as part of the cache key,\n  if there were many different ``Foo`` objects this would fill up the cache\n  with duplicate information, and would also hold long-lasting references to\n  all of these objects.\n\n  The best way to resolve the above situation is to not refer to ``foo``\n  inside of the lambda, and refer to it **outside** instead::\n\n    >>> def my_stmt(foo):\n    ...     x_param, y_param = foo.x, foo.y\n    ...     stmt = lambda_stmt(lambda: select(func.max(x_param, y_param)))\n    ...     return stmt\n\n  In some situations, if the SQL structure of the lambda is guaranteed to\n  never change based on input, to pass ``track_closure_variables=False``\n  which will disable any tracking of closure variables other than those\n  used for bound parameters::\n\n    >>> def my_stmt(foo):\n    ...     stmt = lambda_stmt(\n    ...         lambda: select(func.max(foo.x, foo.y)), track_closure_variables=False\n    ...     )\n    ...     return stmt\n\n  There is also the option to add objects to the element to explicitly form\n  part of the cache key, using the ``track_on`` parameter; using this parameter\n  allows specific values to serve as the cache key and will also prevent other\n  closure variables from being considered.  This is useful for cases where part\n  of the SQL being constructed originates from a contextual object of some sort\n  that may have many different values.  In the example below, the first\n  segment of the SELECT statement will disable tracking of the ``foo`` variable,\n  whereas the second segment will explicitly track ``self`` as part of the\n  cache key::\n\n    >>> def my_stmt(self, foo):\n    ...     stmt = lambda_stmt(\n    ...         lambda: select(*self.column_expressions), track_closure_variables=False\n    ...     )\n    ...     stmt = stmt.add_criteria(lambda: self.where_criteria, track_on=[self])\n    ...     return stmt\n\n  Using ``track_on`` means the given objects will be stored long term in the\n  lambda\'s internal cache and will have strong references for as long as the\n  cache doesn\'t clear out those objects (an LRU scheme of 1000 entries is used\n  by default).\n\n  ..\n\n\nCache Key Generation\n^^^^^^^^^^^^^^^^^^^^\n\nIn order to understand some of the options and behaviors which occur\nwith lambda SQL constructs, an understanding of the caching system\nis helpful.\n\nSQLAlchemy\'s caching system normally generates a cache key from a given\nSQL expression construct by producing a structure that represents all the\nstate within the construct::\n\n    >>> from sqlalchemy import select, column\n    >>> stmt = select(column("q"))\n    >>> cache_key = stmt._generate_cache_key()\n    >>> print(cache_key)  # somewhat paraphrased\n    CacheKey(key=(\n      \'0\',\n      <class \'sqlalchemy.sql.selectable.Select\'>,\n      \'_raw_columns\',\n      (\n        (\n          \'1\',\n          <class \'sqlalchemy.sql.elements.ColumnClause\'>,\n          \'name\',\n          \'q\',\n          \'type\',\n          (\n            <class \'sqlalchemy.sql.sqltypes.NullType\'>,\n          ),\n        ),\n      ),\n      # a few more elements are here, and many more for a more\n      # complicated SELECT statement\n    ),)\n\n\nThe above key is stored in the cache which is essentially a dictionary, and the\nvalue is a construct that among other things stores the string form of the SQL\nstatement, in this case the phrase "SELECT q".  We can observe that even for an\nextremely short query the cache key is pretty verbose as it has to represent\neverything that may vary about what\'s being rendered and potentially executed.\n\nThe lambda construction system by contrast creates a different kind of cache\nkey::\n\n    >>> from sqlalchemy import lambda_stmt\n    >>> stmt = lambda_stmt(lambda: select(column("q")))\n    >>> cache_key = stmt._generate_cache_key()\n    >>> print(cache_key)\n    CacheKey(key=(\n      <code object <lambda> at 0x7fed1617c710, file "<stdin>", line 1>,\n      <class \'sqlalchemy.sql.lambdas.StatementLambdaElement\'>,\n    ),)\n\nAbove, we see a cache key that is vastly shorter than that of the non-lambda\nstatement, and additionally that production of the ``select(column("q"))``\nconstruct itself was not even necessary; the Python lambda itself contains\nan attribute called ``__code__`` which refers to a Python code object that\nwithin the runtime of the application is immutable and permanent.\n\nWhen the lambda also includes closure variables, in the normal case that these\nvariables refer to SQL constructs such as column objects, they become\npart of the cache key, or if they refer to literal values that will be bound\nparameters, they are placed in a separate element of the cache key::\n\n    >>> def my_stmt(parameter):\n    ...     col = column("q")\n    ...     stmt = lambda_stmt(lambda: select(col))\n    ...     stmt += lambda s: s.where(col == parameter)\n    ...     return stmt\n\nThe above :class:`_sql.StatementLambdaElement` includes two lambdas, both\nof which refer to the ``col`` closure variable, so the cache key will\nrepresent both of these segments as well as the ``column()`` object::\n\n    >>> stmt = my_stmt(5)\n    >>> key = stmt._generate_cache_key()\n    >>> print(key)\n    CacheKey(key=(\n      <code object <lambda> at 0x7f07323c50e0, file "<stdin>", line 3>,\n      (\n        \'0\',\n        <class \'sqlalchemy.sql.elements.ColumnClause\'>,\n        \'name\',\n        \'q\',\n        \'type\',\n        (\n          <class \'sqlalchemy.sql.sqltypes.NullType\'>,\n        ),\n      ),\n      <code object <lambda> at 0x7f07323c5190, file "<stdin>", line 4>,\n      <class \'sqlalchemy.sql.lambdas.LinkedLambdaElement\'>,\n      (\n        \'0\',\n        <class \'sqlalchemy.sql.elements.ColumnClause\'>,\n        \'name\',\n        \'q\',\n        \'type\',\n        (\n          <class \'sqlalchemy.sql.sqltypes.NullType\'>,\n        ),\n      ),\n      (\n        \'0\',\n        <class \'sqlalchemy.sql.elements.ColumnClause\'>,\n        \'name\',\n        \'q\',\n        \'type\',\n        (\n          <class \'sqlalchemy.sql.sqltypes.NullType\'>,\n        ),\n      ),\n    ),)\n\n\nThe second part of the cache key has retrieved the bound parameters that will\nbe used when the statement is invoked::\n\n    >>> key.bindparams\n    [BindParameter(\'%(139668884281280 parameter)s\', 5, type_=Integer())]\n\n\nFor a series of examples of "lambda" caching with performance comparisons,\nsee the "short_selects" test suite within the :ref:`examples_performance`\nperformance example.\n\n.. _engine_insertmanyvalues:\n\n"Insert Many Values" Behavior for INSERT statements\n---------------------------------------------------\n\n.. versionadded:: 2.0 see :ref:`change_6047` for background on the change\n   including sample performance tests\n\n.. tip:: The :term:`insertmanyvalues` feature is a **transparently available**\n   performance feature which typically requires no end-user intervention in\n   order for it to take place as needed.   This section describes the\n   architecture of the feature as well as how to measure its performance and\n   tune its behavior in order to optimize the speed of bulk INSERT statements,\n   particularly as used by the ORM.\n\nAs more databases have added support for INSERT..RETURNING, SQLAlchemy has\nundergone a major change in how it approaches the subject of INSERT statements\nwhere there\'s a need to acquire server-generated values, most importantly\nserver-generated primary key values which allow the new row to be referenced in\nsubsequent operations. In particular, this scenario has long been a significant\nperformance issue in the ORM, which relies on being able to retrieve\nserver-generated primary key values in order to correctly populate the\n:term:`identity map`.\n\nWith recent support for RETURNING added to SQLite and MariaDB, SQLAlchemy no\nlonger needs to rely upon the single-row-only\n`cursor.lastrowid <https://peps.python.org/pep-0249/#lastrowid>`_ attribute\nprovided by the :term:`DBAPI` for most backends; RETURNING may now be used for\nall :ref:`SQLAlchemy-included <included_dialects>` backends with the exception\nof MySQL. The remaining performance\nlimitation, that the\n`cursor.executemany() <https://peps.python.org/pep-0249/#executemany>`_ DBAPI\nmethod does not allow for rows to be fetched, is resolved for most backends by\nforegoing the use of ``executemany()`` and instead restructuring individual\nINSERT statements to each accommodate a large number of rows in a single\nstatement that is invoked using ``cursor.execute()``. This approach originates\nfrom the\n`psycopg2 fast execution helpers <https://www.psycopg.org/docs/extras.html#fast-execution-helpers>`_\nfeature of the ``psycopg2`` DBAPI, which SQLAlchemy incrementally added more\nand more support towards in recent release series.\n\nCurrent Support\n~~~~~~~~~~~~~~~\n\nThe feature is enabled for all backend included in SQLAlchemy that support\nRETURNING, with the exception of Oracle Database for which both the\npython-oracledb and cx_Oracle drivers offer their own equivalent feature. The\nfeature normally takes place when making use of the\n:meth:`_dml.Insert.returning` method of an :class:`_dml.Insert` construct in\nconjunction with :term:`executemany` execution, which occurs when passing a\nlist of dictionaries to the :paramref:`_engine.Connection.execute.parameters`\nparameter of the :meth:`_engine.Connection.execute` or\n:meth:`_orm.Session.execute` methods (as well as equivalent methods under\n:ref:`asyncio <asyncio_toplevel>` and shorthand methods like\n:meth:`_orm.Session.scalars`). It also takes place within the ORM :term:`unit\nof work` process when using methods such as :meth:`_orm.Session.add` and\n:meth:`_orm.Session.add_all` to add rows.\n\nFor SQLAlchemy\'s included dialects, support or equivalent support is currently\nas follows:\n\n* SQLite - supported for SQLite versions 3.35 and above\n* PostgreSQL - all supported Postgresql versions (9 and above)\n* SQL Server - all supported SQL Server versions [#]_\n* MariaDB - supported for MariaDB versions 10.5 and above\n* MySQL - no support, no RETURNING feature is present\n* Oracle Database - supports RETURNING with executemany using native python-oracledb / cx_Oracle\n  APIs, for all supported Oracle Database versions 9 and above, using multi-row OUT\n  parameters. This is not the same implementation as "executemanyvalues", however has\n  the same usage patterns and equivalent performance benefits.\n\n.. versionchanged:: 2.0.10\n\n   .. [#] "insertmanyvalues" support for Microsoft SQL Server\n      is restored, after being temporarily disabled in version 2.0.9.\n\nDisabling the feature\n~~~~~~~~~~~~~~~~~~~~~\n\nTo disable the "insertmanyvalues" feature for a given backend for an\n:class:`.Engine` overall, pass the\n:paramref:`_sa.create_engine.use_insertmanyvalues` parameter as ``False`` to\n:func:`_sa.create_engine`::\n\n    engine = create_engine(\n        "mariadb+mariadbconnector://scott:tiger@host/db", use_insertmanyvalues=False\n    )\n\nThe feature can also be disabled from being used implicitly for a particular\n:class:`_schema.Table` object by passing the\n:paramref:`_schema.Table.implicit_returning` parameter as ``False``::\n\n      t = Table(\n          "t",\n          metadata,\n          Column("id", Integer, primary_key=True),\n          Column("x", Integer),\n          implicit_returning=False,\n      )\n\nThe reason one might want to disable RETURNING for a specific table is to\nwork around backend-specific limitations.\n\n\nBatched Mode Operation\n~~~~~~~~~~~~~~~~~~~~~~\n\nThe feature has two modes of operation, which are selected transparently on a\nper-dialect, per-:class:`_schema.Table` basis. One is **batched mode**,\nwhich reduces the number of database round trips by rewriting an\nINSERT statement of the form:\n\n.. sourcecode:: sql\n\n    INSERT INTO a (data, x, y) VALUES (%(data)s, %(x)s, %(y)s) RETURNING a.id\n\ninto a "batched" form such as:\n\n.. sourcecode:: sql\n\n    INSERT INTO a (data, x, y) VALUES\n        (%(data_0)s, %(x_0)s, %(y_0)s),\n        (%(data_1)s, %(x_1)s, %(y_1)s),\n        (%(data_2)s, %(x_2)s, %(y_2)s),\n        ...\n        (%(data_78)s, %(x_78)s, %(y_78)s)\n    RETURNING a.id\n\nwhere above, the statement is organized against a subset (a "batch") of the\ninput data, the size of which is determined by the database backend as well as\nthe number of parameters in each batch to correspond to known limits for\nstatement size / number of parameters.  The feature then executes the INSERT\nstatement once for each batch of input data until all records are consumed,\nconcatenating the RETURNING results for each batch into a single large\nrowset that\'s available from a single :class:`_result.Result` object.\n\nThis "batched" form allows INSERT of many rows using much fewer database round\ntrips, and has been shown to allow dramatic performance improvements for most\nbackends where it\'s supported.\n\n.. _engine_insertmanyvalues_returning_order:\n\nCorrelating RETURNING rows to parameter sets\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\n.. versionadded:: 2.0.10\n\nThe "batch" mode query illustrated in the previous section does not guarantee\nthe order of records returned would correspond with that of the input data.\nWhen used by the SQLAlchemy ORM :term:`unit of work` process, as well as for\napplications which correlate returned server-generated values with input data,\nthe :meth:`_dml.Insert.returning` and :meth:`_dml.UpdateBase.return_defaults`\nmethods include an option\n:paramref:`_dml.Insert.returning.sort_by_parameter_order` which indicates that\n"insertmanyvalues" mode should guarantee this correspondence. This is **not\nrelated** to the order in which records are actually INSERTed by the database\nbackend, which is **not** assumed under any circumstances; only that the\nreturned records should be organized when received back to correspond to the\norder in which the original input data was passed.\n\nWhen the :paramref:`_dml.Insert.returning.sort_by_parameter_order` parameter is\npresent, for tables that use server-generated integer primary key values such\nas ``IDENTITY``, PostgreSQL ``SERIAL``, MariaDB ``AUTO_INCREMENT``, or SQLite\'s\n``ROWID`` scheme, "batch" mode may instead opt to use a more complex\nINSERT..RETURNING form, in conjunction with post-execution sorting of rows\nbased on the returned values, or if\nsuch a form is not available, the "insertmanyvalues" feature may gracefully\ndegrade to "non-batched" mode which runs individual INSERT statements for each\nparameter set.\n\nFor example, on SQL Server when an auto incrementing ``IDENTITY`` column is\nused as the primary key, the following SQL form is used [#]_:\n\n.. sourcecode:: sql\n\n    INSERT INTO a (data, x, y)\n    OUTPUT inserted.id, inserted.id AS id__1\n    SELECT p0, p1, p2 FROM (VALUES\n        (?, ?, ?, 0), (?, ?, ?, 1), (?, ?, ?, 2),\n        ...\n        (?, ?, ?, 77)\n    ) AS imp_sen(p0, p1, p2, sen_counter) ORDER BY sen_counter\n\nA similar form is used for PostgreSQL as well, when primary key columns use\nSERIAL or IDENTITY. The above form **does not** guarantee the order in which\nrows are inserted. However, it does guarantee that the IDENTITY or SERIAL\nvalues will be created in order with each parameter set [#]_. The\n"insertmanyvalues" feature then sorts the returned rows for the above INSERT\nstatement by incrementing integer identity.\n\nFor the SQLite database, there is no appropriate INSERT form that can\ncorrelate the production of new ROWID values with the order in which\nthe parameter sets are passed.  As a result, when using server-generated\nprimary key values, the SQLite backend will degrade to "non-batched"\nmode when ordered RETURNING is requested.\nFor MariaDB, the default INSERT form used by insertmanyvalues is sufficient,\nas this database backend will line up the\norder of AUTO_INCREMENT with the order of input data when using InnoDB [#]_.\n\nFor a client-side generated primary key, such as when using the Python\n``uuid.uuid4()`` function to generate new values for a :class:`.Uuid` column,\nthe "insertmanyvalues" feature transparently includes this column in the\nRETURNING records and correlates its value to that of the given input records,\nthus maintaining correspondence between input records and result rows. From\nthis, it follows that all backends allow for batched, parameter-correlated\nRETURNING order when client-side-generated primary key values are used.\n\nThe subject of how "insertmanyvalues" "batch" mode determines a column or\ncolumns to use as a point of correspondence between input parameters and\nRETURNING rows is known as an :term:`insert sentinel`, which is a specific\ncolumn or columns that are used to track such values. The "insert sentinel" is\nnormally selected automatically, however can also be user-configuration for\nextremely special cases; the section\n:ref:`engine_insertmanyvalues_sentinel_columns` describes this.\n\nFor backends that do not offer an appropriate INSERT form that can deliver\nserver-generated values deterministically aligned with input values, or\nfor :class:`_schema.Table` configurations that feature other kinds of\nserver generated primary key values, "insertmanyvalues" mode will make use\nof **non-batched** mode when guaranteed RETURNING ordering is requested.\n\n.. seealso::\n\n\n    .. [#]\n\n      * Microsoft SQL Server rationale\n\n        "INSERT queries that use SELECT with ORDER BY to populate rows guarantees\n        how identity values are computed but not the order in which the rows are inserted."\n        https://learn.microsoft.com/en-us/sql/t-sql/statements/insert-transact-sql?view=sql-server-ver16#limitations-and-restrictions\n\n    .. [#]\n\n      * PostgreSQL batched INSERT Discussion\n\n        Original description in 2018 https://www.postgresql.org/message-id/29386.1528813619@sss.pgh.pa.us\n\n        Follow up in 2023 - https://www.postgresql.org/message-id/be108555-da2a-4abc-a46b-acbe8b55bd25%40app.fastmail.com\n\n    .. [#]\n\n      * MariaDB AUTO_INCREMENT behavior (using the same InnoDB engine as MySQL)\n\n        https://dev.mysql.com/doc/refman/8.0/en/innodb-auto-increment-handling.html\n\n        https://dba.stackexchange.com/a/72099\n\n\n.. _engine_insertmanyvalues_non_batch:\n\nNon-Batched Mode Operation\n~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nFor :class:`_schema.Table` configurations that do not have client side primary\nkey values, and offer server-generated primary key values (or no primary key)\nthat the database in question is not able to invoke in a deterministic or\nsortable way relative to multiple parameter sets, the "insertmanyvalues"\nfeature when tasked with satisfying the\n:paramref:`_dml.Insert.returning.sort_by_parameter_order` requirement for an\n:class:`_dml.Insert` statement may instead opt to use **non-batched mode**.\n\nIn this mode, the original SQL form of INSERT is maintained, and the\n"insertmanyvalues" feature will instead run the statement as given for each\nparameter set individually, organizing the returned rows into a full result\nset. Unlike previous SQLAlchemy versions, it does so in a tight loop that\nminimizes Python overhead. In some cases, such as on SQLite, "non-batched" mode\nperforms exactly as well as "batched" mode.\n\nStatement Execution Model\n~~~~~~~~~~~~~~~~~~~~~~~~~\n\nFor both "batched" and "non-batched" modes, the feature will necessarily\ninvoke **multiple INSERT statements** using the DBAPI ``cursor.execute()`` method,\nwithin the scope of  **single** call to the Core-level\n:meth:`_engine.Connection.execute` method,\nwith each statement containing up to a fixed limit of parameter sets.\nThis limit is configurable as described below at :ref:`engine_insertmanyvalues_page_size`.\nThe separate calls to ``cursor.execute()`` are logged individually and\nalso individually passed along to event listeners such as\n:meth:`.ConnectionEvents.before_cursor_execute` (see :ref:`engine_insertmanyvalues_events`\nbelow).\n\n\n.. _engine_insertmanyvalues_sentinel_columns:\n\nConfiguring Sentinel Columns\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nIn typical cases, the "insertmanyvalues" feature in order to provide\nINSERT..RETURNING with deterministic row order will automatically determine a\nsentinel column from a given table\'s primary key, gracefully degrading to "row\nat a time" mode if one cannot be identified. As a completely **optional**\nfeature, to get full "insertmanyvalues" bulk performance for tables that have\nserver generated primary keys whose default generator functions aren\'t\ncompatible with the "sentinel" use case, other non-primary key columns may be\nmarked as "sentinel" columns assuming they meet certain requirements. A typical\nexample is a non-primary key :class:`_sqltypes.Uuid` column with a client side\ndefault such as the Python ``uuid.uuid4()`` function.  There is also a construct to create\nsimple integer columns with a a client side integer counter oriented towards\nthe "insertmanyvalues" use case.\n\nSentinel columns may be indicated by adding :paramref:`_schema.Column.insert_sentinel`\nto qualifying columns.   The most basic "qualifying" column is a not-nullable,\nunique column with a client side default, such as a UUID column as follows::\n\n    import uuid\n\n    from sqlalchemy import Column\n    from sqlalchemy import FetchedValue\n    from sqlalchemy import Integer\n    from sqlalchemy import String\n    from sqlalchemy import Table\n    from sqlalchemy import Uuid\n\n    my_table = Table(\n        "some_table",\n        metadata,\n        # assume some arbitrary server-side function generates\n        # primary key values, so cannot be tracked by a bulk insert\n        Column("id", String(50), server_default=FetchedValue(), primary_key=True),\n        Column("data", String(50)),\n        Column(\n            "uniqueid",\n            Uuid(),\n            default=uuid.uuid4,\n            nullable=False,\n            unique=True,\n            insert_sentinel=True,\n        ),\n    )\n\nWhen using ORM Declarative models, the same forms are available using\nthe :class:`_orm.mapped_column` construct::\n\n    import uuid\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class MyClass(Base):\n        __tablename__ = "my_table"\n\n        id: Mapped[str] = mapped_column(primary_key=True, server_default=FetchedValue())\n        data: Mapped[str] = mapped_column(String(50))\n        uniqueid: Mapped[uuid.UUID] = mapped_column(\n            default=uuid.uuid4, unique=True, insert_sentinel=True\n        )\n\nWhile the values generated by the default generator **must** be unique, the\nactual UNIQUE constraint on the above "sentinel" column, indicated by the\n``unique=True`` parameter, itself is optional and may be omitted if not\ndesired.\n\nThere is also a special form of "insert sentinel" that\'s a dedicated nullable\ninteger column which makes use of a special default integer counter that\'s only\nused during "insertmanyvalues" operations; as an additional behavior, the\ncolumn will omit itself from SQL statements and result sets and behave in a\nmostly transparent manner.  It does need to be physically present within\nthe actual database table, however.  This style of :class:`_schema.Column`\nmay be constructed using the function :func:`_schema.insert_sentinel`::\n\n    from sqlalchemy import Column\n    from sqlalchemy import Integer\n    from sqlalchemy import String\n    from sqlalchemy import Table\n    from sqlalchemy import Uuid\n    from sqlalchemy import insert_sentinel\n\n    Table(\n        "some_table",\n        metadata,\n        Column("id", Integer, primary_key=True),\n        Column("data", String(50)),\n        insert_sentinel("sentinel"),\n    )\n\nWhen using ORM Declarative, a Declarative-friendly version of\n:func:`_schema.insert_sentinel` is available called\n:func:`_orm.orm_insert_sentinel`, which has the ability to be used on the Base\nclass or a mixin; if packaged using :func:`_orm.declared_attr`, the column will\napply itself to all table-bound subclasses including within joined inheritance\nhierarchies::\n\n\n    from sqlalchemy.orm import declared_attr\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import orm_insert_sentinel\n\n\n    class Base(DeclarativeBase):\n        @declared_attr\n        def _sentinel(cls) -> Mapped[int]:\n            return orm_insert_sentinel()\n\n\n    class MyClass(Base):\n        __tablename__ = "my_table"\n\n        id: Mapped[str] = mapped_column(primary_key=True, server_default=FetchedValue())\n        data: Mapped[str] = mapped_column(String(50))\n\n\n    class MySubClass(MyClass):\n        __tablename__ = "sub_table"\n\n        id: Mapped[str] = mapped_column(ForeignKey("my_table.id"), primary_key=True)\n\n\n    class MySingleInhClass(MyClass):\n        pass\n\nIn the example above, both "my_table" and "sub_table" will have an additional\ninteger column named "_sentinel" that can be used by the "insertmanyvalues"\nfeature to help optimize bulk inserts used by the ORM.\n\n.. _engine_insertmanyvalues_monotonic_functions:\n\nConfiguring Monotonic Functions such as UUIDV7\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nUsing a monotonic function such as uuidv7 is supported by the "insertmanyvalues"\nfeature most easily by establishing the function as a client side callable,\ne.g. using Python\'s built-in ``uuid.uuid7()`` call by providing the callable\nto the :paramref:`_schema.Connection.default` parameter::\n\n    import uuid\n\n    from sqlalchemy import UUID, Integer\n\n    t = Table(\n        "t",\n        metadata,\n        Column("id", UUID, default=uuid.uuid7, primary_key=True),\n        Column("x", Integer),\n    )\n\nIn the above example, SQLAlchemy will invoke Python\'s ``uuid.uuid7()`` function\nto create new primary key identifiers, which will be batchable by the\n"insertmanyvalues" feature.\n\nHowever, some databases like PostgreSQL provide a server-side function for\nuuid7 called ``uuidv7()``; in SQLAlchemy, this would be available from the\n:data:`_sql.func` namespace as ``func.uuidv7()``, and may be configured on a\n:class:`.Column` using either :paramref:`_schema.Connection.default` to allow\nit to be called as needed, or :paramref:`_schema.Connection.server_default` to\nestablish it as part of the table\'s DDL.  However, for full batched "insertmanyvalues"\nbehavior including support for sorted RETURNING (as would allow the ORM to\nmost effectively batch INSERT statements), an additional directive must be\nincluded indicating that the function produces\nmonotonically increasing values, which is the ``monotonic=True`` directive.\nThis is illustrated below as a DDL server default using\n:paramref:`_schema.Connection.server_default`::\n\n    from sqlalchemy import func, Integer\n\n    t = Table(\n        "t",\n        metadata,\n        Column("id", UUID, server_default=func.uuidv7(monotonic=True), primary_key=True),\n        Column("x", Integer),\n    )\n\nUsing the above form, a batched INSERT...RETURNING on PostgreSQL with\n:paramref:`.UpdateBase.returning.sort_by_parameter_order` set to True will\nlook like:\n\n.. sourcecode:: sql\n\n     INSERT INTO t (x) SELECT p0::INTEGER FROM\n     (VALUES (%(x__0)s, 0), (%(x__1)s, 1), (%(x__2)s, 2),   ...)\n     AS imp_sen(p0, sen_counter) ORDER BY sen_counter\n     RETURNING t.id, t.id AS id__1\n\nSimilarly if the function is configured as an ad-hoc server side function\nusing :paramref:`_schema.Connection.default`::\n\n    t = Table(\n        "t",\n        metadata,\n        Column("id", UUID, default=func.uuidv7(monotonic=True), primary_key=True),\n        Column("x", Integer),\n    )\n\nThe function will then be rendered in the SQL statement explicitly:\n\n.. sourcecode:: sql\n\n    INSERT INTO t (id, x) SELECT uuidv7(), p1::INTEGER FROM\n    (VALUES (%(x__0)s, 0), (%(x__1)s, 1), (%(x__2)s, 2), ...)\n    AS imp_sen(p1, sen_counter) ORDER BY sen_counter\n    RETURNING t.id, t.id AS id__1\n\n.. versionadded:: 2.1 Added support for explicit monotonic server side functions\n   using ``monotonic=True`` with any :class:`.Function`.\n\n.. seealso::\n\n    :ref:`postgresql_monotonic_functions`\n\n\n.. _engine_insertmanyvalues_page_size:\n\nControlling the Batch Size\n~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nA key characteristic of "insertmanyvalues" is that the size of the INSERT\nstatement is limited on a fixed max number of "values" clauses as well as a\ndialect-specific fixed total number of bound parameters that may be represented\nin one INSERT statement at a time. When the number of parameter dictionaries\ngiven exceeds a fixed limit, or when the total number of bound parameters to be\nrendered in a single INSERT statement exceeds a fixed limit (the two fixed\nlimits are separate), multiple INSERT statements will be invoked within the\nscope of a single :meth:`_engine.Connection.execute` call, each of which\naccommodate for a portion of the parameter dictionaries, known as a\n"batch".  The number of parameter dictionaries represented within each\n"batch" is then known as the "batch size".  For example, a batch size of\n500 means that each INSERT statement emitted will INSERT at most 500 rows.\n\nIt\'s potentially important to be able to adjust the batch size,\nas a larger batch size may be more performant for an INSERT where the value\nsets themselves are relatively small, and a smaller batch size may be more\nappropriate for an INSERT that uses very large value sets, where both the size\nof the rendered SQL as well as the total data size being passed in one\nstatement may benefit from being limited to a certain size based on backend\nbehavior and memory constraints.  For this reason the batch size\ncan be configured on a per-:class:`.Engine` as well as a per-statement\nbasis.   The parameter limit on the other hand is fixed based on the known\ncharacteristics of the database in use.\n\nThe batch size defaults to 1000 for most backends, with an additional\nper-dialect "max number of parameters" limiting factor that may reduce the\nbatch size further on a per-statement basis. The max number of parameters\nvaries by dialect and server version; the largest size is 32700 (chosen as a\nhealthy distance away from PostgreSQL\'s limit of 32767 and SQLite\'s modern\nlimit of 32766, while leaving room for additional parameters in the statement\nas well as for DBAPI quirkiness). Older versions of SQLite (prior to 3.32.0)\nwill set this value to 999. MariaDB has no established limit however 32700\nremains as a limiting factor for SQL message size.\n\nThe value of the "batch size" can be affected :class:`_engine.Engine`\nwide via the :paramref:`_sa.create_engine.insertmanyvalues_page_size` parameter.\nSuch as, to affect INSERT statements to include up to 100 parameter sets\nin each statement::\n\n    e = create_engine("sqlite://", insertmanyvalues_page_size=100)\n\nThe batch size may also be affected on a per statement basis using the\n:paramref:`_engine.Connection.execution_options.insertmanyvalues_page_size`\nexecution option, such as per execution::\n\n    with e.begin() as conn:\n        result = conn.execute(\n            table.insert().returning(table.c.id),\n            parameterlist,\n            execution_options={"insertmanyvalues_page_size": 100},\n        )\n\nOr configured on the statement itself::\n\n    stmt = (\n        table.insert()\n        .returning(table.c.id)\n        .execution_options(insertmanyvalues_page_size=100)\n    )\n    with e.begin() as conn:\n        result = conn.execute(stmt, parameterlist)\n\n.. _engine_insertmanyvalues_events:\n\nLogging and Events\n~~~~~~~~~~~~~~~~~~\n\nThe "insertmanyvalues" feature integrates fully with SQLAlchemy\'s :ref:`statement\nlogging <dbengine_logging>` as well as cursor events such as :meth:`.ConnectionEvents.before_cursor_execute`.\nWhen the list of parameters is broken into separate batches, **each INSERT\nstatement is logged and passed to event handlers individually**.   This is a major change\ncompared to how the psycopg2-only feature worked in previous 1.x series of\nSQLAlchemy, where the production of multiple INSERT statements was hidden from\nlogging and events.  Logging display will truncate the long lists of parameters for readability,\nand will also indicate the specific batch of each statement. The example below illustrates\nan excerpt of this logging:\n\n.. sourcecode:: text\n\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?), ... 795 characters truncated ...  (?, ?, ?), (?, ?, ?) RETURNING id\n  [generated in 0.00177s (insertmanyvalues) 1/10 (unordered)] (\'d0\', 0, 0, \'d1\',  ...\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?), ... 795 characters truncated ...  (?, ?, ?), (?, ?, ?) RETURNING id\n  [insertmanyvalues 2/10 (unordered)] (\'d100\', 100, 1000, \'d101\', ...\n\n  ...\n\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?), ... 795 characters truncated ...  (?, ?, ?), (?, ?, ?) RETURNING id\n  [insertmanyvalues 10/10 (unordered)] (\'d900\', 900, 9000, \'d901\', ...\n\nWhen :ref:`non-batch mode <engine_insertmanyvalues_non_batch>` takes place, logging\nwill indicate this along with the insertmanyvalues message:\n\n.. sourcecode:: text\n\n  ...\n\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?) RETURNING id\n  [insertmanyvalues 67/78 (ordered; batch not supported)] (\'d66\', 66, 66)\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?) RETURNING id\n  [insertmanyvalues 68/78 (ordered; batch not supported)] (\'d67\', 67, 67)\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?) RETURNING id\n  [insertmanyvalues 69/78 (ordered; batch not supported)] (\'d68\', 68, 68)\n  INSERT INTO a (data, x, y) VALUES (?, ?, ?) RETURNING id\n  [insertmanyvalues 70/78 (ordered; batch not supported)] (\'d69\', 69, 69)\n\n  ...\n\n.. seealso::\n\n    :ref:`dbengine_logging`\n\nUpsert Support\n~~~~~~~~~~~~~~\n\nThe PostgreSQL, SQLite, and MariaDB dialects offer backend-specific\n"upsert" constructs :func:`_postgresql.insert`, :func:`_sqlite.insert`\nand :func:`_mysql.insert`, which are each :class:`_dml.Insert` constructs that\nhave an additional method such as ``on_conflict_do_update()` or\n``on_duplicate_key()``.   These constructs also support "insertmanyvalues"\nbehaviors when they are used with RETURNING, allowing efficient upserts\nwith RETURNING to take place.\n\n\n.. _engine_disposal:\n\nEngine Disposal\n---------------\n\nThe :class:`_engine.Engine` refers to a connection pool, which means under normal\ncircumstances, there are open database connections present while the\n:class:`_engine.Engine` object is still resident in memory.   When an :class:`_engine.Engine`\nis garbage collected, its connection pool is no longer referred to by\nthat :class:`_engine.Engine`, and assuming none of its connections are still checked\nout, the pool and its connections will also be garbage collected, which has the\neffect of closing out the actual database connections as well.   But otherwise,\nthe :class:`_engine.Engine` will hold onto open database connections assuming\nit uses the normally default pool implementation of :class:`.QueuePool`.\n\nThe :class:`_engine.Engine` is intended to normally be a permanent\nfixture established up-front and maintained throughout the lifespan of an\napplication.  It is **not** intended to be created and disposed on a\nper-connection basis; it is instead a registry that maintains both a pool\nof connections as well as configurational information about the database\nand DBAPI in use, as well as some degree of internal caching of per-database\nresources.\n\nHowever, there are many cases where it is desirable that all connection resources\nreferred to by the :class:`_engine.Engine` be completely closed out.  It\'s\ngenerally not a good idea to rely on Python garbage collection for this\nto occur for these cases; instead, the :class:`_engine.Engine` can be explicitly disposed using\nthe :meth:`_engine.Engine.dispose` method.   This disposes of the engine\'s\nunderlying connection pool and replaces it with a new one that\'s empty.\nProvided that the :class:`_engine.Engine`\nis discarded at this point and no longer used, all **checked-in** connections\nwhich it refers to will also be fully closed.\n\nValid use cases for calling :meth:`_engine.Engine.dispose` include:\n\n* When a program wants to release any remaining checked-in connections\n  held by the connection pool and expects to no longer be connected\n  to that database at all for any future operations.\n\n* When a program uses multiprocessing or ``fork()``, and an\n  :class:`_engine.Engine` object is copied to the child process,\n  :meth:`_engine.Engine.dispose` should be called so that the engine creates\n  brand new database connections local to that fork.   Database connections\n  generally do **not** travel across process boundaries.  Use the\n  :paramref:`.Engine.dispose.close` parameter set to False in this case.\n  See the section :ref:`pooling_multiprocessing` for more background on this\n  use case.\n\n* Within test suites or multitenancy scenarios where many\n  ad-hoc, short-lived :class:`_engine.Engine` objects may be created and disposed.\n\n\nConnections that are **checked out** are **not** discarded when the\nengine is disposed or garbage collected, as these connections are still\nstrongly referenced elsewhere by the application.\nHowever, after :meth:`_engine.Engine.dispose` is called, those\nconnections are no longer associated with that :class:`_engine.Engine`; when they\nare closed, they will be returned to their now-orphaned connection pool\nwhich will ultimately be garbage collected, once all connections which refer\nto it are also no longer referenced anywhere.\nSince this process is not easy to control, it is strongly recommended that\n:meth:`_engine.Engine.dispose` is called only after all checked out connections\nare checked in or otherwise de-associated from their pool.\n\nAn alternative for applications that are negatively impacted by the\n:class:`_engine.Engine` object\'s use of connection pooling is to disable pooling\nentirely.  This typically incurs only a modest performance impact upon the\nuse of new connections, and means that when a connection is checked in,\nit is entirely closed out and is not held in memory.  See :ref:`pool_switching`\nfor guidelines on how to disable pooling.\n\n.. seealso::\n\n    :ref:`pooling_toplevel`\n\n    :ref:`pooling_multiprocessing`\n\n.. _dbapi_connections:\n\nWorking with Driver SQL and Raw DBAPI Connections\n-------------------------------------------------\n\nThe introduction on using :meth:`_engine.Connection.execute` made use of the\n:func:`_expression.text` construct in order to illustrate how textual SQL statements\nmay be invoked.  When working with SQLAlchemy, textual SQL is actually more\nof the exception rather than the norm, as the Core expression language\nand the ORM both abstract away the textual representation of SQL.  However, the\n:func:`_expression.text` construct itself also provides some abstraction of textual\nSQL in that it normalizes how bound parameters are passed, as well as that\nit supports datatyping behavior for parameters and result set rows.\n\nInvoking SQL strings directly to the driver\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nFor the use case where one wants to invoke textual SQL directly passed to the\nunderlying driver (known as the :term:`DBAPI`) without any intervention\nfrom the :func:`_expression.text` construct, the :meth:`_engine.Connection.exec_driver_sql`\nmethod may be used::\n\n    with engine.connect() as conn:\n        conn.exec_driver_sql("SET param=\'bar\'")\n\n.. versionadded:: 1.4  Added the :meth:`_engine.Connection.exec_driver_sql` method.\n\n.. _dbapi_connections_cursor:\n\nWorking with the DBAPI cursor directly\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThere are some cases where SQLAlchemy does not provide a genericized way\nat accessing some :term:`DBAPI` functions, such as calling stored procedures as well\nas dealing with multiple result sets.  In these cases, it\'s just as expedient\nto deal with the raw DBAPI connection directly.\n\nThe most common way to access the raw DBAPI connection is to get it\nfrom an already present :class:`_engine.Connection` object directly.  It is\npresent using the :attr:`_engine.Connection.connection` attribute::\n\n    connection = engine.connect()\n    dbapi_conn = connection.connection\n\nThe DBAPI connection here is actually a "proxied" in terms of the\noriginating connection pool, however this is an implementation detail\nthat in most cases can be ignored.    As this DBAPI connection is still\ncontained within the scope of an owning :class:`_engine.Connection` object, it is\nbest to make use of the :class:`_engine.Connection` object for most features such\nas transaction control as well as calling the :meth:`_engine.Connection.close`\nmethod; if these operations are performed on the DBAPI connection directly,\nthe owning :class:`_engine.Connection` will not be aware of these changes in state.\n\nTo overcome the limitations imposed by the DBAPI connection that is\nmaintained by an owning :class:`_engine.Connection`, a DBAPI connection is also\navailable without the need to procure a\n:class:`_engine.Connection` first, using the :meth:`_engine.Engine.raw_connection` method\nof :class:`_engine.Engine`::\n\n    dbapi_conn = engine.raw_connection()\n\nThis DBAPI connection is again a "proxied" form as was the case before.\nThe purpose of this proxying is now apparent, as when we call the ``.close()``\nmethod of this connection, the DBAPI connection is typically not actually\nclosed, but instead :term:`released` back to the\nengine\'s connection pool::\n\n    dbapi_conn.close()\n\nWhile SQLAlchemy may in the future add built-in patterns for more DBAPI\nuse cases, there are diminishing returns as these cases tend to be rarely\nneeded and they also vary highly dependent on the type of DBAPI in use,\nso in any case the direct DBAPI calling pattern is always there for those\ncases where it is needed.\n\n.. seealso::\n\n    :ref:`faq_dbapi_connection` - includes additional details about how\n    the DBAPI connection is accessed as well as the "driver" connection\n    when using asyncio drivers.\n\nSome recipes for DBAPI connection use follow.\n\n.. _stored_procedures:\n\nCalling Stored Procedures and User Defined Functions\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nSQLAlchemy supports calling stored procedures and user defined functions\nseveral ways. Please note that all DBAPIs have different practices, so you must\nconsult your underlying DBAPI\'s documentation for specifics in relation to your\nparticular usage. The following examples are hypothetical and may not work with\nyour underlying DBAPI.\n\nFor stored procedures or functions with special syntactical or parameter concerns,\nDBAPI-level `callproc <https://legacy.python.org/dev/peps/pep-0249/#callproc>`_\nmay potentially be used with your DBAPI. An example of this pattern is::\n\n    connection = engine.raw_connection()\n    try:\n        cursor_obj = connection.cursor()\n        cursor_obj.callproc("my_procedure", ["x", "y", "z"])\n        results = list(cursor_obj.fetchall())\n        cursor_obj.close()\n        connection.commit()\n    finally:\n        connection.close()\n\n.. note::\n\n  Not all DBAPIs use `callproc` and overall usage details will vary. The above\n  example is only an illustration of how it might look to use a particular DBAPI\n  function.\n\nYour DBAPI may not have a ``callproc`` requirement *or* may require a stored\nprocedure or user defined function to be invoked with another pattern, such as\nnormal SQLAlchemy connection usage. One example of this usage pattern is,\n*at the time of this documentation\'s writing*, executing a stored procedure in\nthe PostgreSQL database with the psycopg2 DBAPI, which should be invoked\nwith normal connection usage::\n\n    connection.execute("CALL my_procedure();")\n\nThis above example is hypothetical. The underlying database is not guaranteed to\nsupport "CALL" or "SELECT" in these situations, and the keyword may vary\ndependent on the function being a stored procedure or a user defined function.\nYou should consult your underlying DBAPI and database documentation in these\nsituations to determine the correct syntax and patterns to use.\n\n\nMultiple Result Sets\n~~~~~~~~~~~~~~~~~~~~\n\nMultiple result set support is available from a raw DBAPI cursor using the\n`nextset <https://legacy.python.org/dev/peps/pep-0249/#nextset>`_ method::\n\n    connection = engine.raw_connection()\n    try:\n        cursor_obj = connection.cursor()\n        cursor_obj.execute("select * from table1; select * from table2")\n        results_one = cursor_obj.fetchall()\n        cursor_obj.nextset()\n        results_two = cursor_obj.fetchall()\n        cursor_obj.close()\n    finally:\n        connection.close()\n\nRegistering New Dialects\n------------------------\n\nThe :func:`_sa.create_engine` function call locates the given dialect\nusing setuptools entrypoints.   These entry points can be established\nfor third party dialects within the setup.py script.  For example,\nto create a new dialect "foodialect://", the steps are as follows:\n\n1. Create a package called ``foodialect``.\n2. The package should have a module containing the dialect class,\n   which is typically a subclass of :class:`sqlalchemy.engine.default.DefaultDialect`.\n   In this example let\'s say it\'s called ``FooDialect`` and its module is accessed\n   via ``foodialect.dialect``.\n3. The entry point can be established in ``setup.cfg`` as follows:\n\n   .. sourcecode:: ini\n\n          [options.entry_points]\n          sqlalchemy.dialects =\n              foodialect = foodialect.dialect:FooDialect\n\nIf the dialect is providing support for a particular DBAPI on top of\nan existing SQLAlchemy-supported database, the name can be given\nincluding a database-qualification.  For example, if ``FooDialect``\nwere in fact a MySQL dialect, the entry point could be established like this:\n\n.. sourcecode:: ini\n\n      [options.entry_points]\n      sqlalchemy.dialects\n          mysql.foodialect = foodialect.dialect:FooDialect\n\nThe above entrypoint would then be accessed as ``create_engine("mysql+foodialect://")``.\n\n\nRegistering Dialects In-Process\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nSQLAlchemy also allows a dialect to be registered within the current process, bypassing\nthe need for separate installation.   Use the ``register()`` function as follows::\n\n    from sqlalchemy.dialects import registry\n\n\n    registry.register("mysql.foodialect", "myapp.dialect", "MyMySQLDialect")\n\nThe above will respond to ``create_engine("mysql+foodialect://")`` and load the\n``MyMySQLDialect`` class from the ``myapp.dialect`` module.\n\n\nConnection / Engine API\n-----------------------\n\n.. autoclass:: Connection\n   :members:\n\n.. autoclass:: CreateEnginePlugin\n   :members:\n\n.. autoclass:: Engine\n   :members:\n\n.. autoclass:: ExceptionContext\n   :members:\n\n.. autoclass:: NestedTransaction\n    :members:\n    :inherited-members:\n\n.. autoclass:: RootTransaction\n    :members:\n    :inherited-members:\n\n.. autoclass:: Transaction\n    :members:\n\n.. autoclass:: TwoPhaseTransaction\n    :members:\n    :inherited-members:\n\n\nResult Set API\n---------------\n\n.. autoclass:: ChunkedIteratorResult\n    :members:\n\n.. autoclass:: CursorResult\n    :members:\n    :inherited-members:\n\n.. autoclass:: FilterResult\n    :members:\n\n.. autoclass:: FrozenResult\n    :members:\n\n.. autoclass:: IteratorResult\n    :members:\n\n.. autoclass:: MergedResult\n    :members:\n\n.. autoclass:: Result\n    :members:\n    :inherited-members:\n\n.. autoclass:: ScalarResult\n    :members:\n    :inherited-members:\n\n.. autoclass:: MappingResult\n    :members:\n    :inherited-members:\n\n.. autoclass:: Row\n    :members:\n    :private-members: _asdict, _fields, _mapping, _t, _tuple\n\n.. autoclass:: RowMapping\n    :members:\n\n.. autoclass:: TupleResult\n',
            'doc/build/core/engines.rst': '.. _engines_toplevel:\n\n====================\nEngine Configuration\n====================\n\nThe :class:`_engine.Engine` is the starting point for any SQLAlchemy application. It\'s\n"home base" for the actual database and its :term:`DBAPI`, delivered to the SQLAlchemy\napplication through a connection pool and a :class:`.Dialect`, which describes how\nto talk to a specific kind of database/DBAPI combination.\n\nThe general structure can be illustrated as follows:\n\n.. image:: sqla_engine_arch.png\n\nWhere above, an :class:`_engine.Engine` references both a\n:class:`.Dialect` and a :class:`_pool.Pool`,\nwhich together interpret the DBAPI\'s module functions as well as the behavior\nof the database.\n\nCreating an engine is just a matter of issuing a single call,\n:func:`_sa.create_engine()`::\n\n    from sqlalchemy import create_engine\n\n    engine = create_engine("postgresql+psycopg2://scott:tiger@localhost:5432/mydatabase")\n\nThe above engine creates a :class:`.Dialect` object tailored towards\nPostgreSQL, as well as a :class:`_pool.Pool` object which will establish a\nDBAPI connection at ``localhost:5432`` when a connection request is first\nreceived. Note that the :class:`_engine.Engine` and its underlying\n:class:`_pool.Pool` do **not** establish the first actual DBAPI connection\nuntil the :meth:`_engine.Engine.connect` or :meth:`_engine.Engine.begin`\nmethods are called.  Either of these methods may also be invoked by other\nSQLAlchemy :class:`_engine.Engine` dependent objects such as the ORM\n:class:`_orm.Session` object when they first require database connectivity.\nIn this way, :class:`_engine.Engine` and :class:`_pool.Pool` can be said to\nhave a *lazy initialization* behavior.\n\nThe :class:`_engine.Engine`, once created, can either be used directly to interact with the database,\nor can be passed to a :class:`.Session` object to work with the ORM.   This section\ncovers the details of configuring an :class:`_engine.Engine`.   The next section, :ref:`connections_toplevel`,\nwill detail the usage API of the :class:`_engine.Engine` and similar, typically for non-ORM\napplications.\n\n.. _supported_dbapis:\n\nSupported Databases\n===================\n\nSQLAlchemy includes many :class:`.Dialect` implementations for various\nbackends.   Dialects for the most common databases are included with SQLAlchemy; a handful\nof others require an additional install of a separate dialect.\n\nSee the section :ref:`dialect_toplevel` for information on the various backends available.\n\n.. _database_urls:\n\nDatabase URLs\n=============\n\nThe :func:`_sa.create_engine` function produces an :class:`_engine.Engine`\nobject based on a URL. The format of the URL generally follows `RFC-1738\n<https://www.ietf.org/rfc/rfc1738.txt>`_, with some exceptions, including that\nunderscores, not dashes or periods, are accepted within the "scheme" portion.\nURLs typically include username, password, hostname, database name fields, as\nwell as optional keyword arguments for additional configuration. In some cases\na file path is accepted, and in others a "data source name" replaces the "host"\nand "database" portions. The typical form of a database URL is:\n\n.. sourcecode:: text\n\n    dialect+driver://username:password@host:port/database\n\nDialect names include the identifying name of the SQLAlchemy dialect,\na name such as ``sqlite``, ``mysql``, ``postgresql``, ``oracle``, or ``mssql``.\nThe drivername is the name of the DBAPI to be used to connect to\nthe database using all lowercase letters. If not specified, a "default" DBAPI\nwill be imported if available - this default is typically the most widely\nknown driver available for that backend.\n\nEscaping Special Characters such as @ signs in Passwords\n----------------------------------------------------------\n\nWhen constructing a fully formed URL string to pass to\n:func:`_sa.create_engine`, **special characters such as those that may\nbe used in the user and password need to be URL encoded to be parsed correctly.**.\n**This includes the @ sign**.\n\nBelow is an example of a URL that includes the password ``"kx@jj5/g"``, where the\n"at" sign and slash characters are represented as ``%40`` and ``%2F``,\nrespectively:\n\n.. sourcecode:: text\n\n    postgresql+pg8000://dbuser:kx%40jj5%2Fg@pghost10/appdb\n\n\nThe encoding for the above password can be generated using\n`urllib.parse <https://docs.python.org/3/library/urllib.parse.html>`_::\n\n  >>> import urllib.parse\n  >>> urllib.parse.quote_plus("kx@jj5/g")\n  \'kx%40jj5%2Fg\'\n\nThe URL may then be passed as a string to :func:`_sa.create_engine`::\n\n    from sqlalchemy import create_engine\n\n    engine = create_engine("postgresql+pg8000://dbuser:kx%40jj5%2Fg@pghost10/appdb")\n\nAs an alternative to escaping special characters in order to create a complete\nURL string, the object passed to :func:`_sa.create_engine` may instead be an\ninstance of the :class:`.URL` object, which bypasses the parsing\nphase and can accommodate for unescaped strings directly.  See the next\nsection for an example.\n\n.. versionchanged:: 1.4\n\n    Support for ``@`` signs in hostnames and database names has been\n    fixed.   As a side effect of this fix, ``@`` signs in passwords must be\n    escaped.\n\nCreating URLs Programmatically\n-------------------------------\n\nThe value passed to :func:`_sa.create_engine` may be an instance of\n:class:`.URL`, instead of a plain string, which bypasses the need for string\nparsing to be used, and therefore does not need an escaped URL string to be\nprovided.\n\nThe :class:`.URL` object is created using the :meth:`_engine.URL.create()`\nconstructor method, passing all fields individually.   Special characters\nsuch as those within passwords may be passed without any modification::\n\n    from sqlalchemy import URL\n\n    url_object = URL.create(\n        "postgresql+pg8000",\n        username="dbuser",\n        password="kx@jj5/g",  # plain (unescaped) text\n        host="pghost10",\n        database="appdb",\n    )\n\nThe constructed :class:`.URL` object may then be passed directly to\n:func:`_sa.create_engine` in place of a string argument::\n\n    from sqlalchemy import create_engine\n\n    engine = create_engine(url_object)\n\n.. seealso::\n\n    :class:`.URL`\n\n    :meth:`.URL.create`\n\nBackend-Specific URLs\n----------------------\n\nExamples for common connection styles follow below.  For a full index of\ndetailed information on all included dialects as well as links to third-party\ndialects, see :ref:`dialect_toplevel`.\n\nPostgreSQL\n^^^^^^^^^^\n\nThe PostgreSQL dialect uses psycopg2 as the default DBAPI.  Other\nPostgreSQL DBAPIs include pg8000 and asyncpg::\n\n    # default\n    engine = create_engine("postgresql://scott:tiger@localhost/mydatabase")\n\n    # psycopg2\n    engine = create_engine("postgresql+psycopg2://scott:tiger@localhost/mydatabase")\n\n    # pg8000\n    engine = create_engine("postgresql+pg8000://scott:tiger@localhost/mydatabase")\n\nMore notes on connecting to PostgreSQL at :ref:`postgresql_toplevel`.\n\nMySQL\n^^^^^^^^^^\n\nThe MySQL dialect uses mysqlclient as the default DBAPI.  There are other\nMySQL DBAPIs available, including PyMySQL::\n\n    # default\n    engine = create_engine("mysql://scott:tiger@localhost/foo")\n\n    # mysqlclient (a maintained fork of MySQL-Python)\n    engine = create_engine("mysql+mysqldb://scott:tiger@localhost/foo")\n\n    # PyMySQL\n    engine = create_engine("mysql+pymysql://scott:tiger@localhost/foo")\n\nMore notes on connecting to MySQL at :ref:`mysql_toplevel`.\n\nOracle\n^^^^^^^^^^\n\nThe preferred Oracle Database dialect uses the python-oracledb driver as the\nDBAPI::\n\n      engine = create_engine(\n          "oracle+oracledb://scott:tiger@127.0.0.1:1521/?service_name=freepdb1"\n      )\n\n      engine = create_engine("oracle+oracledb://scott:tiger@tnsalias")\n\nFor historical reasons, the Oracle dialect uses the obsolete cx_Oracle driver\nas the default DBAPI::\n\n      engine = create_engine("oracle://scott:tiger@127.0.0.1:1521/?service_name=freepdb1")\n\n      engine = create_engine("oracle+cx_oracle://scott:tiger@tnsalias")\n\nMore notes on connecting to Oracle Database at :ref:`oracle_toplevel`.\n\nMicrosoft SQL Server\n^^^^^^^^^^^^^^^^^^^^\n\nThe SQL Server dialect uses pyodbc as the default DBAPI.  pymssql is\nalso available::\n\n    # pyodbc\n    engine = create_engine("mssql+pyodbc://scott:tiger@mydsn")\n\n    # pymssql\n    engine = create_engine("mssql+pymssql://scott:tiger@hostname:port/dbname")\n\nMore notes on connecting to SQL Server at :ref:`mssql_toplevel`.\n\nSQLite\n^^^^^^^\n\nSQLite connects to file-based databases, using the Python built-in\nmodule ``sqlite3`` by default.\n\nAs SQLite connects to local files, the URL format is slightly different.\nThe "file" portion of the URL is the filename of the database.\nFor a relative file path, this requires three slashes::\n\n    # sqlite://<nohostname>/<path>\n    # where <path> is relative:\n    engine = create_engine("sqlite:///foo.db")\n\nAnd for an absolute file path, the three slashes are followed by the absolute path::\n\n    # Unix/Mac - 4 initial slashes in total\n    engine = create_engine("sqlite:////absolute/path/to/foo.db")\n\n    # Windows\n    engine = create_engine("sqlite:///C:\\\\path\\\\to\\\\foo.db")\n\n    # Windows alternative using raw string\n    engine = create_engine(r"sqlite:///C:\\path\\to\\foo.db")\n\nTo use a SQLite ``:memory:`` database, specify an empty URL::\n\n    engine = create_engine("sqlite://")\n\nMore notes on connecting to SQLite at :ref:`sqlite_toplevel`.\n\nOthers\n^^^^^^\n\nSee :ref:`dialect_toplevel`, the top-level page for all additional dialect\ndocumentation.\n\n.. _create_engine_args:\n\nEngine Creation API\n===================\n\n.. autofunction:: sqlalchemy.create_engine\n\n.. autofunction:: sqlalchemy.engine_from_config\n\n.. autofunction:: sqlalchemy.create_mock_engine\n\n.. autofunction:: sqlalchemy.engine.make_url\n\n.. autofunction:: sqlalchemy.create_pool_from_url\n\n.. autoclass:: sqlalchemy.engine.URL\n    :members:\n\nPooling\n=======\n\nThe :class:`_engine.Engine` will ask the connection pool for a\nconnection when the ``connect()`` or ``execute()`` methods are called. The\ndefault connection pool, :class:`~.QueuePool`, will open connections to the\ndatabase on an as-needed basis. As concurrent statements are executed,\n:class:`.QueuePool` will grow its pool of connections to a\ndefault size of five, and will allow a default "overflow" of ten. Since the\n:class:`_engine.Engine` is essentially "home base" for the\nconnection pool, it follows that you should keep a single\n:class:`_engine.Engine` per database established within an\napplication, rather than creating a new one for each connection.\n\n.. note::\n\n   :class:`.QueuePool` is not used by default for SQLite engines.  See\n   :ref:`sqlite_toplevel` for details on SQLite connection pool usage.\n\nFor more information on connection pooling, see :ref:`pooling_toplevel`.\n\n\n.. _custom_dbapi_args:\n\nCustom DBAPI connect() arguments / on-connect routines\n=======================================================\n\nFor cases where special connection methods are needed, in the vast majority\nof cases, it is most appropriate to use one of several hooks at the\n:func:`_sa.create_engine` level in order to customize this process. These\nare described in the following sub-sections.\n\nSpecial Keyword Arguments Passed to dbapi.connect()\n---------------------------------------------------\n\nAll Python DBAPIs accept additional arguments beyond the basics of connecting.\nCommon parameters include those to specify character set encodings and timeout\nvalues; more complex data includes special DBAPI constants and objects and SSL\nsub-parameters. There are two rudimentary means of passing these arguments\nwithout complexity.\n\nAdd Parameters to the URL Query string\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nSimple string values, as well as some numeric values and boolean flags, may be\noften specified in the query string of the URL directly. A common example of\nthis is DBAPIs that accept an argument ``encoding`` for character encodings,\nsuch as most MySQL DBAPIs::\n\n    engine = create_engine("mysql+pymysql://user:pass@host/test?charset=utf8mb4")\n\nThe advantage of using the query string is that additional DBAPI options may be\nspecified in configuration files in a manner that\'s portable to the DBAPI\nspecified in the URL. The specific parameters passed through at this level vary\nby SQLAlchemy dialect. Some dialects pass all arguments through as strings,\nwhile others will parse for specific datatypes and move parameters to different\nplaces, such as into driver-level DSNs and connect strings. As per-dialect\nbehavior in this area currently varies, the dialect documentation should be\nconsulted for the specific dialect in use to see if particular parameters are\nsupported at this level.\n\n.. tip::\n\n  A general technique to display the exact arguments passed to the DBAPI\n  for a given URL may be performed using the :meth:`.Dialect.create_connect_args`\n  method directly as follows::\n\n    >>> from sqlalchemy import create_engine\n    >>> engine = create_engine(\n    ...     "mysql+pymysql://some_user:some_pass@some_host/test?charset=utf8mb4"\n    ... )\n    >>> args, kwargs = engine.dialect.create_connect_args(engine.url)\n    >>> args, kwargs\n    ([], {\'host\': \'some_host\', \'database\': \'test\', \'user\': \'some_user\', \'password\': \'some_pass\', \'charset\': \'utf8mb4\', \'client_flag\': 2})\n\n  The above ``args, kwargs`` pair is normally passed to the DBAPI as\n  ``dbapi.connect(*args, **kwargs)``.\n\nUse the connect_args dictionary parameter\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nA more general system of passing any parameter to the ``dbapi.connect()``\nfunction that is guaranteed to pass all parameters at all times is the\n:paramref:`_sa.create_engine.connect_args` dictionary parameter. This may be\nused for parameters that are otherwise not handled by the dialect when added to\nthe query string, as well as when special sub-structures or objects must be\npassed to the DBAPI. Sometimes it\'s just that a particular flag must be sent as\nthe ``True`` symbol and the SQLAlchemy dialect is not aware of this keyword\nargument to coerce it from its string form as presented in the URL. Below\nillustrates the use of a psycopg2 "connection factory" that replaces the\nunderlying implementation the connection::\n\n\n    engine = create_engine(\n        "postgresql+psycopg2://user:pass@hostname/dbname",\n        connect_args={"connection_factory": MyConnectionFactory},\n    )\n\nAnother example is the pyodbc "timeout" parameter::\n\n    engine = create_engine(\n        "mssql+pyodbc://user:pass@sqlsrvr?driver=ODBC+Driver+13+for+SQL+Server",\n        connect_args={"timeout": 30},\n    )\n\nThe above example also illustrates that both URL "query string" parameters as\nwell as :paramref:`_sa.create_engine.connect_args` may be used at the same\ntime; in the case of pyodbc, the "driver" keyword has special meaning\nwithin the URL.\n\nControlling how parameters are passed to the DBAPI connect() function\n---------------------------------------------------------------------\n\nBeyond manipulating the parameters passed to ``connect()``, we can further\ncustomize how the DBAPI ``connect()`` function itself is called using the\n:meth:`.DialectEvents.do_connect` event hook. This hook is passed the full\n``*args, **kwargs`` that the dialect would send to ``connect()``. These\ncollections can then be modified in place to alter how they are used::\n\n    from sqlalchemy import event\n\n    engine = create_engine("postgresql+psycopg2://user:pass@hostname/dbname")\n\n\n    @event.listens_for(engine, "do_connect")\n    def receive_do_connect(dialect, conn_rec, cargs, cparams):\n        cparams["connection_factory"] = MyConnectionFactory\n\n.. _engines_dynamic_tokens:\n\nGenerating dynamic authentication tokens\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n:meth:`.DialectEvents.do_connect` is also an ideal way to dynamically\ninsert an authentication token that might change over the lifespan of an\n:class:`_sa.engine.Engine`. For example, if the token gets generated by\n``get_authentication_token()`` and passed to the DBAPI in  a ``token``\nparameter, this could be implemented as::\n\n    from sqlalchemy import event\n\n    engine = create_engine("postgresql+psycopg2://user@hostname/dbname")\n\n\n    @event.listens_for(engine, "do_connect")\n    def provide_token(dialect, conn_rec, cargs, cparams):\n        cparams["token"] = get_authentication_token()\n\n.. seealso::\n\n    :ref:`mssql_pyodbc_access_tokens` - a more concrete example involving\n    SQL Server\n\nModifying the DBAPI connection after connect, or running commands after connect\n-------------------------------------------------------------------------------\n\nFor a DBAPI connection that SQLAlchemy creates without issue, but where we\nwould like to modify the completed connection before it\'s actually used, such\nas for setting special flags or running certain commands, the\n:meth:`.PoolEvents.connect` event hook is the most appropriate hook.  This\nhook is called for every new connection created, before it is used by\nSQLAlchemy::\n\n    from sqlalchemy import event\n\n    engine = create_engine("postgresql+psycopg2://user:pass@hostname/dbname")\n\n\n    @event.listens_for(engine, "connect")\n    def connect(dbapi_connection, connection_record):\n        cursor_obj = dbapi_connection.cursor()\n        cursor_obj.execute("SET some session variables")\n        cursor_obj.close()\n\nFully Replacing the DBAPI ``connect()`` function\n------------------------------------------------\n\nFinally, the :meth:`.DialectEvents.do_connect` event hook can also allow us to take\nover the connection process entirely by establishing the connection\nand returning it::\n\n    from sqlalchemy import event\n\n    engine = create_engine("postgresql+psycopg2://user:pass@hostname/dbname")\n\n\n    @event.listens_for(engine, "do_connect")\n    def receive_do_connect(dialect, conn_rec, cargs, cparams):\n        # return the new DBAPI connection with whatever we\'d like to\n        # do\n        return psycopg2.connect(*cargs, **cparams)\n\nThe :meth:`.DialectEvents.do_connect` hook supersedes the previous\n:paramref:`_sa.create_engine.creator` hook, which remains available.\n:meth:`.DialectEvents.do_connect` has the distinct advantage that the\ncomplete arguments parsed from the URL are also passed to the user-defined\nfunction which is not the case with :paramref:`_sa.create_engine.creator`.\n\n.. _dbengine_logging:\n\nConfiguring Logging\n===================\n\nPython\'s standard `logging\n<https://docs.python.org/library/logging.html>`_ module is used to\nimplement informational and debug log output with SQLAlchemy. This allows\nSQLAlchemy\'s logging to integrate in a standard way with other applications\nand libraries.   There are also two parameters\n:paramref:`_sa.create_engine.echo` and :paramref:`_sa.create_engine.echo_pool`\npresent on :func:`_sa.create_engine` which allow immediate logging to ``sys.stdout``\nfor the purposes of local development; these parameters ultimately interact\nwith the regular Python loggers described below.\n\nThis section assumes familiarity with the above linked logging module. All\nlogging performed by SQLAlchemy exists underneath the ``sqlalchemy``\nnamespace, as used by ``logging.getLogger(\'sqlalchemy\')``. When logging has\nbeen configured (i.e. such as via ``logging.basicConfig()``), the general\nnamespace of SA loggers that can be turned on is as follows:\n\n* ``sqlalchemy.engine`` - controls SQL echoing.  Set to ``logging.INFO`` for\n  SQL query output, ``logging.DEBUG`` for query + result set output.  These\n  settings are equivalent to ``echo=True`` and ``echo="debug"`` on\n  :paramref:`_sa.create_engine.echo`, respectively.\n\n* ``sqlalchemy.pool`` - controls connection pool logging.  Set to\n  ``logging.INFO`` to log connection invalidation and recycle events; set to\n  ``logging.DEBUG`` to additionally log all pool checkins and checkouts.\n  These settings are equivalent to ``pool_echo=True`` and ``pool_echo="debug"``\n  on :paramref:`_sa.create_engine.echo_pool`, respectively.\n\n* ``sqlalchemy.dialects`` - controls custom logging for SQL dialects, to the\n  extent that logging is used within specific dialects, which is generally\n  minimal.\n\n* ``sqlalchemy.orm`` - controls logging of various ORM functions to the extent\n  that logging is used within the ORM, which is generally minimal.  Set to\n  ``logging.INFO`` to log some top-level information on mapper configurations.\n\nFor example, to log SQL queries using Python logging instead of the\n``echo=True`` flag::\n\n    import logging\n\n    logging.basicConfig()\n    logging.getLogger("sqlalchemy.engine").setLevel(logging.INFO)\n\nBy default, the log level is set to ``logging.WARN`` within the entire\n``sqlalchemy`` namespace so that no log operations occur, even within an\napplication that has logging enabled otherwise.\n\n.. note::\n\n   The SQLAlchemy :class:`_engine.Engine` conserves Python function call\n   overhead by only emitting log statements when the current logging level is\n   detected as ``logging.INFO`` or ``logging.DEBUG``.  It only checks this\n   level when a new connection is procured from the connection pool.  Therefore\n   when changing the logging configuration for an already-running application,\n   any :class:`_engine.Connection` that\'s currently active, or more commonly a\n   :class:`~.orm.session.Session` object that\'s active in a transaction, won\'t\n   log any SQL according to the new configuration until a new\n   :class:`_engine.Connection` is procured (in the case of\n   :class:`~.orm.session.Session`, this is after the current transaction ends\n   and a new one begins).\n\nMore on the Echo Flag\n---------------------\n\nAs mentioned previously, the :paramref:`_sa.create_engine.echo` and :paramref:`_sa.create_engine.echo_pool`\nparameters are a shortcut to immediate logging to ``sys.stdout``::\n\n\n    >>> from sqlalchemy import create_engine, text\n    >>> e = create_engine("sqlite://", echo=True, echo_pool="debug")\n    >>> with e.connect() as conn:\n    ...     print(conn.scalar(text("select \'hi\'")))\n    2020-10-24 12:54:57,701 DEBUG sqlalchemy.pool.impl.SingletonThreadPool Created new connection <sqlite3.Connection object at 0x7f287819ac60>\n    2020-10-24 12:54:57,701 DEBUG sqlalchemy.pool.impl.SingletonThreadPool Connection <sqlite3.Connection object at 0x7f287819ac60> checked out from pool\n    2020-10-24 12:54:57,702 INFO sqlalchemy.engine.Engine select \'hi\'\n    2020-10-24 12:54:57,702 INFO sqlalchemy.engine.Engine ()\n    hi\n    2020-10-24 12:54:57,703 DEBUG sqlalchemy.pool.impl.SingletonThreadPool Connection <sqlite3.Connection object at 0x7f287819ac60> being returned to pool\n    2020-10-24 12:54:57,704 DEBUG sqlalchemy.pool.impl.SingletonThreadPool Connection <sqlite3.Connection object at 0x7f287819ac60> rollback-on-return\n\nUse of these flags is roughly equivalent to::\n\n    import logging\n\n    logging.basicConfig()\n    logging.getLogger("sqlalchemy.engine").setLevel(logging.INFO)\n    logging.getLogger("sqlalchemy.pool").setLevel(logging.DEBUG)\n\nIt\'s important to note that these two flags work **independently** of any\nexisting logging configuration, and will make use of ``logging.basicConfig()``\nunconditionally.  This has the effect of being configured **in addition** to\nany existing logger configurations. Therefore, **when configuring logging\nexplicitly, ensure all echo flags are set to False at all times**, to avoid\ngetting duplicate log lines.\n\nSetting the Logging Name\n-------------------------\n\nThe logger name for :class:`~sqlalchemy.engine.Engine` or\n:class:`~sqlalchemy.pool.Pool` is set to be the module-qualified class name of the\nobject.  This name can be further qualified with an additional name\nusing the\n:paramref:`_sa.create_engine.logging_name` and\n:paramref:`_sa.create_engine.pool_logging_name` parameters with\n:func:`sqlalchemy.create_engine`; the name will be appended to existing\nclass-qualified logging name.   This use is recommended for applications that\nmake use of multiple global :class:`.Engine` instances simultaenously, so\nthat they may be distinguished in logging::\n\n    >>> import logging\n    >>> from sqlalchemy import create_engine\n    >>> from sqlalchemy import text\n    >>> logging.basicConfig()\n    >>> logging.getLogger("sqlalchemy.engine.Engine.myengine").setLevel(logging.INFO)\n    >>> e = create_engine("sqlite://", logging_name="myengine")\n    >>> with e.connect() as conn:\n    ...     conn.execute(text("select \'hi\'"))\n    2020-10-24 12:47:04,291 INFO sqlalchemy.engine.Engine.myengine select \'hi\'\n    2020-10-24 12:47:04,292 INFO sqlalchemy.engine.Engine.myengine ()\n\n.. tip::\n\n    The :paramref:`_sa.create_engine.logging_name` and\n    :paramref:`_sa.create_engine.pool_logging_name` parameters may also be used in\n    conjunction with :paramref:`_sa.create_engine.echo` and\n    :paramref:`_sa.create_engine.echo_pool`. However, an unavoidable double logging\n    condition will occur if other engines are created with echo flags set to True\n    and **no** logging name. This is because a handler will be added automatically\n    for ``sqlalchemy.engine.Engine`` which will log messages both for the name-less\n    engine as well as engines with logging names.   For example::\n\n        from sqlalchemy import create_engine, text\n\n        e1 = create_engine("sqlite://", echo=True, logging_name="myname")\n        with e1.begin() as conn:\n            conn.execute(text("SELECT 1"))\n\n        e2 = create_engine("sqlite://", echo=True)\n        with e2.begin() as conn:\n            conn.execute(text("SELECT 2"))\n\n        with e1.begin() as conn:\n            conn.execute(text("SELECT 3"))\n\n    The above scenario will double log ``SELECT 3``.  To resolve, ensure\n    all engines have a ``logging_name`` set, or use explicit logger / handler\n    setup without using :paramref:`_sa.create_engine.echo` and\n    :paramref:`_sa.create_engine.echo_pool`.\n\n.. _dbengine_logging_tokens:\n\nSetting Per-Connection / Sub-Engine Tokens\n------------------------------------------\n\n.. versionadded:: 1.4.0b2\n\n\nWhile the logging name is appropriate to establish on an\n:class:`_engine.Engine` object that is long lived, it\'s not flexible enough\nto accommodate for an arbitrarily large list of names, for the case of\ntracking individual connections and/or transactions in log messages.\n\nFor this use case, the log message itself generated by the\n:class:`_engine.Connection` and :class:`_engine.Result` objects may be\naugmented with additional tokens such as transaction or request identifiers.\nThe :paramref:`_engine.Connection.execution_options.logging_token` parameter\naccepts a string argument that may be used to establish per-connection tracking\ntokens::\n\n    >>> from sqlalchemy import create_engine\n    >>> e = create_engine("sqlite://", echo="debug")\n    >>> with e.connect().execution_options(logging_token="track1") as conn:\n    ...     conn.execute(text("select 1")).all()\n    2021-02-03 11:48:45,754 INFO sqlalchemy.engine.Engine [track1] select 1\n    2021-02-03 11:48:45,754 INFO sqlalchemy.engine.Engine [track1] [raw sql] ()\n    2021-02-03 11:48:45,754 DEBUG sqlalchemy.engine.Engine [track1] Col (\'1\',)\n    2021-02-03 11:48:45,755 DEBUG sqlalchemy.engine.Engine [track1] Row (1,)\n\nThe :paramref:`_engine.Connection.execution_options.logging_token` parameter\nmay also be established on engines or sub-engines via\n:paramref:`_sa.create_engine.execution_options` or :meth:`_engine.Engine.execution_options`.\nThis may be useful to apply different logging tokens to different components\nof an application without creating new engines::\n\n    >>> from sqlalchemy import create_engine\n    >>> e = create_engine("sqlite://", echo="debug")\n    >>> e1 = e.execution_options(logging_token="track1")\n    >>> e2 = e.execution_options(logging_token="track2")\n    >>> with e1.connect() as conn:\n    ...     conn.execute(text("select 1")).all()\n    2021-02-03 11:51:08,960 INFO sqlalchemy.engine.Engine [track1] select 1\n    2021-02-03 11:51:08,960 INFO sqlalchemy.engine.Engine [track1] [raw sql] ()\n    2021-02-03 11:51:08,960 DEBUG sqlalchemy.engine.Engine [track1] Col (\'1\',)\n    2021-02-03 11:51:08,961 DEBUG sqlalchemy.engine.Engine [track1] Row (1,)\n\n    >>> with e2.connect() as conn:\n    ...     conn.execute(text("select 2")).all()\n    2021-02-03 11:52:05,518 INFO sqlalchemy.engine.Engine [track2] Select 1\n    2021-02-03 11:52:05,519 INFO sqlalchemy.engine.Engine [track2] [raw sql] ()\n    2021-02-03 11:52:05,520 DEBUG sqlalchemy.engine.Engine [track2] Col (\'1\',)\n    2021-02-03 11:52:05,520 DEBUG sqlalchemy.engine.Engine [track2] Row (1,)\n\n\nHiding Parameters\n------------------\n\nThe logging emitted by :class:`_engine.Engine` also indicates an excerpt\nof the SQL parameters that are present for a particular statement.  To prevent\nthese parameters from being logged for privacy purposes, enable the\n:paramref:`_sa.create_engine.hide_parameters` flag::\n\n    >>> e = create_engine("sqlite://", echo=True, hide_parameters=True)\n    >>> with e.connect() as conn:\n    ...     conn.execute(text("select :some_private_name"), {"some_private_name": "pii"})\n    2020-10-24 12:48:32,808 INFO sqlalchemy.engine.Engine select ?\n    2020-10-24 12:48:32,808 INFO sqlalchemy.engine.Engine [SQL parameters hidden due to hide_parameters=True]\n',
            'doc/build/orm/backref.rst': '.. _relationships_backref:\n\nUsing the legacy \'backref\' relationship parameter\n--------------------------------------------------\n\n.. note:: The :paramref:`_orm.relationship.backref` keyword should be considered\n   legacy, and use of :paramref:`_orm.relationship.back_populates` with explicit\n   :func:`_orm.relationship` constructs should be preferred.  Using\n   individual :func:`_orm.relationship` constructs provides advantages\n   including that both ORM mapped classes will include their attributes\n   up front as the class is constructed, rather than as a deferred step,\n   and configuration is more straightforward as all arguments are explicit.\n   New :pep:`484` features in SQLAlchemy 2.0 also take advantage of\n   attributes being explicitly present in source code rather than\n   using dynamic attribute generation.\n\n.. seealso::\n\n    For general information about bidirectional relationships, see the\n    following sections:\n\n    :ref:`tutorial_orm_related_objects` - in the :ref:`unified_tutorial`,\n    presents an overview of bi-directional relationship configuration\n    and behaviors using :paramref:`_orm.relationship.back_populates`\n\n    :ref:`back_populates_cascade` - notes on bi-directional :func:`_orm.relationship`\n    behavior regarding :class:`_orm.Session` cascade behaviors.\n\n    :paramref:`_orm.relationship.back_populates`\n\n\nThe :paramref:`_orm.relationship.backref` keyword argument on the\n:func:`_orm.relationship` construct allows the\nautomatic generation of a new :func:`_orm.relationship` that will be automatically\nbe added to the ORM mapping for the related class.  It will then be\nplaced into a :paramref:`_orm.relationship.back_populates` configuration\nagainst the current :func:`_orm.relationship` being configured, with both\n:func:`_orm.relationship` constructs referring to each other.\n\nStarting with the following example::\n\n    from sqlalchemy import Column, ForeignKey, Integer, String\n    from sqlalchemy.orm import DeclarativeBase, relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n\n        addresses = relationship("Address", backref="user")\n\n\n    class Address(Base):\n        __tablename__ = "address"\n        id = mapped_column(Integer, primary_key=True)\n        email = mapped_column(String)\n        user_id = mapped_column(Integer, ForeignKey("user.id"))\n\nThe above configuration establishes a collection of ``Address`` objects on ``User`` called\n``User.addresses``.   It also establishes a ``.user`` attribute on ``Address`` which will\nrefer to the parent ``User`` object.   Using :paramref:`_orm.relationship.back_populates`\nit\'s equivalent to the following::\n\n    from sqlalchemy import Column, ForeignKey, Integer, String\n    from sqlalchemy.orm import DeclarativeBase, relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n\n        addresses = relationship("Address", back_populates="user")\n\n\n    class Address(Base):\n        __tablename__ = "address"\n        id = mapped_column(Integer, primary_key=True)\n        email = mapped_column(String)\n        user_id = mapped_column(Integer, ForeignKey("user.id"))\n\n        user = relationship("User", back_populates="addresses")\n\nThe behavior of the ``User.addresses`` and ``Address.user`` relationships\nis that they now behave in a **bi-directional** way, indicating that\nchanges on one side of the relationship impact the other.   An example\nand discussion of this behavior is in the :ref:`unified_tutorial`\nat :ref:`tutorial_orm_related_objects`.\n\n\nBackref Default Arguments\n~~~~~~~~~~~~~~~~~~~~~~~~~\n\nSince :paramref:`_orm.relationship.backref` generates a whole new\n:func:`_orm.relationship`, the generation process by default\nwill attempt to include corresponding arguments in the new\n:func:`_orm.relationship` that correspond to the original arguments.\nAs an example, below is a :func:`_orm.relationship` that includes a\n:ref:`custom join condition <relationship_configure_joins>`\nwhich also includes the :paramref:`_orm.relationship.backref` keyword::\n\n    from sqlalchemy import Column, ForeignKey, Integer, String\n    from sqlalchemy.orm import DeclarativeBase, relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n\n        addresses = relationship(\n            "Address",\n            primaryjoin=(\n                "and_(User.id==Address.user_id, Address.email.startswith(\'tony\'))"\n            ),\n            backref="user",\n        )\n\n\n    class Address(Base):\n        __tablename__ = "address"\n        id = mapped_column(Integer, primary_key=True)\n        email = mapped_column(String)\n        user_id = mapped_column(Integer, ForeignKey("user.id"))\n\nWhen the "backref" is generated, the :paramref:`_orm.relationship.primaryjoin`\ncondition is copied to the new :func:`_orm.relationship` as well::\n\n    >>> print(User.addresses.property.primaryjoin)\n    "user".id = address.user_id AND address.email LIKE :email_1 || \'%%\'\n    >>>\n    >>> print(Address.user.property.primaryjoin)\n    "user".id = address.user_id AND address.email LIKE :email_1 || \'%%\'\n    >>>\n\nOther arguments that are transferrable include the\n:paramref:`_orm.relationship.secondary` parameter that refers to a\nmany-to-many association table, as well as the "join" arguments\n:paramref:`_orm.relationship.primaryjoin` and\n:paramref:`_orm.relationship.secondaryjoin`; "backref" is smart enough to know\nthat these two arguments should also be "reversed" when generating\nthe opposite side.\n\nSpecifying Backref Arguments\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nLots of other arguments for a "backref" are not implicit, and\ninclude arguments like\n:paramref:`_orm.relationship.lazy`,\n:paramref:`_orm.relationship.remote_side`,\n:paramref:`_orm.relationship.cascade` and\n:paramref:`_orm.relationship.cascade_backrefs`.   For this case we use\nthe :func:`.backref` function in place of a string; this will store\na specific set of arguments that will be transferred to the new\n:func:`_orm.relationship` when generated::\n\n    # <other imports>\n    from sqlalchemy.orm import backref\n\n\n    class User(Base):\n        __tablename__ = "user"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n\n        addresses = relationship(\n            "Address",\n            backref=backref("user", lazy="joined"),\n        )\n\nWhere above, we placed a ``lazy="joined"`` directive only on the ``Address.user``\nside, indicating that when a query against ``Address`` is made, a join to the ``User``\nentity should be made automatically which will populate the ``.user`` attribute of each\nreturned ``Address``.   The :func:`.backref` function formatted the arguments we gave\nit into a form that is interpreted by the receiving :func:`_orm.relationship` as additional\narguments to be applied to the new relationship it creates.\n\n',
            'doc/build/orm/cascades.rst': '.. _unitofwork_cascades:\n\nCascades\n========\n\nMappers support the concept of configurable :term:`cascade` behavior on\n:func:`~sqlalchemy.orm.relationship` constructs.  This refers\nto how operations performed on a "parent" object relative to a\nparticular :class:`.Session` should be propagated to items\nreferred to by that relationship (e.g. "child" objects), and is\naffected by the :paramref:`_orm.relationship.cascade` option.\n\nThe default behavior of cascade is limited to cascades of the\nso-called :ref:`cascade_save_update` and :ref:`cascade_merge` settings.\nThe typical "alternative" setting for cascade is to add\nthe :ref:`cascade_delete` and :ref:`cascade_delete_orphan` options;\nthese settings are appropriate for related objects which only exist as\nlong as they are attached to their parent, and are otherwise deleted.\n\nCascade behavior is configured using the\n:paramref:`_orm.relationship.cascade` option on\n:func:`~sqlalchemy.orm.relationship`::\n\n    class Order(Base):\n        __tablename__ = "order"\n\n        items = relationship("Item", cascade="all, delete-orphan")\n        customer = relationship("User", cascade="save-update")\n\nTo set cascades on a backref, the same flag can be used with the\n:func:`~.sqlalchemy.orm.backref` function, which ultimately feeds\nits arguments back into :func:`~sqlalchemy.orm.relationship`::\n\n    class Item(Base):\n        __tablename__ = "item"\n\n        order = relationship(\n            "Order", backref=backref("items", cascade="all, delete-orphan")\n        )\n\n.. sidebar:: The Origins of Cascade\n\n    SQLAlchemy\'s notion of cascading behavior on relationships,\n    as well as the options to configure them, are primarily derived\n    from the similar feature in the Hibernate ORM; Hibernate refers\n    to "cascade" in a few places such as in\n    `Example: Parent/Child <https://docs.jboss.org/hibernate/orm/3.3/reference/en-US/html/example-parentchild.html>`_.\n    If cascades are confusing, we\'ll refer to their conclusion,\n    stating "The sections we have just covered can be a bit confusing.\n    However, in practice, it all works out nicely."\n\nThe default value of :paramref:`_orm.relationship.cascade` is ``save-update, merge``.\nThe typical alternative setting for this parameter is either\n``all`` or more commonly ``all, delete-orphan``.  The ``all`` symbol\nis a synonym for ``save-update, merge, refresh-expire, expunge, delete``,\nand using it in conjunction with ``delete-orphan`` indicates that the child\nobject should follow along with its parent in all cases, and be deleted once\nit is no longer associated with that parent.\n\n.. warning:: The ``all`` cascade option implies the\n   :ref:`cascade_refresh_expire`\n   cascade setting which may not be desirable when using the\n   :ref:`asyncio_toplevel` extension, as it will expire related objects\n   more aggressively than is typically appropriate in an explicit IO context.\n   See the notes at :ref:`asyncio_orm_avoid_lazyloads` for further background.\n\nThe list of available values which can be specified for\nthe :paramref:`_orm.relationship.cascade` parameter are described in the following subsections.\n\n.. _cascade_save_update:\n\nsave-update\n-----------\n\n``save-update`` cascade indicates that when an object is placed into a\n:class:`.Session` via :meth:`.Session.add`, all the objects associated\nwith it via this :func:`_orm.relationship` should also be added to that\nsame :class:`.Session`.  Suppose we have an object ``user1`` with two\nrelated objects ``address1``, ``address2``::\n\n    >>> user1 = User()\n    >>> address1, address2 = Address(), Address()\n    >>> user1.addresses = [address1, address2]\n\nIf we add ``user1`` to a :class:`.Session`, it will also add\n``address1``, ``address2`` implicitly::\n\n    >>> sess = Session()\n    >>> sess.add(user1)\n    >>> address1 in sess\n    True\n\n``save-update`` cascade also affects attribute operations for objects\nthat are already present in a :class:`.Session`.  If we add a third\nobject, ``address3`` to the ``user1.addresses`` collection, it\nbecomes part of the state of that :class:`.Session`::\n\n    >>> address3 = Address()\n    >>> user1.addresses.append(address3)\n    >>> address3 in sess\n    True\n\nA ``save-update`` cascade can exhibit surprising behavior when removing an item from\na collection or de-associating an object from a scalar attribute. In some cases, the\norphaned objects may still be pulled into the ex-parent\'s :class:`.Session`; this is\nso that the flush process may handle that related object appropriately.\nThis case usually only arises if an object is removed from one :class:`.Session`\nand added to another::\n\n    >>> user1 = sess1.scalars(select(User).filter_by(id=1)).first()\n    >>> address1 = user1.addresses[0]\n    >>> sess1.close()  # user1, address1 no longer associated with sess1\n    >>> user1.addresses.remove(address1)  # address1 no longer associated with user1\n    >>> sess2 = Session()\n    >>> sess2.add(user1)  # ... but it still gets added to the new session,\n    >>> address1 in sess2  # because it\'s still "pending" for flush\n    True\n\nThe ``save-update`` cascade is on by default, and is typically taken\nfor granted; it simplifies code by allowing a single call to\n:meth:`.Session.add` to register an entire structure of objects within\nthat :class:`.Session` at once.   While it can be disabled, there\nis usually not a need to do so.\n\n.. _back_populates_cascade:\n\n.. _backref_cascade:\n\nBehavior of save-update cascade with bi-directional relationships\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe ``save-update`` cascade takes place **uni-directionally** in the context of\na bi-directional relationship, i.e. when using\nthe :paramref:`_orm.relationship.back_populates` or :paramref:`_orm.relationship.backref`\nparameters to create two separate\n:func:`_orm.relationship` objects which refer to each other.\n\nAn object that\'s not associated with a :class:`_orm.Session`, when assigned to\nan attribute or collection on a parent object that is associated with a\n:class:`_orm.Session`, will be automatically added to that same\n:class:`_orm.Session`. However, the same operation in reverse will not have\nthis effect; an object that\'s not associated with a :class:`_orm.Session`, upon\nwhich a child object that is associated with a :class:`_orm.Session` is\nassigned, will not result in an automatic addition of that parent object to the\n:class:`_orm.Session`.  The overall subject of this behavior is known\nas "cascade backrefs", and represents a change in behavior that was standardized\nas of SQLAlchemy 2.0.\n\nTo illustrate, given a mapping of ``Order`` objects which relate\nbi-directionally to a series of ``Item`` objects via relationships\n``Order.items`` and ``Item.order``::\n\n    mapper_registry.map_imperatively(\n        Order,\n        order_table,\n        properties={"items": relationship(Item, back_populates="order")},\n    )\n\n    mapper_registry.map_imperatively(\n        Item,\n        item_table,\n        properties={"order": relationship(Order, back_populates="items")},\n    )\n\nIf an ``Order`` is already associated with a :class:`_orm.Session`, and\nan ``Item`` object is then created and appended to the ``Order.items``\ncollection of that ``Order``, the ``Item`` will be automatically cascaded\ninto that same :class:`_orm.Session`::\n\n    >>> o1 = Order()\n    >>> session.add(o1)\n    >>> o1 in session\n    True\n\n    >>> i1 = Item()\n    >>> o1.items.append(i1)\n    >>> o1 is i1.order\n    True\n    >>> i1 in session\n    True\n\nAbove, the bidirectional nature of ``Order.items`` and ``Item.order`` means\nthat appending to ``Order.items`` also assigns to ``Item.order``. At the same\ntime, the ``save-update`` cascade allowed for the ``Item`` object to be added\nto the same :class:`_orm.Session` which the parent ``Order`` was already\nassociated.\n\nHowever, if the operation above is performed in the **reverse** direction,\nwhere ``Item.order`` is assigned rather than appending directly to\n``Order.item``, the cascade operation into the :class:`_orm.Session` will\n**not** take place automatically, even though the object assignments\n``Order.items`` and ``Item.order`` will be in the same state as in the\nprevious example::\n\n    >>> o1 = Order()\n    >>> session.add(o1)\n    >>> o1 in session\n    True\n\n    >>> i1 = Item()\n    >>> i1.order = o1\n    >>> i1 in order.items\n    True\n    >>> i1 in session\n    False\n\nIn the above case, after the ``Item`` object is created and all the desired\nstate is set upon it, it should then be added to the :class:`_orm.Session`\nexplicitly::\n\n    >>> session.add(i1)\n\nIn older versions of SQLAlchemy, the save-update cascade would occur\nbidirectionally in all cases. It was then made optional using an option known\nas ``cascade_backrefs``. Finally, in SQLAlchemy 1.4 the old behavior was\ndeprecated and the ``cascade_backrefs`` option was removed in SQLAlchemy 2.0.\nThe rationale is that users generally do not find it intuitive that assigning\nto an attribute on an object, illustrated above as the assignment of\n``i1.order = o1``, would alter the persistence state of that object ``i1`` such\nthat it\'s now pending within a :class:`_orm.Session`, and there would\nfrequently be subsequent issues where autoflush would prematurely flush the\nobject and cause errors, in those cases where the given object was still being\nconstructed and wasn\'t in a ready state to be flushed. The option to select between\nuni-directional and bi-directional behvaiors was also removed, as this option\ncreated two slightly different ways of working, adding to the overall learning\ncurve of the ORM as well as to the documentation and user support burden.\n\n.. seealso::\n\n    :ref:`change_5150` - background on the change in behavior for\n    "cascade backrefs"\n\n.. _cascade_delete:\n\ndelete\n------\n\nThe ``delete`` cascade indicates that when a "parent" object\nis marked for deletion, its related "child" objects should also be marked\nfor deletion.   If for example we have a relationship ``User.addresses``\nwith ``delete`` cascade configured::\n\n    class User(Base):\n        # ...\n\n        addresses = relationship("Address", cascade="all, delete")\n\nIf using the above mapping, we have a ``User`` object and two\nrelated ``Address`` objects::\n\n    >>> user1 = sess1.scalars(select(User).filter_by(id=1)).first()\n    >>> address1, address2 = user1.addresses\n\nIf we mark ``user1`` for deletion, after the flush operation proceeds,\n``address1`` and ``address2`` will also be deleted:\n\n.. sourcecode:: pycon+sql\n\n    >>> sess.delete(user1)\n    >>> sess.commit()\n    {execsql}DELETE FROM address WHERE address.id = ?\n    ((1,), (2,))\n    DELETE FROM user WHERE user.id = ?\n    (1,)\n    COMMIT\n\nAlternatively, if our ``User.addresses`` relationship does *not* have\n``delete`` cascade, SQLAlchemy\'s default behavior is to instead de-associate\n``address1`` and ``address2`` from ``user1`` by setting their foreign key\nreference to ``NULL``.  Using a mapping as follows::\n\n    class User(Base):\n        # ...\n\n        addresses = relationship("Address")\n\nUpon deletion of a parent ``User`` object, the rows in ``address`` are not\ndeleted, but are instead de-associated:\n\n.. sourcecode:: pycon+sql\n\n    >>> sess.delete(user1)\n    >>> sess.commit()\n    {execsql}UPDATE address SET user_id=? WHERE address.id = ?\n    (None, 1)\n    UPDATE address SET user_id=? WHERE address.id = ?\n    (None, 2)\n    DELETE FROM user WHERE user.id = ?\n    (1,)\n    COMMIT\n\n:ref:`cascade_delete` cascade on one-to-many relationships is often combined\nwith :ref:`cascade_delete_orphan` cascade, which will emit a DELETE for the\nrelated row if the "child" object is deassociated from the parent.  The\ncombination of ``delete`` and ``delete-orphan`` cascade covers both\nsituations where SQLAlchemy has to decide between setting a foreign key\ncolumn to NULL versus deleting the row entirely.\n\nThe feature by default works completely independently of database-configured\n``FOREIGN KEY`` constraints that may themselves configure ``CASCADE`` behavior.\nIn order to integrate more efficiently with this configuration, additional\ndirectives described at :ref:`passive_deletes` should be used.\n\n.. warning::  Note that the ORM\'s "delete" and "delete-orphan" behavior applies\n   **only** to the use of the :meth:`_orm.Session.delete` method to mark\n   individual ORM instances for deletion within the :term:`unit of work` process.\n   It does **not** apply to "bulk" deletes, which would be emitted using\n   the :func:`_sql.delete` construct as illustrated at\n   :ref:`orm_queryguide_update_delete_where`.   See\n   :ref:`orm_queryguide_update_delete_caveats` for additional background.\n\n.. seealso::\n\n    :ref:`passive_deletes`\n\n    :ref:`cascade_delete_many_to_many`\n\n    :ref:`cascade_delete_orphan`\n\n.. _cascade_delete_many_to_many:\n\nUsing delete cascade with many-to-many relationships\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe ``cascade="all, delete"`` option works equally well with a many-to-many\nrelationship, one that uses :paramref:`_orm.relationship.secondary` to\nindicate an association table.   When a parent object is deleted, and therefore\nde-associated with its related objects, the unit of work process will normally\ndelete rows from the association table, but leave the related objects intact.\nWhen combined with ``cascade="all, delete"``, additional ``DELETE`` statements\nwill take place for the child rows themselves.\n\nThe following example adapts that of :ref:`relationships_many_to_many` to\nillustrate the ``cascade="all, delete"`` setting on **one** side of the\nassociation::\n\n    association_table = Table(\n        "association",\n        Base.metadata,\n        Column("left_id", Integer, ForeignKey("left.id")),\n        Column("right_id", Integer, ForeignKey("right.id")),\n    )\n\n\n    class Parent(Base):\n        __tablename__ = "left"\n        id = mapped_column(Integer, primary_key=True)\n        children = relationship(\n            "Child",\n            secondary=association_table,\n            back_populates="parents",\n            cascade="all, delete",\n        )\n\n\n    class Child(Base):\n        __tablename__ = "right"\n        id = mapped_column(Integer, primary_key=True)\n        parents = relationship(\n            "Parent",\n            secondary=association_table,\n            back_populates="children",\n        )\n\nAbove, when a ``Parent`` object is marked for deletion\nusing :meth:`_orm.Session.delete`, the flush process will as usual delete\nthe associated rows from the ``association`` table, however per cascade\nrules it will also delete all related ``Child`` rows.\n\n\n.. warning::\n\n    If the above ``cascade="all, delete"`` setting were configured on **both**\n    relationships, then the cascade action would continue cascading through all\n    ``Parent`` and ``Child`` objects, loading each ``children`` and ``parents``\n    collection encountered and deleting everything that\'s connected.   It is\n    typically not desirable for "delete" cascade to be configured\n    bidirectionally.\n\n.. seealso::\n\n  :ref:`relationships_many_to_many_deletion`\n\n  :ref:`passive_deletes_many_to_many`\n\n.. _passive_deletes:\n\nUsing foreign key ON DELETE cascade with ORM relationships\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe behavior of SQLAlchemy\'s "delete" cascade overlaps with the\n``ON DELETE`` feature of a database ``FOREIGN KEY`` constraint.\nSQLAlchemy allows configuration of these schema-level :term:`DDL` behaviors\nusing the :class:`_schema.ForeignKey` and :class:`_schema.ForeignKeyConstraint`\nconstructs; usage of these objects in conjunction with :class:`_schema.Table`\nmetadata is described at :ref:`on_update_on_delete`.\n\nIn order to use ``ON DELETE`` foreign key cascades in conjunction with\n:func:`_orm.relationship`, it\'s important to note first and foremost that the\n:paramref:`_orm.relationship.cascade` setting must still be configured to\nmatch the desired "delete" or "set null" behavior (using ``delete`` cascade\nor leaving it omitted), so that whether the ORM or the database\nlevel constraints will handle the task of actually modifying the data in the\ndatabase, the ORM will still be able to appropriately track the state of\nlocally present objects that may be affected.\n\nThere is then an additional option on :func:`_orm.relationship` which\nindicates the degree to which the ORM should try to run DELETE/UPDATE\noperations on related rows itself, vs. how much it should rely upon expecting\nthe database-side FOREIGN KEY constraint cascade to handle the task; this is\nthe :paramref:`_orm.relationship.passive_deletes` parameter and it accepts\noptions ``False`` (the default), ``True`` and ``"all"``.\n\nThe most typical example is that where child rows are to be deleted when\nparent rows are deleted, and that ``ON DELETE CASCADE`` is configured\non the relevant ``FOREIGN KEY`` constraint as well::\n\n\n    class Parent(Base):\n        __tablename__ = "parent"\n        id = mapped_column(Integer, primary_key=True)\n        children = relationship(\n            "Child",\n            back_populates="parent",\n            cascade="all, delete",\n            passive_deletes=True,\n        )\n\n\n    class Child(Base):\n        __tablename__ = "child"\n        id = mapped_column(Integer, primary_key=True)\n        parent_id = mapped_column(Integer, ForeignKey("parent.id", ondelete="CASCADE"))\n        parent = relationship("Parent", back_populates="children")\n\nThe behavior of the above configuration when a parent row is deleted\nis as follows:\n\n1. The application calls ``session.delete(my_parent)``, where ``my_parent``\n   is an instance of ``Parent``.\n\n2. When the :class:`_orm.Session` next flushes changes to the database,\n   all of the **currently loaded** items within the ``my_parent.children``\n   collection are deleted by the ORM, meaning a ``DELETE`` statement is\n   emitted for each record.\n\n3. If the ``my_parent.children`` collection is **unloaded**, then no ``DELETE``\n   statements are emitted.   If the :paramref:`_orm.relationship.passive_deletes`\n   flag were **not** set on this :func:`_orm.relationship`, then a ``SELECT``\n   statement for unloaded ``Child`` objects would have been emitted.\n\n4. A ``DELETE`` statement is then emitted for the ``my_parent`` row itself.\n\n5. The database-level ``ON DELETE CASCADE`` setting ensures that all rows in\n   ``child`` which refer to the affected row in ``parent`` are also deleted.\n\n6. The ``Parent`` instance referred to by ``my_parent``, as well as all\n   instances of ``Child`` that were related to this object and were\n   **loaded** (i.e. step 2 above took place), are de-associated from the\n   :class:`._orm.Session`.\n\n.. note::\n\n    To use "ON DELETE CASCADE", the underlying database engine must\n    support ``FOREIGN KEY`` constraints and they must be enforcing:\n\n    * When using MySQL, an appropriate storage engine must be\n      selected.  See :ref:`mysql_storage_engines` for details.\n\n    * When using SQLite, foreign key support must be enabled explicitly.\n      See :ref:`sqlite_foreign_keys` for details.\n\n.. topic:: Notes on Passive Deletes\n\n    It is important to note the differences between the ORM and the relational\n    database\'s notion of "cascade" as well as how they integrate:\n\n    * A database level ``ON DELETE`` cascade is configured effectively\n      on the **many-to-one** side of the relationship; that is, we configure\n      it relative to the ``FOREIGN KEY`` constraint that is the "many" side\n      of a relationship.  At the ORM level, **this direction is reversed**.\n      SQLAlchemy handles the deletion of "child" objects relative to a\n      "parent" from the "parent" side, which means that ``delete`` and\n      ``delete-orphan`` cascade are configured on the **one-to-many**\n      side.\n\n    * Database level foreign keys with no ``ON DELETE`` setting are often used\n      to **prevent** a parent row from being removed, as it would necessarily\n      leave an unhandled related row present.  If this behavior is desired in a\n      one-to-many relationship, SQLAlchemy\'s default behavior of setting a\n      foreign key to ``NULL`` can be caught in one of two ways:\n\n        * The easiest and most common is just to set the foreign-key-holding\n          column to ``NOT NULL`` at the database schema level.  An attempt by\n          SQLAlchemy to set the column to NULL will fail with a simple NOT NULL\n          constraint exception.\n\n        * The other, more special case way is to set the\n          :paramref:`_orm.relationship.passive_deletes` flag to the string\n          ``"all"``.  This has the effect of entirely disabling\n          SQLAlchemy\'s behavior of setting the foreign key column to NULL,\n          and a DELETE will be emitted for the parent row without any\n          affect on the child row, even if the child row is present in\n          memory. This may be desirable in the case when database-level\n          foreign key triggers, either special ``ON DELETE`` settings or\n          otherwise, need to be activated in all cases when a parent row is\n          deleted.\n\n    * Database level ``ON DELETE`` cascade is generally much more efficient\n      than relying upon the "cascade" delete feature of SQLAlchemy.  The\n      database can chain a series of cascade operations across many\n      relationships at once; e.g. if row A is deleted, all the related rows in\n      table B can be deleted, and all the C rows related to each of those B\n      rows, and on and on, all within the scope of a single DELETE statement.\n      SQLAlchemy on the other hand, in order to support the cascading delete\n      operation fully, has to individually load each related collection in\n      order to target all rows that then may have further related collections.\n      That is, SQLAlchemy isn\'t sophisticated enough to emit a DELETE for all\n      those related rows at once within this context.\n\n    * SQLAlchemy doesn\'t **need** to be this sophisticated, as we instead\n      provide smooth integration with the database\'s own ``ON DELETE``\n      functionality, by using the :paramref:`_orm.relationship.passive_deletes`\n      option in conjunction with properly configured foreign key constraints.\n      Under this behavior, SQLAlchemy only emits DELETE for those rows that are\n      already locally present in the :class:`.Session`; for any collections\n      that are unloaded, it leaves them to the database to handle, rather than\n      emitting a SELECT for them.  The section :ref:`passive_deletes` provides\n      an example of this use.\n\n    * While database-level ``ON DELETE`` functionality works only on the "many"\n      side of a relationship, SQLAlchemy\'s "delete" cascade has **limited**\n      ability to operate in the *reverse* direction as well, meaning it can be\n      configured on the "many" side to delete an object on the "one" side when\n      the reference on the "many" side is deleted.  However this can easily\n      result in constraint violations if there are other objects referring to\n      this "one" side from the "many", so it typically is only useful when a\n      relationship is in fact a "one to one".  The\n      :paramref:`_orm.relationship.single_parent` flag should be used to\n      establish an in-Python assertion for this case.\n\n.. _passive_deletes_many_to_many:\n\nUsing foreign key ON DELETE with many-to-many relationships\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nAs described at :ref:`cascade_delete_many_to_many`, "delete" cascade works\nfor many-to-many relationships as well.  To make use of ``ON DELETE CASCADE``\nforeign keys in conjunction with many to many, ``FOREIGN KEY`` directives\nare configured on the association table.   These directives can handle\nthe task of automatically deleting from the association table, but cannot\naccommodate the automatic deletion of the related objects themselves.\n\nIn this case, the :paramref:`_orm.relationship.passive_deletes` directive can\nsave us some additional ``SELECT`` statements during a delete operation but\nthere are still some collections that the ORM will continue to load, in order\nto locate affected child objects and handle them correctly.\n\n.. note::\n\n  Hypothetical optimizations to this could include a single ``DELETE``\n  statement against all parent-associated rows of the association table at\n  once, then use ``RETURNING`` to locate affected related child rows, however\n  this is not currently part of the ORM unit of work implementation.\n\nIn this configuration, we configure ``ON DELETE CASCADE`` on both foreign key\nconstraints of the association table.  We configure ``cascade="all, delete"``\non the parent->child side of the relationship, and we can then configure\n``passive_deletes=True`` on the **other** side of the bidirectional\nrelationship as illustrated below::\n\n    association_table = Table(\n        "association",\n        Base.metadata,\n        Column("left_id", Integer, ForeignKey("left.id", ondelete="CASCADE")),\n        Column("right_id", Integer, ForeignKey("right.id", ondelete="CASCADE")),\n    )\n\n\n    class Parent(Base):\n        __tablename__ = "left"\n        id = mapped_column(Integer, primary_key=True)\n        children = relationship(\n            "Child",\n            secondary=association_table,\n            back_populates="parents",\n            cascade="all, delete",\n        )\n\n\n    class Child(Base):\n        __tablename__ = "right"\n        id = mapped_column(Integer, primary_key=True)\n        parents = relationship(\n            "Parent",\n            secondary=association_table,\n            back_populates="children",\n            passive_deletes=True,\n        )\n\nUsing the above configuration, the deletion of a ``Parent`` object proceeds\nas follows:\n\n1. A ``Parent`` object is marked for deletion using\n   :meth:`_orm.Session.delete`.\n\n2. When the flush occurs, if the ``Parent.children`` collection is not loaded,\n   the ORM will first emit a SELECT statement in order to load the ``Child``\n   objects that correspond to ``Parent.children``.\n\n3. It will then then emit ``DELETE`` statements for the rows in ``association``\n   which correspond to that parent row.\n\n4. for each ``Child`` object affected by this immediate deletion, because\n   ``passive_deletes=True`` is configured, the unit of work will not need to\n   try to emit SELECT statements for each ``Child.parents`` collection as it\n   is assumed the corresponding rows in ``association`` will be deleted.\n\n5. ``DELETE`` statements are then emitted for each ``Child`` object that was\n   loaded from ``Parent.children``.\n\n\n.. _cascade_delete_orphan:\n\ndelete-orphan\n-------------\n\n``delete-orphan`` cascade adds behavior to the ``delete`` cascade,\nsuch that a child object will be marked for deletion when it is\nde-associated from the parent, not just when the parent is marked\nfor deletion.   This is a common feature when dealing with a related\nobject that is "owned" by its parent, with a NOT NULL foreign key,\nso that removal of the item from the parent collection results\nin its deletion.\n\n``delete-orphan`` cascade implies that each child object can only\nhave one parent at a time, and in the **vast majority of cases is configured\nonly on a one-to-many relationship.**   For the much less common\ncase of setting it on a many-to-one or\nmany-to-many relationship, the "many" side can be forced to allow only\na single object at a time by configuring the :paramref:`_orm.relationship.single_parent` argument,\nwhich establishes Python-side validation that ensures the object\nis associated with only one parent at a time, however this greatly limits\nthe functionality of the "many" relationship and is usually not what\'s\ndesired.\n\n.. seealso::\n\n  :ref:`error_bbf0` - background on a common error scenario involving delete-orphan\n  cascade.\n\n.. _cascade_merge:\n\nmerge\n-----\n\n``merge`` cascade indicates that the :meth:`.Session.merge`\noperation should be propagated from a parent that\'s the subject\nof the :meth:`.Session.merge` call down to referred objects.\nThis cascade is also on by default.\n\n.. _cascade_refresh_expire:\n\nrefresh-expire\n--------------\n\n``refresh-expire`` is an uncommon option, indicating that the\n:meth:`.Session.expire` operation should be propagated from a parent\ndown to referred objects.   When using :meth:`.Session.refresh`,\nthe referred objects are expired only, but not actually refreshed.\n\n.. _cascade_expunge:\n\nexpunge\n-------\n\n``expunge`` cascade indicates that when the parent object is removed\nfrom the :class:`.Session` using :meth:`.Session.expunge`, the\noperation should be propagated down to referred objects.\n\n\n.. _session_deleting_from_collections:\n\nNotes on Delete - Deleting Objects Referenced from Collections and Scalar Relationships\n----------------------------------------------------------------------------------------\n\nThe ORM in general never modifies the contents of a collection or scalar\nrelationship during the flush process.  This means, if your class has a\n:func:`_orm.relationship` that refers to a collection of objects, or a reference\nto a single object such as many-to-one, the contents of this attribute will\nnot be modified when the flush process occurs.  Instead, it is expected\nthat the :class:`.Session` would eventually be expired, either through the expire-on-commit behavior of\n:meth:`.Session.commit` or through explicit use of :meth:`.Session.expire`.\nAt that point, any referenced object or collection associated with that\n:class:`.Session` will be cleared and will re-load itself upon next access.\n\nA common confusion that arises regarding this behavior involves the use of the\n:meth:`~.Session.delete` method.   When :meth:`.Session.delete` is invoked upon\nan object and the :class:`.Session` is flushed, the row is deleted from the\ndatabase.  Rows that refer to the target row via  foreign key, assuming they\nare tracked using a :func:`_orm.relationship` between the two mapped object types,\nwill also see their foreign key attributes UPDATED to null, or if delete\ncascade is set up, the related rows will be deleted as well. However, even\nthough rows related to the deleted object might be themselves modified as well,\n**no changes occur to relationship-bound collections or object references on\nthe objects** involved in the operation within the scope of the flush\nitself.   This means if the object was a\nmember of a related collection, it will still be present on the Python side\nuntil that collection is expired.  Similarly, if the object were\nreferenced via many-to-one or one-to-one from another object, that reference\nwill remain present on that object until the object is expired as well.\n\nBelow, we illustrate that after an ``Address`` object is marked\nfor deletion, it\'s still present in the collection associated with the\nparent ``User``, even after a flush::\n\n    >>> address = user.addresses[1]\n    >>> session.delete(address)\n    >>> session.flush()\n    >>> address in user.addresses\n    True\n\nWhen the above session is committed, all attributes are expired.  The next\naccess of ``user.addresses`` will re-load the collection, revealing the\ndesired state::\n\n    >>> session.commit()\n    >>> address in user.addresses\n    False\n\nThere is a recipe for intercepting :meth:`.Session.delete` and invoking this\nexpiration automatically; see `ExpireRelationshipOnFKChange <https://www.sqlalchemy.org/trac/wiki/UsageRecipes/ExpireRelationshipOnFKChange>`_ for this.  However, the usual practice of\ndeleting items within collections is to forego the usage of\n:meth:`~.Session.delete` directly, and instead use cascade behavior to\nautomatically invoke the deletion as a result of removing the object from the\nparent collection.  The ``delete-orphan`` cascade accomplishes this, as\nillustrated in the example below::\n\n    class User(Base):\n        __tablename__ = "user"\n\n        # ...\n\n        addresses = relationship("Address", cascade="all, delete-orphan")\n\n\n    # ...\n\n    del user.addresses[1]\n    session.flush()\n\nWhere above, upon removing the ``Address`` object from the ``User.addresses``\ncollection, the ``delete-orphan`` cascade has the effect of marking the ``Address``\nobject for deletion in the same way as passing it to :meth:`~.Session.delete`.\n\nThe ``delete-orphan`` cascade can also be applied to a many-to-one\nor one-to-one relationship, so that when an object is de-associated from its\nparent, it is also automatically marked for deletion.   Using ``delete-orphan``\ncascade on a many-to-one or one-to-one requires an additional flag\n:paramref:`_orm.relationship.single_parent` which invokes an assertion\nthat this related object is not to shared with any other parent simultaneously::\n\n    class User(Base):\n        # ...\n\n        preference = relationship(\n            "Preference", cascade="all, delete-orphan", single_parent=True\n        )\n\nAbove, if a hypothetical ``Preference`` object is removed from a ``User``,\nit will be deleted on flush::\n\n    some_user.preference = None\n    session.flush()  # will delete the Preference object\n\n.. seealso::\n\n    :ref:`unitofwork_cascades` for detail on cascades.\n\n',
            'doc/build/orm/dataclasses.rst': '.. _orm_dataclasses_toplevel:\n\n======================================\nIntegration with dataclasses and attrs\n======================================\n\nSQLAlchemy as of version 2.0 features "native dataclass" integration where\nan :ref:`Annotated Declarative Table <orm_declarative_mapped_column>`\nmapping may be turned into a Python dataclass_ by adding a single mixin\nor decorator to mapped classes.\n\n.. versionadded:: 2.0 Integrated dataclass creation with ORM Declarative classes\n\nThere are also patterns available that allow existing dataclasses to be\nmapped, as well as to map classes instrumented by the\nattrs_ third party integration library.\n\n.. _orm_declarative_native_dataclasses:\n\nDeclarative Dataclass Mapping\n-----------------------------\n\nSQLAlchemy :ref:`Annotated Declarative Table <orm_declarative_mapped_column>`\nmappings may be augmented with an additional\nmixin class or decorator directive, which will add an additional step to\nthe Declarative process after the mapping is complete that will convert\nthe mapped class **in-place** into a Python dataclass_, before completing\nthe mapping process which applies ORM-specific :term:`instrumentation`\nto the class.   The most prominent behavioral addition this provides is\ngeneration of an ``__init__()`` method with fine-grained control over\npositional and keyword arguments with or without defaults, as well as\ngeneration of methods like ``__repr__()`` and ``__eq__()``.\n\nFrom a :pep:`484` typing perspective, the class is recognized\nas having Dataclass-specific behaviors, most notably  by taking advantage of :pep:`681`\n"Dataclass Transforms", which allows typing tools to consider the class\nas though it were explicitly decorated using the ``@dataclasses.dataclass``\ndecorator.\n\n.. note::  Support for :pep:`681` in typing tools as of **April 4, 2023** is\n   limited and is currently known to be supported by Pyright_ as well\n   as Mypy_ as of **version 1.2**.  Note that Mypy 1.1.1 introduced\n   :pep:`681` support but did not correctly accommodate Python descriptors\n   which will lead to errors when using SQLAlchemy\'s ORM mapping scheme.\n\n   .. seealso::\n\n      https://peps.python.org/pep-0681/#the-dataclass-transform-decorator - background\n      on how libraries like SQLAlchemy enable :pep:`681` support\n\n\nDataclass conversion may be added to any Declarative class either by adding the\n:class:`_orm.MappedAsDataclass` mixin to a :class:`_orm.DeclarativeBase` class\nhierarchy, or for decorator mapping by using the\n:meth:`_orm.registry.mapped_as_dataclass` class decorator or its\nfunctional variant :func:`_orm.mapped_as_dataclass`.\n\nThe :class:`_orm.MappedAsDataclass` mixin may be applied either\nto the Declarative ``Base`` class or any superclass, as in the example\nbelow::\n\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import MappedAsDataclass\n\n\n    class Base(MappedAsDataclass, DeclarativeBase):\n        """subclasses will be converted to dataclasses"""\n\n\n    class User(Base):\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\nOr may be applied directly to classes that extend from the Declarative base::\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import MappedAsDataclass\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(MappedAsDataclass, Base):\n        """User class will be converted to a dataclass"""\n\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\nWhen using the decorator form, the :meth:`_orm.registry.mapped_as_dataclass`\ndecorator is supported::\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n\n    reg = registry()\n\n\n    @reg.mapped_as_dataclass\n    class User:\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\nThe same method is available in a standalone function form, which may\nhave better compatibility with some versions of the mypy type checker::\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User:\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\n.. versionadded:: 2.0.44 Added :func:`_orm.mapped_as_dataclass` after observing\n   mypy compatibility issues with the method form of the same feature\n\nClass level feature configuration\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nSupport for dataclasses features is partial.  Currently **supported** are\nthe ``init``, ``repr``, ``eq``, ``order`` and ``unsafe_hash`` features,\n``match_args`` and ``kw_only`` are supported on Python 3.10+.\nCurrently **not supported** are the ``frozen`` and ``slots`` features.\n\nWhen using the mixin class form with :class:`_orm.MappedAsDataclass`,\nclass configuration arguments are passed as class-level parameters::\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import MappedAsDataclass\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(MappedAsDataclass, Base, repr=False, unsafe_hash=True):\n        """User class will be converted to a dataclass"""\n\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\nWhen using the decorator form with :meth:`_orm.registry.mapped_as_dataclass` or\n:func:`_orm.mapped_as_dataclass`, class configuration arguments are passed to\nthe decorator directly::\n\n    from sqlalchemy.orm import registry\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n\n\n    reg = registry()\n\n\n    @reg.mapped_as_dataclass(unsafe_hash=True)\n    class User:\n        """User class will be converted to a dataclass"""\n\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\nFor background on dataclass class options, see the dataclasses_ documentation\nat `@dataclasses.dataclass <https://docs.python.org/3/library/dataclasses.html#dataclasses.dataclass>`_.\n\nAttribute Configuration\n^^^^^^^^^^^^^^^^^^^^^^^\n\nSQLAlchemy native dataclasses differ from normal dataclasses in that\nattributes to be mapped are described using the :class:`_orm.Mapped`\ngeneric annotation container in all cases.    Mappings follow the same\nforms as those documented at :ref:`orm_declarative_table`, and all\nfeatures of :func:`_orm.mapped_column` and :class:`_orm.Mapped` are supported.\n\nAdditionally, ORM attribute configuration constructs including\n:func:`_orm.mapped_column`, :func:`_orm.relationship` and :func:`_orm.composite`\nsupport **per-attribute field options**, including ``init``, ``default``,\n``default_factory`` and ``repr``.  The names of these arguments is fixed\nas specified in :pep:`681`.   Functionality is equivalent to dataclasses:\n\n* ``init``, as in :paramref:`_orm.mapped_column.init`,\n  :paramref:`_orm.relationship.init`, if False indicates the field should\n  not be part of the ``__init__()`` method\n* ``default``, as in :paramref:`_orm.mapped_column.default`,\n  :paramref:`_orm.relationship.default`\n  indicates a default value for the field as given as a keyword argument\n  in the ``__init__()`` method.\n* ``default_factory``, as in :paramref:`_orm.mapped_column.default_factory`,\n  :paramref:`_orm.relationship.default_factory`, indicates a callable function\n  that will be invoked to generate a new default value for a parameter\n  if not passed explicitly to the ``__init__()`` method.\n* ``repr`` True by default, indicates the field should be part of the generated\n  ``__repr__()`` method\n\n\nAnother key difference from dataclasses is that default values for attributes\n**must** be configured using the ``default`` parameter of the ORM construct,\nsuch as ``mapped_column(default=None)``.   A syntax that resembles dataclass\nsyntax which accepts simple Python values as defaults without using\n``@dataclases.field()`` is not supported.\n\nAs an example using :func:`_orm.mapped_column`, the mapping below will\nproduce an ``__init__()`` method that accepts only the fields ``name`` and\n``fullname``, where ``name`` is required and may be passed positionally,\nand ``fullname`` is optional.  The ``id`` field, which we expect to be\ndatabase-generated, is not part of the constructor at all::\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User:\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n        fullname: Mapped[str] = mapped_column(default=None)\n\n\n    # \'fullname\' is optional keyword argument\n    u1 = User("name")\n\nColumn Defaults\n~~~~~~~~~~~~~~~\n\nIn order to accommodate the name overlap of the ``default`` argument with\nthe existing :paramref:`_schema.Column.default` parameter of the  :class:`_schema.Column`\nconstruct, the :func:`_orm.mapped_column` construct disambiguates the two\nnames by adding a new parameter :paramref:`_orm.mapped_column.insert_default`,\nwhich will be populated directly into the\n:paramref:`_schema.Column.default` parameter of  :class:`_schema.Column`,\nindependently of what may be set on\n:paramref:`_orm.mapped_column.default`, which is always used for the\ndataclasses configuration.  For example, to configure a datetime column with\na :paramref:`_schema.Column.default` set to the ``func.utc_timestamp()`` SQL function,\nbut where the parameter is optional in the constructor::\n\n    from datetime import datetime\n\n    from sqlalchemy import func\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User:\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        created_at: Mapped[datetime] = mapped_column(\n            insert_default=func.utc_timestamp(), default=None\n        )\n\nWith the above mapping, an ``INSERT`` for a new ``User`` object where no\nparameter for ``created_at`` were passed proceeds as:\n\n.. sourcecode:: pycon+sql\n\n    >>> with Session(e) as session:\n    ...     session.add(User())\n    ...     session.commit()\n    {execsql}BEGIN (implicit)\n    INSERT INTO user_account (created_at) VALUES (utc_timestamp())\n    [generated in 0.00010s] ()\n    COMMIT\n\n\n\nIntegration with Annotated\n~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe approach introduced at :ref:`orm_declarative_mapped_column_pep593`\nillustrates how to use :pep:`593` ``Annotated`` objects to package whole\n:func:`_orm.mapped_column` constructs for re-use.  While ``Annotated`` objects\ncan be combined with the use of dataclasses, **dataclass-specific keyword\narguments unfortunately cannot be used within the Annotated construct**.  This\nincludes :pep:`681`-specific arguments ``init``, ``default``, ``repr``, and\n``default_factory``, which **must** be present in a :func:`_orm.mapped_column`\nor similar construct inline with the class attribute.\n\n.. versionchanged:: 2.0.14/2.0.22  the ``Annotated`` construct when used with\n   an ORM construct like :func:`_orm.mapped_column` cannot accommodate dataclass\n   field parameters such as ``init`` and ``repr`` - this use goes against the\n   design of Python dataclasses and is not supported by :pep:`681`, and therefore\n   is also rejected by the SQLAlchemy ORM at runtime.   A deprecation warning\n   is now emitted and the attribute will be ignored.\n\nAs an example, the ``init=False`` parameter below will be ignored and additionally\nemit a deprecation warning::\n\n    from typing import Annotated\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    # typing tools as well as SQLAlchemy will ignore init=False here\n    intpk = Annotated[int, mapped_column(init=False, primary_key=True)]\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User:\n        __tablename__ = "user_account"\n        id: Mapped[intpk]\n\n\n    # typing error as well as runtime error: Argument missing for parameter "id"\n    u1 = User()\n\nInstead, :func:`_orm.mapped_column` must be present on the right side\nas well with an explicit setting for :paramref:`_orm.mapped_column.init`;\nthe other arguments can remain within the ``Annotated`` construct::\n\n    from typing import Annotated\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    intpk = Annotated[int, mapped_column(primary_key=True)]\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User:\n        __tablename__ = "user_account"\n\n        # init=False and other pep-681 arguments must be inline\n        id: Mapped[intpk] = mapped_column(init=False)\n\n\n    u1 = User()\n\n.. _orm_declarative_dc_mixins:\n\nUsing mixins and abstract superclasses\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nMixin and abstract superclass are supported with the Declarative Dataclass\nMapping by defining classes that are part of the :class:`_orm.MappedAsDataclass`\nhierarchy, either without including a declarative base or by setting\n``__abstract__ = True``.  The example below illustrates a class ``Mixin`` that is\nnot itself mapped, but serves as part of the base for a mapped class::\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import MappedAsDataclass\n\n\n    class Mixin(MappedAsDataclass):\n        create_user: Mapped[int] = mapped_column()\n        update_user: Mapped[Optional[int]] = mapped_column(default=None)\n\n\n    class Base(DeclarativeBase, MappedAsDataclass):\n        pass\n\n\n    class User(Base, Mixin):\n        __tablename__ = "sys_user"\n\n        uid: Mapped[str] = mapped_column(\n            String(50), init=False, default_factory=uuid4, primary_key=True\n        )\n        username: Mapped[str] = mapped_column()\n        email: Mapped[str] = mapped_column()\n\n.. tip::\n\n    When using :class:`_orm.MappedAsDataclass` without a declarative base in\n    the hiearchy, the target class is still turned into a real Python dataclass,\n    so that it may properly serve as a base for a mapped dataclass.   Using\n    :class:`_orm.MappedAsDataclass` (or the :func:`_orm.unmapped_dataclass` decorator\n    described later in this section) is required in order for the class to be correctly\n    recognized by type checkers as SQLAlchemy-enabled dataclasses.   Declarative\n    itself will reject mixins / abstract classes that are not themselves\n    Declarative Dataclasses (e.g. they can\'t be plain classes nor can they be\n    plain ``@dataclass`` classes).\n\n    .. seealso::\n\n        :ref:`error_dcmx` - further background\n\nAnother example, where an abstract base combines :class:`_orm.MappedAsDataclass`\nwith ``__abstract__ = True``::\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import MappedAsDataclass\n\n\n    class Base(DeclarativeBase, MappedAsDataclass):\n        pass\n\n\n    class AbstractUser(Base):\n        __abstract__ = True\n\n        create_user: Mapped[int] = mapped_column()\n        update_user: Mapped[Optional[int]] = mapped_column(default=None)\n\n\n    class User(AbstractUser):\n        __tablename__ = "sys_user"\n\n        uid: Mapped[str] = mapped_column(\n            String(50), init=False, default_factory=uuid4, primary_key=True\n        )\n        username: Mapped[str] = mapped_column()\n        email: Mapped[str] = mapped_column()\n\nFinally, for a hierarchy that\'s based on use of the :func:`_orm.mapped_as_dataclass`\ndecorator, mixins may be defined using the :func:`_orm.unmapped_dataclass` decorator::\n\n    from sqlalchemy.orm import registry\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import unmapped_dataclass\n\n\n    @unmapped_dataclass()\n    class Mixin:\n        create_user: Mapped[int] = mapped_column()\n        update_user: Mapped[Optional[int]] = mapped_column(default=None, init=False)\n\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User(Mixin):\n        __tablename__ = "sys_user"\n\n        uid: Mapped[str] = mapped_column(\n            String(50), init=False, default_factory=uuid4, primary_key=True\n        )\n        username: Mapped[str] = mapped_column()\n        email: Mapped[str] = mapped_column()\n\n.. versionadded:: 2.1 Added :func:`_orm.unmapped_dataclass`\n\n.. _orm_declarative_dc_relationships:\n\nRelationship Configuration\n^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe :class:`_orm.Mapped` annotation in combination with\n:func:`_orm.relationship` is used in the same way as described at\n:ref:`relationship_patterns`.    When specifying a collection-based\n:func:`_orm.relationship` as an optional keyword argument, the\n:paramref:`_orm.relationship.default_factory` parameter must be passed and it\nmust refer to the collection class that\'s to be used.  Many-to-one and\nscalar object references may make use of\n:paramref:`_orm.relationship.default` if the default value is to be ``None``::\n\n    from typing import List\n\n    from sqlalchemy import ForeignKey\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n    from sqlalchemy.orm import relationship\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class Parent:\n        __tablename__ = "parent"\n        id: Mapped[int] = mapped_column(primary_key=True)\n        children: Mapped[List["Child"]] = relationship(\n            default_factory=list, back_populates="parent"\n        )\n\n\n    @mapped_as_dataclass(reg)\n    class Child:\n        __tablename__ = "child"\n        id: Mapped[int] = mapped_column(primary_key=True)\n        parent_id: Mapped[int] = mapped_column(ForeignKey("parent.id"))\n        parent: Mapped["Parent"] = relationship(default=None)\n\nThe above mapping will generate an empty list for ``Parent.children`` when a\nnew ``Parent()`` object is constructed without passing ``children``, and\nsimilarly a ``None`` value for ``Child.parent`` when a new ``Child()`` object\nis constructed without passing ``parent``.\n\nWhile the :paramref:`_orm.relationship.default_factory` can be automatically\nderived from the given collection class of the :func:`_orm.relationship`\nitself, this would break compatibility with dataclasses, as the presence\nof :paramref:`_orm.relationship.default_factory` or\n:paramref:`_orm.relationship.default` is what determines if the parameter is\nto be required or optional when rendered into the ``__init__()`` method.\n\n.. _orm_declarative_native_dataclasses_non_mapped_fields:\n\nUsing Non-Mapped Dataclass Fields\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nWhen using Declarative dataclasses, non-mapped fields may be used on the\nclass as well, which will be part of the dataclass construction process but\nwill not be mapped.   Any field that does not use :class:`.Mapped` will\nbe ignored by the mapping process.   In the example below, the fields\n``ctrl_one`` and ``ctrl_two`` will be part of the instance-level state\nof the object, but will not be persisted by the ORM::\n\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class Data:\n        __tablename__ = "data"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        status: Mapped[str]\n\n        ctrl_one: Optional[str] = None\n        ctrl_two: Optional[str] = None\n\nInstance of ``Data`` above can be created as::\n\n    d1 = Data(status="s1", ctrl_one="ctrl1", ctrl_two="ctrl2")\n\nA more real world example might be to make use of the Dataclasses\n``InitVar`` feature in conjunction with the ``__post_init__()`` feature to\nreceive init-only fields that can be used to compose persisted data.\nIn the example below, the ``User``\nclass is declared using ``id``, ``name`` and ``password_hash`` as mapped features,\nbut makes use of init-only ``password`` and ``repeat_password`` fields to\nrepresent the user creation process (note: to run this example, replace\nthe function ``your_crypt_function_here()`` with a third party crypt\nfunction, such as `bcrypt <https://pypi.org/project/bcrypt/>`_ or\n`argon2-cffi <https://pypi.org/project/argon2-cffi/>`_)::\n\n    from dataclasses import InitVar\n    from typing import Optional\n\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_as_dataclass\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    reg = registry()\n\n\n    @mapped_as_dataclass(reg)\n    class User:\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(init=False, primary_key=True)\n        name: Mapped[str]\n\n        password: InitVar[str]\n        repeat_password: InitVar[str]\n\n        password_hash: Mapped[str] = mapped_column(init=False, nullable=False)\n\n        def __post_init__(self, password: str, repeat_password: str):\n            if password != repeat_password:\n                raise ValueError("passwords do not match")\n\n            self.password_hash = your_crypt_function_here(password)\n\nThe above object is created with parameters ``password`` and\n``repeat_password``, which are consumed up front so that the ``password_hash``\nvariable may be generated::\n\n    >>> u1 = User(name="some_user", password="xyz", repeat_password="xyz")\n    >>> u1.password_hash\n    \'$6$9ppc... (example crypted string....)\'\n\n.. versionchanged:: 2.0.0rc1  When using :meth:`_orm.registry.mapped_as_dataclass`\n   or :class:`.MappedAsDataclass`, fields that do not include the\n   :class:`.Mapped` annotation may be included, which will be treated as part\n   of the resulting dataclass but not be mapped, without the need to\n   also indicate the ``__allow_unmapped__`` class attribute.  Previous 2.0\n   beta releases would require this attribute to be explicitly present,\n   even though the purpose of this attribute was only to allow legacy\n   ORM typed mappings to continue to function.\n\n.. _dataclasses_pydantic:\n\nIntegrating with Alternate Dataclass Providers such as Pydantic\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n.. warning::\n\n    The dataclass layer of Pydantic is **not fully compatible** with\n    SQLAlchemy\'s class instrumentation without additional internal changes,\n    and many features such as related collections may not work correctly.\n\n    For Pydantic compatibility, please consider the\n    `SQLModel <https://sqlmodel.tiangolo.com>`_ ORM which is built with\n    Pydantic on top of SQLAlchemy ORM, which includes special implementation\n    details which **explicitly resolve** these incompatibilities.\n\nSQLAlchemy\'s :class:`_orm.MappedAsDataclass` class\n:meth:`_orm.registry.mapped_as_dataclass` method, and\n:func:`_orm.mapped_as_dataclass` functions call directly into\nthe Python standard library ``dataclasses.dataclass`` class decorator, after\nthe declarative mapping process has been applied to the class.  This\nfunction call may be swapped out for alternateive dataclasses providers,\nsuch as that of Pydantic, using the ``dataclass_callable`` parameter\naccepted by :class:`_orm.MappedAsDataclass` as a class keyword argument\nas well as by :meth:`_orm.registry.mapped_as_dataclass`::\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import MappedAsDataclass\n    from sqlalchemy.orm import registry\n\n\n    class Base(\n        MappedAsDataclass,\n        DeclarativeBase,\n        dataclass_callable=pydantic.dataclasses.dataclass,\n    ):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        name: Mapped[str]\n\nThe above ``User`` class will be applied as a dataclass, using Pydantic\'s\n``pydantic.dataclasses.dataclasses`` callable.     The process is available\nboth for mapped classes as well as mixins that extend from\n:class:`_orm.MappedAsDataclass` or which have\n:meth:`_orm.registry.mapped_as_dataclass` applied directly.\n\n.. versionadded:: 2.0.4 Added the ``dataclass_callable`` class and method\n   parameters for :class:`_orm.MappedAsDataclass` and\n   :meth:`_orm.registry.mapped_as_dataclass`, and adjusted some of the\n   dataclass internals to accommodate more strict dataclass functions such as\n   that of Pydantic.\n\n\n.. _orm_declarative_dataclasses:\n\nApplying ORM Mappings to an existing dataclass (legacy dataclass use)\n---------------------------------------------------------------------\n\n.. legacy::\n\n   The approaches described here are superseded by\n   the :ref:`orm_declarative_native_dataclasses` feature new in the 2.0\n   series of SQLAlchemy.  This newer version of the feature builds upon\n   the dataclass support first added in version 1.4, which is described\n   in this section.\n\nTo map an existing dataclass, SQLAlchemy\'s "inline" declarative directives\ncannot be used directly; ORM directives are assigned using one of three\ntechniques:\n\n* Using "Declarative with Imperative Table", the table / column to be mapped\n  is defined using a :class:`_schema.Table` object assigned to the\n  ``__table__`` attribute of the class; relationships are defined within\n  ``__mapper_args__`` dictionary.  The class is mapped using the\n  :meth:`_orm.registry.mapped` decorator.   An example is below at\n  :ref:`orm_declarative_dataclasses_imperative_table`.\n\n* Using full "Declarative", the Declarative-interpreted directives such as\n  :class:`_schema.Column`, :func:`_orm.relationship` are added to the\n  ``.metadata`` dictionary of the ``dataclasses.field()`` construct, where\n  they are consumed by the declarative process.  The class is again\n  mapped using the :meth:`_orm.registry.mapped` decorator.  See the example\n  below at :ref:`orm_declarative_dataclasses_declarative_table`.\n\n* An "Imperative" mapping can be applied to an existing dataclass using\n  the :meth:`_orm.registry.map_imperatively` method to produce the mapping\n  in exactly the same way as described at :ref:`orm_imperative_mapping`.\n  This is illustrated below at :ref:`orm_imperative_dataclasses`.\n\nThe general process by which SQLAlchemy applies mappings to a dataclass\nis the same as that of an ordinary class, but also includes that\nSQLAlchemy will detect class-level attributes that were part of the\ndataclasses declaration process and replace them at runtime with\nthe usual SQLAlchemy ORM mapped attributes.   The ``__init__`` method that\nwould have been generated by dataclasses is left intact, as is the same\nfor all the other methods that dataclasses generates such as\n``__eq__()``, ``__repr__()``, etc.\n\n.. _orm_declarative_dataclasses_imperative_table:\n\nMapping pre-existing dataclasses using Declarative With Imperative Table\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nAn example of a mapping using ``@dataclass`` using\n:ref:`orm_imperative_table_configuration` is below. A complete\n:class:`_schema.Table` object is constructed explicitly and assigned to the\n``__table__`` attribute. Instance fields are defined using normal dataclass\nsyntaxes. Additional :class:`.MapperProperty`\ndefinitions such as :func:`.relationship`, are placed in the\n:ref:`__mapper_args__ <orm_declarative_mapper_options>` class-level\ndictionary underneath the ``properties`` key, corresponding to the\n:paramref:`_orm.Mapper.properties` parameter::\n\n    from __future__ import annotations\n\n    from dataclasses import dataclass, field\n    from typing import List, Optional\n\n    from sqlalchemy import Column, ForeignKey, Integer, String, Table\n    from sqlalchemy.orm import registry, relationship\n\n    mapper_registry = registry()\n\n\n    @mapper_registry.mapped\n    @dataclass\n    class User:\n        __table__ = Table(\n            "user",\n            mapper_registry.metadata,\n            Column("id", Integer, primary_key=True),\n            Column("name", String(50)),\n            Column("fullname", String(50)),\n            Column("nickname", String(12)),\n        )\n        id: int = field(init=False)\n        name: Optional[str] = None\n        fullname: Optional[str] = None\n        nickname: Optional[str] = None\n        addresses: List[Address] = field(default_factory=list)\n\n        __mapper_args__ = {  # type: ignore\n            "properties": {\n                "addresses": relationship("Address"),\n            }\n        }\n\n\n    @mapper_registry.mapped\n    @dataclass\n    class Address:\n        __table__ = Table(\n            "address",\n            mapper_registry.metadata,\n            Column("id", Integer, primary_key=True),\n            Column("user_id", Integer, ForeignKey("user.id")),\n            Column("email_address", String(50)),\n        )\n        id: int = field(init=False)\n        user_id: int = field(init=False)\n        email_address: Optional[str] = None\n\nIn the above example, the ``User.id``, ``Address.id``, and ``Address.user_id``\nattributes are defined as ``field(init=False)``. This means that parameters for\nthese won\'t be added to ``__init__()`` methods, but\n:class:`.Session` will still be able to set them after getting their values\nduring flush from autoincrement or other default value generator.   To\nallow them to be specified in the constructor explicitly, they would instead\nbe given a default value of ``None``.\n\nFor a :func:`_orm.relationship` to be declared separately, it needs to be\nspecified directly within the :paramref:`_orm.Mapper.properties` dictionary\nwhich itself is specified within the ``__mapper_args__`` dictionary, so that it\nis passed to the constructor for :class:`_orm.Mapper`. An alternative to this\napproach is in the next example.\n\n\n.. warning::\n    Declaring a dataclass ``field()`` setting a ``default`` together with ``init=False``\n    will not work as would be expected with a totally plain dataclass,\n    since the SQLAlchemy class instrumentation will replace\n    the default value set on the class by the dataclass creation process.\n    Use ``default_factory`` instead. This adaptation is done automatically when\n    making use of :ref:`orm_declarative_native_dataclasses`.\n\n.. _orm_declarative_dataclasses_declarative_table:\n\nMapping pre-existing dataclasses using Declarative-style fields\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n.. legacy:: This approach to Declarative mapping with\n   dataclasses should be considered as legacy.  It will remain supported\n   however is unlikely to offer any advantages against the new\n   approach detailed at :ref:`orm_declarative_native_dataclasses`.\n\n   Note that **mapped_column() is not supported with this use**;\n   the :class:`_schema.Column` construct should continue to be used to declare\n   table metadata within the ``metadata`` field of ``dataclasses.field()``.\n\nThe fully declarative approach requires that :class:`_schema.Column` objects\nare declared as class attributes, which when using dataclasses would conflict\nwith the dataclass-level attributes.  An approach to combine these together\nis to make use of the ``metadata`` attribute on the ``dataclass.field``\nobject, where SQLAlchemy-specific mapping information may be supplied.\nDeclarative supports extraction of these parameters when the class\nspecifies the attribute ``__sa_dataclass_metadata_key__``.  This also\nprovides a more succinct method of indicating the :func:`_orm.relationship`\nassociation::\n\n\n    from __future__ import annotations\n\n    from dataclasses import dataclass, field\n    from typing import List\n\n    from sqlalchemy import Column, ForeignKey, Integer, String\n    from sqlalchemy.orm import registry, relationship\n\n    mapper_registry = registry()\n\n\n    @mapper_registry.mapped\n    @dataclass\n    class User:\n        __tablename__ = "user"\n\n        __sa_dataclass_metadata_key__ = "sa"\n        id: int = field(init=False, metadata={"sa": Column(Integer, primary_key=True)})\n        name: str = field(default=None, metadata={"sa": Column(String(50))})\n        fullname: str = field(default=None, metadata={"sa": Column(String(50))})\n        nickname: str = field(default=None, metadata={"sa": Column(String(12))})\n        addresses: List[Address] = field(\n            default_factory=list, metadata={"sa": relationship("Address")}\n        )\n\n\n    @mapper_registry.mapped\n    @dataclass\n    class Address:\n        __tablename__ = "address"\n        __sa_dataclass_metadata_key__ = "sa"\n        id: int = field(init=False, metadata={"sa": Column(Integer, primary_key=True)})\n        user_id: int = field(init=False, metadata={"sa": Column(ForeignKey("user.id"))})\n        email_address: str = field(default=None, metadata={"sa": Column(String(50))})\n\n.. _orm_declarative_dataclasses_mixin:\n\nUsing Declarative Mixins with pre-existing dataclasses\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nIn the section :ref:`orm_mixins_toplevel`, Declarative Mixin classes\nare introduced.  One requirement of declarative mixins is that certain\nconstructs that can\'t be easily duplicated must be given as callables,\nusing the :class:`_orm.declared_attr` decorator, such as in the\nexample at :ref:`orm_declarative_mixins_relationships`::\n\n    class RefTargetMixin:\n        @declared_attr\n        def target_id(cls) -> Mapped[int]:\n            return mapped_column("target_id", ForeignKey("target.id"))\n\n        @declared_attr\n        def target(cls):\n            return relationship("Target")\n\nThis form is supported within the Dataclasses ``field()`` object by using\na lambda to indicate the SQLAlchemy construct inside the ``field()``.\nUsing :func:`_orm.declared_attr` to surround the lambda is optional.\nIf we wanted to produce our ``User`` class above where the ORM fields\ncame from a mixin that is itself a dataclass, the form would be::\n\n    @dataclass\n    class UserMixin:\n        __tablename__ = "user"\n\n        __sa_dataclass_metadata_key__ = "sa"\n\n        id: int = field(init=False, metadata={"sa": Column(Integer, primary_key=True)})\n\n        addresses: List[Address] = field(\n            default_factory=list, metadata={"sa": lambda: relationship("Address")}\n        )\n\n\n    @dataclass\n    class AddressMixin:\n        __tablename__ = "address"\n        __sa_dataclass_metadata_key__ = "sa"\n        id: int = field(init=False, metadata={"sa": Column(Integer, primary_key=True)})\n        user_id: int = field(\n            init=False, metadata={"sa": lambda: Column(ForeignKey("user.id"))}\n        )\n        email_address: str = field(default=None, metadata={"sa": Column(String(50))})\n\n\n    @mapper_registry.mapped\n    class User(UserMixin):\n        pass\n\n\n    @mapper_registry.mapped\n    class Address(AddressMixin):\n        pass\n\n.. versionadded:: 1.4.2  Added support for "declared attr" style mixin attributes,\n   namely :func:`_orm.relationship` constructs as well as :class:`_schema.Column`\n   objects with foreign key declarations, to be used within "Dataclasses\n   with Declarative Table" style mappings.\n\n\n\n.. _orm_imperative_dataclasses:\n\nMapping pre-existing dataclasses using Imperative Mapping\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nAs described previously, a class which is set up as a dataclass using the\n``@dataclass`` decorator can then be further decorated using the\n:meth:`_orm.registry.mapped` decorator in order to apply declarative-style\nmapping to the class. As an alternative to using the\n:meth:`_orm.registry.mapped` decorator, we may also pass the class through the\n:meth:`_orm.registry.map_imperatively` method instead, so that we may pass all\n:class:`_schema.Table` and :class:`_orm.Mapper` configuration imperatively to\nthe function rather than having them defined on the class itself as class\nvariables::\n\n    from __future__ import annotations\n\n    from dataclasses import dataclass\n    from dataclasses import field\n    from typing import List\n\n    from sqlalchemy import Column\n    from sqlalchemy import ForeignKey\n    from sqlalchemy import Integer\n    from sqlalchemy import MetaData\n    from sqlalchemy import String\n    from sqlalchemy import Table\n    from sqlalchemy.orm import registry\n    from sqlalchemy.orm import relationship\n\n    mapper_registry = registry()\n\n\n    @dataclass\n    class User:\n        id: int = field(init=False)\n        name: str = None\n        fullname: str = None\n        nickname: str = None\n        addresses: List[Address] = field(default_factory=list)\n\n\n    @dataclass\n    class Address:\n        id: int = field(init=False)\n        user_id: int = field(init=False)\n        email_address: str = None\n\n\n    metadata_obj = MetaData()\n\n    user = Table(\n        "user",\n        metadata_obj,\n        Column("id", Integer, primary_key=True),\n        Column("name", String(50)),\n        Column("fullname", String(50)),\n        Column("nickname", String(12)),\n    )\n\n    address = Table(\n        "address",\n        metadata_obj,\n        Column("id", Integer, primary_key=True),\n        Column("user_id", Integer, ForeignKey("user.id")),\n        Column("email_address", String(50)),\n    )\n\n    mapper_registry.map_imperatively(\n        User,\n        user,\n        properties={\n            "addresses": relationship(Address, backref="user", order_by=address.c.id),\n        },\n    )\n\n    mapper_registry.map_imperatively(Address, address)\n\nThe same warning mentioned in :ref:`orm_declarative_dataclasses_imperative_table`\napplies when using this mapping style.\n\n.. _orm_declarative_attrs_imperative_table:\n\nApplying ORM mappings to an existing attrs class\n-------------------------------------------------\n\n.. warning:: The ``attrs`` library is not part of SQLAlchemy\'s continuous\n   integration testing, and compatibility with this library may change without\n   notice due to incompatibilities introduced by either side.\n\n\nThe attrs_ library is a popular third party library that provides similar\nfeatures as dataclasses, with many additional features provided not\nfound in ordinary dataclasses.\n\nA class augmented with attrs_ uses the ``@define`` decorator. This decorator\ninitiates a process to scan the class for attributes that define the class\'\nbehavior, which are then used to generate methods, documentation, and\nannotations.\n\nThe SQLAlchemy ORM supports mapping an attrs_ class using **Imperative** mapping.\nThe general form of this style is equivalent to the\n:ref:`orm_imperative_dataclasses` mapping form used with\ndataclasses, where the class construction uses ``attrs`` alone, with ORM mappings\napplied after the fact without any class attribute scanning.\n\nThe ``@define`` decorator of attrs_ by default replaces the annotated class\nwith a new __slots__ based class, which is not supported. When using the old\nstyle annotation ``@attr.s`` or using ``define(slots=False)``, the class\ndoes not get replaced. Furthermore ``attrs`` removes its own class-bound attributes\nafter the decorator runs, so that SQLAlchemy\'s mapping process takes over these\nattributes without any issue. Both decorators, ``@attr.s`` and ``@define(slots=False)``\nwork with SQLAlchemy.\n\n.. versionchanged:: 2.0  SQLAlchemy integration with ``attrs`` works only\n   with imperative mapping style, that is, not using Declarative.\n   The introduction of ORM Annotated Declarative style is not cross-compatible\n   with ``attrs``.\n\nThe ``attrs`` class is built first.  The SQLAlchemy ORM mapping can be\napplied after the fact using :meth:`_orm.registry.map_imperatively`::\n\n    from __future__ import annotations\n\n    from typing import List\n\n    from attrs import define\n    from sqlalchemy import Column\n    from sqlalchemy import ForeignKey\n    from sqlalchemy import Integer\n    from sqlalchemy import MetaData\n    from sqlalchemy import String\n    from sqlalchemy import Table\n    from sqlalchemy.orm import registry\n    from sqlalchemy.orm import relationship\n\n    mapper_registry = registry()\n\n\n    @define(slots=False)\n    class User:\n        id: int\n        name: str\n        fullname: str\n        nickname: str\n        addresses: List[Address]\n\n\n    @define(slots=False)\n    class Address:\n        id: int\n        user_id: int\n        email_address: Optional[str]\n\n\n    metadata_obj = MetaData()\n\n    user = Table(\n        "user",\n        metadata_obj,\n        Column("id", Integer, primary_key=True),\n        Column("name", String(50)),\n        Column("fullname", String(50)),\n        Column("nickname", String(12)),\n    )\n\n    address = Table(\n        "address",\n        metadata_obj,\n        Column("id", Integer, primary_key=True),\n        Column("user_id", Integer, ForeignKey("user.id")),\n        Column("email_address", String(50)),\n    )\n\n    mapper_registry.map_imperatively(\n        User,\n        user,\n        properties={\n            "addresses": relationship(Address, backref="user", order_by=address.c.id),\n        },\n    )\n\n    mapper_registry.map_imperatively(Address, address)\n\n.. _dataclass: https://docs.python.org/3/library/dataclasses.html\n.. _dataclasses: https://docs.python.org/3/library/dataclasses.html\n.. _attrs: https://pypi.org/project/attrs/\n.. _mypy: https://mypy.readthedocs.io/en/stable/\n.. _pyright: https://github.com/microsoft/pyright\n',
            'doc/build/orm/declarative_tables.rst': '\n.. _orm_declarative_table_config_toplevel:\n\n=============================================\nTable Configuration with Declarative\n=============================================\n\nAs introduced at :ref:`orm_declarative_mapping`, the Declarative style\nincludes the ability to generate a mapped :class:`_schema.Table` object\nat the same time, or to accommodate a :class:`_schema.Table` or other\n:class:`_sql.FromClause` object directly.\n\nThe following examples assume a declarative base class as::\n\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        pass\n\nAll of the examples that follow illustrate a class inheriting from the above\n``Base``.  The decorator style introduced at :ref:`orm_declarative_decorator`\nis fully supported with all the following examples as well, as are legacy\nforms of Declarative Base including base classes generated by\n:func:`_orm.declarative_base`.\n\n\n.. _orm_declarative_table:\n\nDeclarative Table with ``mapped_column()``\n------------------------------------------\n\nWhen using Declarative, the body of the class to be mapped in most cases\nincludes an attribute ``__tablename__`` that indicates the string name of a\n:class:`_schema.Table` that should be generated along with the mapping. The\n:func:`_orm.mapped_column` construct, which features additional ORM-specific\nconfiguration capabilities not present in the plain :class:`_schema.Column`\nclass, is then used within the class body to indicate columns in the table. The\nexample below illustrates the most basic use of this construct within a\nDeclarative mapping::\n\n\n    from sqlalchemy import Integer, String\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import mapped_column\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String(50), nullable=False)\n        fullname = mapped_column(String)\n        nickname = mapped_column(String(30))\n\nAbove, :func:`_orm.mapped_column` constructs are placed inline within the class\ndefinition as class level attributes. At the point at which the class is\ndeclared, the Declarative mapping process will generate a new\n:class:`_schema.Table` object against the :class:`_schema.MetaData` collection\nassociated with the Declarative ``Base``; each instance of\n:func:`_orm.mapped_column` will then be used to generate a\n:class:`_schema.Column` object during this process, which will become part of\nthe :attr:`.schema.Table.columns` collection of this :class:`_schema.Table`\nobject.\n\nIn the above example, Declarative will build a :class:`_schema.Table`\nconstruct that is equivalent to the following::\n\n    # equivalent Table object produced\n    user_table = Table(\n        "user",\n        Base.metadata,\n        Column("id", Integer, primary_key=True),\n        Column("name", String(50)),\n        Column("fullname", String()),\n        Column("nickname", String(30)),\n    )\n\nWhen the ``User`` class above is mapped, this :class:`_schema.Table` object\ncan be accessed directly via the ``__table__`` attribute; this is described\nfurther at :ref:`orm_declarative_metadata`.\n\n.. sidebar::  ``mapped_column()`` supersedes the use of ``Column()``\n\n  Users of 1.x SQLAlchemy will note the use of the :func:`_orm.mapped_column`\n  construct, which is new as of the SQLAlchemy 2.0 series.  This ORM-specific\n  construct is intended first and foremost to be a drop-in replacement for\n  the use of :class:`_schema.Column` within Declarative mappings only, adding\n  new ORM-specific convenience features such as the ability to establish\n  :paramref:`_orm.mapped_column.deferred` within the construct, and most\n  importantly to indicate to typing tools such as Mypy_ and Pylance_ an\n  accurate representation of how the attribute will behave at runtime at\n  both the class level as well as the instance level.  As will be seen in\n  the following sections, it\'s also at the forefront of a new\n  annotation-driven configuration style introduced in SQLAlchemy 2.0.\n\n  Users of legacy code should be aware that the :class:`_schema.Column` form\n  will always work in Declarative in the same way it always has. The different\n  forms of attribute mapping may also be mixed within a single mapping on an\n  attribute by attribute basis, so migration to the new form can be at\n  any pace.   See the section :ref:`whatsnew_20_orm_declarative_typing` for\n  a step by step guide to migrating a Declarative model to the new form.\n\n\nThe :func:`_orm.mapped_column` construct accepts all arguments that are\naccepted by the :class:`_schema.Column` construct, as well as additional\nORM-specific arguments. The :paramref:`_orm.mapped_column.__name` positional parameter,\nindicating the name of the database column, is typically omitted, as the\nDeclarative process will make use of the attribute name given to the construct\nand assign this as the name of the column (in the above example, this refers to\nthe names ``id``, ``name``, ``fullname``, ``nickname``). Assigning an alternate\n:paramref:`_orm.mapped_column.__name` is valid as well, where the resulting\n:class:`_schema.Column` will use the given name in SQL and DDL statements,\nwhile the ``User`` mapped class will continue to allow access to the attribute\nusing the attribute name given, independent of the name given to the column\nitself (more on this at :ref:`mapper_column_distinct_names`).\n\n.. tip::\n\n    The :func:`_orm.mapped_column` construct is **only valid within a\n    Declarative class mapping**.   When constructing a :class:`_schema.Table`\n    object using Core as well as when using\n    :ref:`imperative table <orm_imperative_table_configuration>` configuration,\n    the :class:`_schema.Column` construct is still required in order to\n    indicate the presence of a database column.\n\n.. seealso::\n\n    :ref:`mapping_columns_toplevel` - contains additional notes on affecting\n    how :class:`_orm.Mapper` interprets incoming :class:`.Column` objects.\n\nORM Annotated Declarative - Automated Mapping with Type Annotations\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe :func:`_orm.mapped_column` construct in modern Python is normally augmented\nby the use of :pep:`484` Python type annotations, where it is capable of\nderiving its column-configuration information from type annotations associated\nwith the attribute as declared in the Declarative mapped class. These type\nannotations, if used, must be present within a special SQLAlchemy type called\n:class:`.Mapped`, which is a generic type that indicates a specific Python type\nwithin it.\n\nUsing this technique, the example in the previous section can be written\nmore succinctly as below::\n\n    from sqlalchemy import String\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        name: Mapped[str] = mapped_column(String(50))\n        fullname: Mapped[str | None]\n        nickname: Mapped[str | None] = mapped_column(String(30))\n\nThe example above demonstrates that if a class attribute is type-hinted with\n:class:`.Mapped` but doesn\'t have an explicit :func:`_orm.mapped_column` assigned\nto it, SQLAlchemy will automatically create one. Furthermore, details like the\ncolumn\'s datatype and whether it can be null (nullability) are inferred from\nthe :class:`.Mapped` annotation. However, you can always explicitly provide these\narguments to :func:`_orm.mapped_column` to override these automatically-derived\nsettings.\n\nFor complete details on using the ORM Annotated Declarative system, see\n:ref:`orm_declarative_mapped_column` later in this chapter.\n\n.. seealso::\n\n    :ref:`orm_declarative_mapped_column` - complete reference for ORM Annotated Declarative\n\nDataclass features in ``mapped_column()``\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe :func:`_orm.mapped_column` construct integrates with SQLAlchemy\'s\n"native dataclasses" feature, discussed at\n:ref:`orm_declarative_native_dataclasses`.   See that section for current\nbackground on additional directives supported by :func:`_orm.mapped_column`.\n\n\n\n\n.. _orm_declarative_metadata:\n\nAccessing Table and Metadata\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nA declaratively mapped class will always include an attribute called\n``__table__``; when the above configuration using ``__tablename__`` is\ncomplete, the declarative process makes the :class:`_schema.Table`\navailable via the ``__table__`` attribute::\n\n\n    # access the Table\n    user_table = User.__table__\n\nThe above table is ultimately the same one that corresponds to the\n:attr:`_orm.Mapper.local_table` attribute, which we can see through the\n:ref:`runtime inspection system <inspection_toplevel>`::\n\n    from sqlalchemy import inspect\n\n    user_table = inspect(User).local_table\n\nThe :class:`_schema.MetaData` collection associated with both the declarative\n:class:`_orm.registry` as well as the base class is frequently necessary in\norder to run DDL operations such as CREATE, as well as in use with migration\ntools such as Alembic.   This object is available via the ``.metadata``\nattribute of :class:`_orm.registry` as well as the declarative base class.\nBelow, for a small script we may wish to emit a CREATE for all tables against a\nSQLite database::\n\n    engine = create_engine("sqlite://")\n\n    Base.metadata.create_all(engine)\n\n.. _orm_declarative_table_configuration:\n\nDeclarative Table Configuration\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nWhen using Declarative Table configuration with the ``__tablename__``\ndeclarative class attribute, additional arguments to be supplied to the\n:class:`_schema.Table` constructor should be provided using the\n``__table_args__`` declarative class attribute.\n\nThis attribute accommodates both positional as well as keyword\narguments that are normally sent to the\n:class:`_schema.Table` constructor.\nThe attribute can be specified in one of two forms. One is as a\ndictionary::\n\n    class MyClass(Base):\n        __tablename__ = "sometable"\n        __table_args__ = {"mysql_engine": "InnoDB"}\n\nThe other, a tuple, where each argument is positional\n(usually constraints)::\n\n    class MyClass(Base):\n        __tablename__ = "sometable"\n        __table_args__ = (\n            ForeignKeyConstraint(["id"], ["remote_table.id"]),\n            UniqueConstraint("foo"),\n        )\n\nKeyword arguments can be specified with the above form by\nspecifying the last argument as a dictionary::\n\n    class MyClass(Base):\n        __tablename__ = "sometable"\n        __table_args__ = (\n            ForeignKeyConstraint(["id"], ["remote_table.id"]),\n            UniqueConstraint("foo"),\n            {"autoload": True},\n        )\n\nA class may also specify the ``__table_args__`` declarative attribute,\nas well as the ``__tablename__`` attribute, in a dynamic style using the\n:func:`_orm.declared_attr` method decorator.   See\n:ref:`orm_mixins_toplevel` for background.\n\n.. _orm_declarative_table_schema_name:\n\nExplicit Schema Name with Declarative Table\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe schema name for a :class:`_schema.Table` as documented at\n:ref:`schema_table_schema_name` is applied to an individual :class:`_schema.Table`\nusing the :paramref:`_schema.Table.schema` argument.   When using Declarative\ntables, this option is passed like any other to the ``__table_args__``\ndictionary::\n\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class MyClass(Base):\n        __tablename__ = "sometable"\n        __table_args__ = {"schema": "some_schema"}\n\nThe schema name can also be applied to all :class:`_schema.Table` objects\nglobally by using the :paramref:`_schema.MetaData.schema` parameter documented\nat :ref:`schema_metadata_schema_name`.   The :class:`_schema.MetaData` object\nmay be constructed separately and associated with a :class:`_orm.DeclarativeBase`\nsubclass by assigning to the ``metadata`` attribute directly::\n\n    from sqlalchemy import MetaData\n    from sqlalchemy.orm import DeclarativeBase\n\n    metadata_obj = MetaData(schema="some_schema")\n\n\n    class Base(DeclarativeBase):\n        metadata = metadata_obj\n\n\n    class MyClass(Base):\n        # will use "some_schema" by default\n        __tablename__ = "sometable"\n\n.. seealso::\n\n    :ref:`schema_table_schema_name` - in the :ref:`metadata_toplevel` documentation.\n\n.. _orm_declarative_column_options:\n\nSetting Load and Persistence Options for Declarative Mapped Columns\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe :func:`_orm.mapped_column` construct accepts additional ORM-specific\narguments that affect how the generated :class:`_schema.Column` is\nmapped, affecting its load and persistence-time behavior.   Options\nthat are commonly used include:\n\n* **deferred column loading** - The :paramref:`_orm.mapped_column.deferred`\n  boolean establishes the :class:`_schema.Column` using\n  :ref:`deferred column loading <orm_queryguide_column_deferral>` by default.  In the example\n  below, the ``User.bio`` column will not be loaded by default, but only\n  when accessed::\n\n      class User(Base):\n          __tablename__ = "user"\n\n          id: Mapped[int] = mapped_column(primary_key=True)\n          name: Mapped[str]\n          bio: Mapped[str] = mapped_column(Text, deferred=True)\n\n  .. seealso::\n\n     :ref:`orm_queryguide_column_deferral` - full description of deferred column loading\n\n* **active history** - The :paramref:`_orm.mapped_column.active_history`\n  ensures that upon change of value for the attribute, the previous value\n  will have been loaded and made part of the :attr:`.AttributeState.history`\n  collection when inspecting the history of the attribute.   This may incur\n  additional SQL statements::\n\n    class User(Base):\n        __tablename__ = "user"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        important_identifier: Mapped[str] = mapped_column(active_history=True)\n\nSee the docstring for :func:`_orm.mapped_column` for a list of supported\nparameters.\n\n.. seealso::\n\n    :ref:`orm_imperative_table_column_options` - describes using\n    :func:`_orm.column_property` and :func:`_orm.deferred` for use with\n    Imperative Table configuration\n\n.. _mapper_column_distinct_names:\n\n.. _orm_declarative_table_column_naming:\n\nNaming Declarative Mapped Columns Explicitly\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nAll of the examples thus far feature the :func:`_orm.mapped_column` construct\nlinked to an ORM mapped attribute, where the Python attribute name given\nto the :func:`_orm.mapped_column` is also that of the column as we see in\nCREATE TABLE statements as well as queries.   The name for a column as\nexpressed in SQL may be indicated by passing the string positional argument\n:paramref:`_orm.mapped_column.__name` as the first positional argument.\nIn the example below, the ``User`` class is mapped with alternate names\ngiven to the columns themselves::\n\n    class User(Base):\n        __tablename__ = "user"\n\n        id: Mapped[int] = mapped_column("user_id", primary_key=True)\n        name: Mapped[str] = mapped_column("user_name")\n\nWhere above ``User.id`` resolves to a column named ``user_id``\nand ``User.name`` resolves to a column named ``user_name``.  We\nmay write a :func:`_sql.select` statement using our Python attribute names\nand will see the SQL names generated:\n\n.. sourcecode:: pycon+sql\n\n    >>> from sqlalchemy import select\n    >>> print(select(User.id, User.name).where(User.name == "x"))\n    {printsql}SELECT "user".user_id, "user".user_name\n    FROM "user"\n    WHERE "user".user_name = :user_name_1\n\n\n.. seealso::\n\n    :ref:`orm_imperative_table_column_naming` - applies to Imperative Table\n\n.. _orm_declarative_table_adding_columns:\n\nAppending additional columns to an existing Declarative mapped class\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nA declarative table configuration allows the addition of new\n:class:`_schema.Column` objects to an existing mapping after the :class:`.Table`\nmetadata has already been generated.\n\nFor a declarative class that is declared using a declarative base class,\nthe underlying metaclass :class:`.DeclarativeMeta` includes a ``__setattr__()``\nmethod that will intercept additional :func:`_orm.mapped_column` or Core\n:class:`.Column` objects and\nadd them to both the :class:`.Table` using :meth:`.Table.append_column`\nas well as to the existing :class:`.Mapper` using :meth:`.Mapper.add_property`::\n\n    MyClass.some_new_column = mapped_column(String)\n\nUsing core :class:`_schema.Column`::\n\n    MyClass.some_new_column = Column(String)\n\nAll arguments are supported including an alternate name, such as\n``MyClass.some_new_column = mapped_column("some_name", String)``.  However,\nthe SQL type must be passed to the :func:`_orm.mapped_column` or\n:class:`_schema.Column` object explicitly, as in the above examples where\nthe :class:`_sqltypes.String` type is passed.  There\'s no capability for\nthe :class:`_orm.Mapped` annotation type to take part in the operation.\n\nAdditional :class:`_schema.Column` objects may also be added to a mapping\nin the specific circumstance of using single table inheritance, where\nadditional columns are present on mapped subclasses that have\nno :class:`.Table` of their own.  This is illustrated in the section\n:ref:`single_inheritance`.\n\n.. seealso::\n\n   :ref:`orm_declarative_table_adding_relationship` - similar examples for :func:`_orm.relationship`\n\n.. note:: Assignment of mapped\n    properties to an already mapped class will only\n    function correctly if the "declarative base" class is used, meaning\n    the user-defined subclass of :class:`_orm.DeclarativeBase` or the\n    dynamically generated class returned by :func:`_orm.declarative_base`\n    or :meth:`_orm.registry.generate_base`.   This "base" class includes\n    a Python metaclass which implements a special ``__setattr__()`` method\n    that intercepts these operations.\n\n    Runtime assignment of class-mapped attributes to a mapped class will **not** work\n    if the class is mapped using decorators like :meth:`_orm.registry.mapped`\n    or imperative functions like :meth:`_orm.registry.map_imperatively`.\n\n\n.. _orm_declarative_mapped_column:\n\nORM Annotated Declarative - Complete Guide\n------------------------------------------\n\nThe :func:`_orm.mapped_column` construct is capable of deriving its\ncolumn-configuration information from :pep:`484` type annotations associated\nwith the attribute as declared in the Declarative mapped class.   These type\nannotations, if used,  must be present within a special SQLAlchemy type called\n:class:`_orm.Mapped`, which is a generic_ type that then indicates a specific\nPython type within it.\n\nUsing this technique, the ``User`` example from previous sections may be\nwritten as below::\n\n    from sqlalchemy import String\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        name: Mapped[str] = mapped_column(String(50))\n        fullname: Mapped[str | None]\n        nickname: Mapped[str | None] = mapped_column(String(30))\n\nAbove, when Declarative processes each class attribute, each\n:func:`_orm.mapped_column` will derive additional arguments from the\ncorresponding :class:`_orm.Mapped` type annotation on the left side, if\npresent.   Additionally, Declarative will generate an empty\n:func:`_orm.mapped_column` directive implicitly, whenever a\n:class:`_orm.Mapped` type annotation is encountered that does not have\na value assigned to the attribute (this form is inspired by the similar\nstyle used in Python dataclasses_); this :func:`_orm.mapped_column` construct\nproceeds to derive its configuration from the :class:`_orm.Mapped`\nannotation present.\n\n.. _orm_declarative_mapped_column_nullability:\n\n``mapped_column()`` derives the datatype and nullability from the ``Mapped`` annotation\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe two qualities that :func:`_orm.mapped_column` derives from the\n:class:`_orm.Mapped` annotation are:\n\n* **datatype** - the Python type given inside :class:`_orm.Mapped`, as contained\n  within the ``typing.Optional`` construct if present, is associated with a\n  :class:`_sqltypes.TypeEngine` subclass such as :class:`.Integer`, :class:`.String`,\n  :class:`.DateTime`, or :class:`.Uuid`, to name a few common types.\n\n  The datatype is determined based on a dictionary of Python type to\n  SQLAlchemy datatype.   This dictionary is completely customizable,\n  as detailed in the next section :ref:`orm_declarative_mapped_column_type_map`.\n  The default type map is implemented as in the code example below::\n\n      from typing import Any\n      from typing import Dict\n      from typing import Type\n\n      import datetime\n      import decimal\n      import uuid\n\n      from sqlalchemy import types\n\n      # default type mapping, deriving the type for mapped_column()\n      # from a Mapped[] annotation\n      type_map: Dict[Type[Any], TypeEngine[Any]] = {\n          bool: types.Boolean(),\n          bytes: types.LargeBinary(),\n          datetime.date: types.Date(),\n          datetime.datetime: types.DateTime(),\n          datetime.time: types.Time(),\n          datetime.timedelta: types.Interval(),\n          decimal.Decimal: types.Numeric(),\n          float: types.Float(),\n          int: types.Integer(),\n          str: types.String(),\n          uuid.UUID: types.Uuid(),\n      }\n\n  If the :func:`_orm.mapped_column` construct indicates an explicit type\n  as passed to the :paramref:`_orm.mapped_column.__type` argument, then\n  the given Python type is disregarded.\n\n* **nullability** - The :func:`_orm.mapped_column` construct will indicate\n  its :class:`_schema.Column` as ``NULL`` or ``NOT NULL`` first and foremost by\n  the presence of the :paramref:`_orm.mapped_column.nullable` parameter, passed\n  either as ``True`` or ``False``. Additionally , if the\n  :paramref:`_orm.mapped_column.primary_key` parameter is present and set to\n  ``True``, that will also imply that the column should be ``NOT NULL``.\n\n  In the absence of **both** of these parameters, the presence of\n  ``typing.Optional[]`` (or its equivalent) within the :class:`_orm.Mapped`\n  type annotation will be used to determine nullability, where\n  ``typing.Optional[]`` means ``NULL``, and the absence of\n  ``typing.Optional[]`` means ``NOT NULL``. If there is no ``Mapped[]``\n  annotation present at all, and there is no\n  :paramref:`_orm.mapped_column.nullable` or\n  :paramref:`_orm.mapped_column.primary_key` parameter, then SQLAlchemy\'s usual\n  default for :class:`_schema.Column` of ``NULL`` is used.\n\n  In the example below, the ``id`` and ``data`` columns will be ``NOT NULL``,\n  and the ``additional_info`` column will be ``NULL``::\n\n      from typing import Optional\n\n      from sqlalchemy.orm import DeclarativeBase\n      from sqlalchemy.orm import Mapped\n      from sqlalchemy.orm import mapped_column\n\n\n      class Base(DeclarativeBase):\n          pass\n\n\n      class SomeClass(Base):\n          __tablename__ = "some_table"\n\n          # primary_key=True, therefore will be NOT NULL\n          id: Mapped[int] = mapped_column(primary_key=True)\n\n          # not Optional[], therefore will be NOT NULL\n          data: Mapped[str]\n\n          # Optional[], therefore will be NULL\n          additional_info: Mapped[Optional[str]]\n\n  It is also perfectly valid to have a :func:`_orm.mapped_column` whose\n  nullability is **different** from what would be implied by the annotation.\n  For example, an ORM mapped attribute may be annotated as allowing ``None``\n  within Python code that works with the object as it is first being created\n  and populated, however the value will ultimately be written to a database\n  column that is ``NOT NULL``.   The :paramref:`_orm.mapped_column.nullable`\n  parameter, when present, will always take precedence::\n\n      class SomeClass(Base):\n          # ...\n\n          # will be String() NOT NULL, but can be None in Python\n          data: Mapped[Optional[str]] = mapped_column(nullable=False)\n\n  Similarly, a non-None attribute that\'s written to a database column that\n  for whatever reason needs to be NULL at the schema level,\n  :paramref:`_orm.mapped_column.nullable` may be set to ``True``::\n\n      class SomeClass(Base):\n          # ...\n\n          # will be String() NULL, but type checker will not expect\n          # the attribute to be None\n          data: Mapped[str] = mapped_column(nullable=True)\n\n.. _orm_declarative_mapped_column_type_map:\n\nCustomizing the Type Map\n^^^^^^^^^^^^^^^^^^^^^^^^\n\n\nThe mapping of Python types to SQLAlchemy :class:`_types.TypeEngine` types\ndescribed in the previous section defaults to a hardcoded dictionary\npresent in the ``sqlalchemy.sql.sqltypes`` module.  However, the :class:`_orm.registry`\nobject that coordinates the Declarative mapping process will first consult\na local, user defined dictionary of types which may be passed\nas the :paramref:`_orm.registry.type_annotation_map` parameter when\nconstructing the :class:`_orm.registry`, which may be associated with\nthe :class:`_orm.DeclarativeBase` superclass when first used.\n\nAs an example, if we wish to make use of the :class:`_sqltypes.BIGINT` datatype\nfor ``int``, the :class:`_sqltypes.TIMESTAMP` datatype with ``timezone=True``\nfor ``datetime.datetime``, and then for ``str`` types we\'d like to see\n:class:`_sqltypes.NVARCHAR` when Microsoft SQL Server is used and\n``VARCHAR(255)`` when MySQL is used, the registry and Declarative base could be\nconfigured as::\n\n    import datetime\n\n    from sqlalchemy import BIGINT, NVARCHAR, String, TIMESTAMP\n    from sqlalchemy.orm import DeclarativeBase, Mapped, mapped_column\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {\n            int: BIGINT,\n            datetime.datetime: TIMESTAMP(timezone=True),\n            # set up variants for str/String()\n            str: String()\n            # use NVARCHAR for MSSQL\n            .with_variant(NVARCHAR, "mssql")\n            # add a default VARCHAR length for MySQL\n            .with_variant(VARCHAR(255), "mysql"),\n        }\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        date: Mapped[datetime.datetime]\n        status: Mapped[str]\n\nBelow illustrates the CREATE TABLE statement generated for the above mapping,\nfirst on the Microsoft SQL Server backend, illustrating the ``NVARCHAR`` datatype:\n\n.. sourcecode:: pycon+sql\n\n    >>> from sqlalchemy.schema import CreateTable\n    >>> from sqlalchemy.dialects import mssql, mysql, postgresql\n    >>> print(CreateTable(SomeClass.__table__).compile(dialect=mssql.dialect()))\n    {printsql}CREATE TABLE some_table (\n      id BIGINT NOT NULL IDENTITY,\n      date TIMESTAMP NOT NULL,\n      status NVARCHAR(max) NOT NULL,\n      PRIMARY KEY (id)\n    )\n\nOn MySQL, we get a VARCHAR column with an explcit length (required by\nMySQL):\n\n.. sourcecode:: pycon+sql\n\n    >>> print(CreateTable(SomeClass.__table__).compile(dialect=mysql.dialect()))\n    {printsql}CREATE TABLE some_table (\n        id BIGINT NOT NULL AUTO_INCREMENT,\n        date TIMESTAMP NOT NULL,\n        status VARCHAR(255) NOT NULL,\n        PRIMARY KEY (id)\n    )\n\n\nThen on the PostgreSQL backend, illustrating ``TIMESTAMP WITH TIME ZONE``:\n\n.. sourcecode:: pycon+sql\n\n    >>> print(CreateTable(SomeClass.__table__).compile(dialect=postgresql.dialect()))\n    {printsql}CREATE TABLE some_table (\n      id BIGSERIAL NOT NULL,\n      date TIMESTAMP WITH TIME ZONE NOT NULL,\n      status VARCHAR NOT NULL,\n      PRIMARY KEY (id)\n    )\n\nBy making use of methods such as :meth:`.TypeEngine.with_variant`, we\'re able\nto build up a type map that\'s customized to what we need for different backends,\nwhile still being able to use succinct annotation-only :func:`_orm.mapped_column`\nconfigurations.  There are two more levels of Python-type configurability\navailable beyond this, described in the next two sections.\n\n.. _orm_declarative_type_map_union_types:\n\nUnion types inside the Type Map\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n\n.. versionchanged:: 2.0.37 The features described in this section have been\n   repaired and enhanced to work consistently.  Prior to this change, union\n   types were supported in ``type_annotation_map``, however the feature\n   exhibited inconsistent behaviors between union syntaxes as well as in how\n   ``None`` was handled.   Please ensure SQLAlchemy is up to date before\n   attempting to use the features described in this section.\n\nSQLAlchemy supports mapping union types inside the ``type_annotation_map`` to\nallow mapping database types that can support multiple Python types, such as\n:class:`_types.JSON` or :class:`_postgresql.JSONB`::\n\n    from typing import Union, Optional\n    from sqlalchemy import JSON\n    from sqlalchemy.dialects import postgresql\n    from sqlalchemy.orm import DeclarativeBase, Mapped, mapped_column\n    from sqlalchemy.schema import CreateTable\n\n    # new style Union using a pipe operator\n    json_list = list[int] | list[str]\n\n    # old style Union using Union explicitly\n    json_scalar = Union[float, str, bool]\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {\n            json_list: postgresql.JSONB,\n            json_scalar: JSON,\n        }\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        list_col: Mapped[list[str] | list[int]]\n\n        # uses JSON\n        scalar_col: Mapped[json_scalar]\n\n        # uses JSON and is also nullable=True\n        scalar_col_nullable: Mapped[json_scalar | None]\n\n        # these forms all use JSON as well due to the json_scalar entry\n        scalar_col_newstyle: Mapped[float | str | bool]\n        scalar_col_oldstyle: Mapped[Union[float, str, bool]]\n        scalar_col_mixedstyle: Mapped[Optional[float | str | bool]]\n\nThe above example maps the union of ``list[int]`` and ``list[str]`` to the Postgresql\n:class:`_postgresql.JSONB` datatype, while naming a union of ``float,\nstr, bool`` will match to the :class:`_types.JSON` datatype.   An equivalent\nunion, stated in the :class:`_orm.Mapped` construct, will match into the\ncorresponding entry in the type map.\n\nThe matching of a union type is based on the contents of the union regardless\nof how the individual types are named, and additionally excluding the use of\nthe ``None`` type.  That is, ``json_scalar`` will also match to ``str | bool |\nfloat | None``.   It will **not** match to a union that is a subset or superset\nof this union; that is, ``str | bool`` would not match, nor would ``str | bool\n| float | int``.  The individual contents of the union excluding ``None`` must\nbe an exact match.\n\nThe ``None`` value is never significant as far as matching\nfrom ``type_annotation_map`` to :class:`_orm.Mapped`, however is significant\nas an indicator for nullability of the :class:`_schema.Column`. When ``None`` is present in the\nunion either as it is placed in the :class:`_orm.Mapped` construct.  When\npresent in :class:`_orm.Mapped`, it indicates the :class:`_schema.Column`\nwould be nullable, in the absense of more specific indicators.  This logic works\nin the same way as indicating an ``Optional`` type as described at\n:ref:`orm_declarative_mapped_column_nullability`.\n\nThe CREATE TABLE statement for the above mapping will look as below:\n\n.. sourcecode:: pycon+sql\n\n    >>> print(CreateTable(SomeClass.__table__).compile(dialect=postgresql.dialect()))\n    {printsql}CREATE TABLE some_table (\n        id SERIAL NOT NULL,\n        list_col JSONB NOT NULL,\n        scalar_col JSON,\n        scalar_col_not_null JSON NOT NULL,\n        PRIMARY KEY (id)\n    )\n\nWhile union types use a "loose" matching approach that matches on any equivalent\nset of subtypes, Python typing also features a way to create "type aliases"\nthat are treated as distinct types that are non-equivalent to another type that\nincludes the same composition.   Integration of these types with ``type_annotation_map``\nis described in the next section, :ref:`orm_declarative_type_map_pep695_types`.\n\n.. _orm_declarative_type_map_pep695_types:\n\nSupport for Type Alias Types (defined by PEP 695) and NewType\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nIn contrast to the typing lookup described in\n:ref:`orm_declarative_type_map_union_types`, Python typing also includes two\nways to create a composed type in a more formal way, using ``typing.NewType`` as\nwell as the ``type`` keyword introduced in :pep:`695`.  These types behave\ndifferently from ordinary type aliases (i.e. assigning a type to a variable\nname), and this difference is honored in how SQLAlchemy resolves these\ntypes from the type map.\n\n.. versionchanged:: 2.0.44  Support for resolving pep-695 types without a\n   corresponding entry in :paramref:`_orm.registry.type_annotation_map`\n   has been expanded, reversing part of the restrictions introduced in 2.0.37.\n   Please ensure SQLAlchemy is up to date before attempting to use the features\n   described in this section.\n\n.. versionchanged:: 2.0.37  The behaviors described in this section for ``typing.NewType``\n   as well as :pep:`695` ``type`` were formalized to disallow these types\n   from being implicitly resolvable without entries in\n   :paramref:`_orm.registry.type_annotation_map`, with deprecation warnings\n   emitted when these patterns were detected. As of 2.0.44, a pep-695 type\n   is implicitly resolvable as long as the type it resolves to is present\n   in the type map.\n\nThe typing module allows the creation of "new types" using ``typing.NewType``::\n\n    from typing import NewType\n\n    nstr30 = NewType("nstr30", str)\n    nstr50 = NewType("nstr50", str)\n\nThe ``NewType`` construct creates types that are analogous to creating a\nsubclass of the referenced type.\n\nAdditionally, :pep:`695` introduced in Python 3.12 provides a new ``type``\nkeyword for creating type aliases with greater separation of concerns from plain\naliases, as well as succinct support for generics without requiring explicit\nuse of ``TypeVar`` or ``Generic`` elements. Types created by the ``type``\nkeyword are represented at runtime by ``typing.TypeAliasType``::\n\n    type SmallInt = int\n    type BigInt = int\n    type JsonScalar = str | float | bool | None\n\nBoth ``NewType`` and pep-695 ``type`` constructs may be used as arguments\nwithin :class:`_orm.Mapped` annotations, where they will be resolved to Python\ntypes using the following rules:\n\n* When a ``TypeAliasType`` or ``NewType`` object is present in the\n  :paramref:`_orm.registry.type_annotation_map`, it will resolve directly::\n\n    from typing import NewType\n    from sqlalchemy import String, BigInteger\n\n    nstr30 = NewType("nstr30", str)\n    type BigInt = int\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {nstr30: String(30), BigInt: BigInteger}\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        # BigInt is in the type_annotation_map.  So this\n        # will resolve to sqlalchemy.BigInteger\n        id: Mapped[BigInt] = mapped_column(primary_key=True)\n\n        # nstr30 is in the type_annotation_map.  So this\n        # will resolve to sqlalchemy.String(30)\n        data: Mapped[nstr30]\n\n* A ``TypeAliasType`` that refers **directly** to another type present\n  in the type map will resolve against that type::\n\n    type PlainInt = int\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        # PlainInt refers to int, which is one of the default types\n        # already in the type_annotation_map.   So this\n        # will resolve to sqlalchemy.Integer via the int type\n        id: Mapped[PlainInt] = mapped_column(primary_key=True)\n\n* A ``TypeAliasType`` that refers to another pep-695 ``TypeAliasType``\n  not present in the type map will not resolve (emits a deprecation\n  warning in 2.0), as this would involve a recursive lookup::\n\n    type PlainInt = int\n    type AlsoAnInt = PlainInt\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        # AlsoAnInt refers to PlainInt, which is not in the type_annotation_map.\n        # This will emit a deprecation warning in 2.0, will fail in 2.1\n        id: Mapped[AlsoAnInt] = mapped_column(primary_key=True)\n\n* A ``NewType`` that is not in the type map will not resolve (emits a\n  deprecation warning in 2.0). Since ``NewType`` is analogous to creating an\n  entirely new type with different semantics than the type it extends, these\n  must be explicitly matched in the type map::\n\n\n    from typing import NewType\n\n    nstr30 = NewType("nstr30", str)\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        # a NewType is a new kind of type, so this will emit a deprecation\n        # warning in 2.0 and fail in 2.1, as nstr30 is not present\n        # in the type_annotation_map.\n        id: Mapped[nstr30] = mapped_column(primary_key=True)\n\nFor all of the above examples, any type that is combined with ``Optional[]``\nor ``| None`` will consider this to indicate the column is nullable, if\nno other directive for nullability is present.\n\n.. seealso::\n\n    :ref:`orm_declarative_mapped_column_generic_pep593`\n\n\n.. _orm_declarative_mapped_column_type_map_pep593:\n\nMapping Multiple Type Configurations to Python Types with pep-593 ``Annotated``\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n\nAs individual Python types may be associated with :class:`_types.TypeEngine`\nconfigurations of any variety by using the :paramref:`_orm.registry.type_annotation_map`\nparameter, an additional\ncapability is the ability to associate a single Python type with different\nvariants of a SQL type based on additional type qualifiers.  One typical\nexample of this is mapping the Python ``str`` datatype to ``VARCHAR``\nSQL types of different lengths.  Another is mapping different varieties of\n``decimal.Decimal`` to differently sized ``NUMERIC`` columns.\n\nPython\'s typing system provides a great way to add additional metadata to a\nPython type which is by using the :pep:`593` ``Annotated`` generic type, which\nallows additional information to be bundled along with a Python type. The\n:func:`_orm.mapped_column` construct will correctly interpret an ``Annotated``\nobject by identity when resolving it in the\n:paramref:`_orm.registry.type_annotation_map`, as in the example below where we\ndeclare two variants of :class:`.String` and :class:`.Numeric`::\n\n    from decimal import Decimal\n\n    from typing_extensions import Annotated\n\n    from sqlalchemy import Numeric\n    from sqlalchemy import String\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import registry\n\n    str_30 = Annotated[str, 30]\n    str_50 = Annotated[str, 50]\n    num_12_4 = Annotated[Decimal, 12]\n    num_6_2 = Annotated[Decimal, 6]\n\n\n    class Base(DeclarativeBase):\n        registry = registry(\n            type_annotation_map={\n                str_30: String(30),\n                str_50: String(50),\n                num_12_4: Numeric(12, 4),\n                num_6_2: Numeric(6, 2),\n            }\n        )\n\nThe Python type passed to the ``Annotated`` container, in the above example the\n``str`` and ``Decimal`` types, is important only for the benefit of typing\ntools; as far as the :func:`_orm.mapped_column` construct is concerned, it will only need\nperform a lookup of each type object in the\n:paramref:`_orm.registry.type_annotation_map` dictionary without actually\nlooking inside of the ``Annotated`` object, at least in this particular\ncontext. Similarly, the arguments passed to ``Annotated`` beyond the underlying\nPython type itself are also not important, it\'s only that at least one argument\nmust be present for the ``Annotated`` construct to be valid. We can then use\nthese augmented types directly in our mapping where they will be matched to the\nmore specific type constructions, as in the following example::\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        short_name: Mapped[str_30] = mapped_column(primary_key=True)\n        long_name: Mapped[str_50]\n        num_value: Mapped[num_12_4]\n        short_num_value: Mapped[num_6_2]\n\na CREATE TABLE for the above mapping will illustrate the different variants\nof ``VARCHAR`` and ``NUMERIC`` we\'ve configured, and looks like:\n\n.. sourcecode:: pycon+sql\n\n    >>> from sqlalchemy.schema import CreateTable\n    >>> print(CreateTable(SomeClass.__table__))\n    {printsql}CREATE TABLE some_table (\n      short_name VARCHAR(30) NOT NULL,\n      long_name VARCHAR(50) NOT NULL,\n      num_value NUMERIC(12, 4) NOT NULL,\n      short_num_value NUMERIC(6, 2) NOT NULL,\n      PRIMARY KEY (short_name)\n    )\n\nWhile variety in linking ``Annotated`` types to different SQL types grants\nus a wide degree of flexibility, the next section illustrates a second\nway in which ``Annotated`` may be used with Declarative that is even\nmore open ended.\n\n\n.. note::  While a ``typing.TypeAliasType`` can be assigned to unions, like in the\n   case of ``JsonScalar`` defined above, it has a different behavior than normal\n   unions defined without the ``type ...`` syntax.\n   The following mapping includes unions that are compatible with ``JsonScalar``,\n   but they will not be recognized::\n\n        class SomeClass(TABase):\n            __tablename__ = "some_table"\n\n            id: Mapped[int] = mapped_column(primary_key=True)\n            col_a: Mapped[str | float | bool | None]\n            col_b: Mapped[str | float | bool]\n\n  This raises an error since the union types used by ``col_a`` or ``col_b``,\n  are not found in ``TABase`` type map and ``JsonScalar`` must be referenced\n  directly.\n\n.. _orm_declarative_mapped_column_pep593:\n\nMapping Whole Column Declarations to Python Types with pep-593 ``Annotated``\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n\nThe previous section illustrated using :pep:`593` ``Annotated`` type\ninstances as keys within the :paramref:`_orm.registry.type_annotation_map`\ndictionary.  In this form, the :func:`_orm.mapped_column` construct does not\nactually look inside the ``Annotated`` object itself, it\'s instead\nused only as a dictionary key.  However, Declarative also has the ability to extract\nan entire pre-established :func:`_orm.mapped_column` construct from\nan ``Annotated`` object directly.  Using this form, we can define not only\ndifferent varieties of SQL datatypes linked to Python types without using\nthe :paramref:`_orm.registry.type_annotation_map` dictionary, we can also\nset up any number of arguments such as nullability, column defaults,\nand constraints in a reusable fashion.\n\nA set of ORM models will usually have some kind of primary\nkey style that is common to all mapped classes.   There also may be\ncommon column configurations such as timestamps with defaults and other fields of\npre-established sizes and configurations.   We can compose these configurations\ninto :func:`_orm.mapped_column` instances that we then bundle directly into\ninstances of ``Annotated``, which are then re-used in any number of class\ndeclarations.  Declarative will unpack an ``Annotated`` object\nwhen provided in this manner, skipping over any other directives that don\'t\napply to SQLAlchemy and searching only for SQLAlchemy ORM constructs.\n\nThe example below illustrates a variety of pre-configured field types used\nin this way, where we define ``intpk`` that represents an :class:`.Integer` primary\nkey column, ``timestamp`` that represents a :class:`.DateTime` type\nwhich will use ``CURRENT_TIMESTAMP`` as a DDL level column default,\nand ``required_name`` which is a :class:`.String` of length 30 that\'s\n``NOT NULL``::\n\n    import datetime\n\n    from typing_extensions import Annotated\n\n    from sqlalchemy import func\n    from sqlalchemy import String\n    from sqlalchemy.orm import mapped_column\n\n\n    intpk = Annotated[int, mapped_column(primary_key=True)]\n    timestamp = Annotated[\n        datetime.datetime,\n        mapped_column(nullable=False, server_default=func.CURRENT_TIMESTAMP()),\n    ]\n    required_name = Annotated[str, mapped_column(String(30), nullable=False)]\n\nThe above ``Annotated`` objects can then be used directly within\n:class:`_orm.Mapped`, where the pre-configured :func:`_orm.mapped_column`\nconstructs will be extracted and copied to a new instance that will be\nspecific to each attribute::\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        id: Mapped[intpk]\n        name: Mapped[required_name]\n        created_at: Mapped[timestamp]\n\n``CREATE TABLE`` for our above mapping looks like:\n\n.. sourcecode:: pycon+sql\n\n    >>> from sqlalchemy.schema import CreateTable\n    >>> print(CreateTable(SomeClass.__table__))\n    {printsql}CREATE TABLE some_table (\n      id INTEGER NOT NULL,\n      name VARCHAR(30) NOT NULL,\n      created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,\n      PRIMARY KEY (id)\n    )\n\nWhen using ``Annotated`` types in this way, the configuration of the type\nmay also be affected on a per-attribute basis.  For the types in the above\nexample that feature explicit use of :paramref:`_orm.mapped_column.nullable`,\nwe can apply the ``Optional[]`` generic modifier to any of our types so that\nthe field is optional or not at the Python level, which will be independent\nof the ``NULL`` / ``NOT NULL`` setting that takes place in the database::\n\n    from typing_extensions import Annotated\n\n    import datetime\n    from typing import Optional\n\n    from sqlalchemy.orm import DeclarativeBase\n\n    timestamp = Annotated[\n        datetime.datetime,\n        mapped_column(nullable=False),\n    ]\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class SomeClass(Base):\n        # ...\n\n        # pep-484 type will be Optional, but column will be\n        # NOT NULL\n        created_at: Mapped[Optional[timestamp]]\n\nThe :func:`_orm.mapped_column` construct is also reconciled with an explicitly\npassed :func:`_orm.mapped_column` construct, whose arguments will take precedence\nover those of the ``Annotated`` construct.   Below we add a :class:`.ForeignKey`\nconstraint to our integer primary key and also use an alternate server\ndefault for the ``created_at`` column::\n\n    import datetime\n\n    from typing_extensions import Annotated\n\n    from sqlalchemy import ForeignKey\n    from sqlalchemy import func\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.schema import CreateTable\n\n    intpk = Annotated[int, mapped_column(primary_key=True)]\n    timestamp = Annotated[\n        datetime.datetime,\n        mapped_column(nullable=False, server_default=func.CURRENT_TIMESTAMP()),\n    ]\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class Parent(Base):\n        __tablename__ = "parent"\n\n        id: Mapped[intpk]\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        # add ForeignKey to mapped_column(Integer, primary_key=True)\n        id: Mapped[intpk] = mapped_column(ForeignKey("parent.id"))\n\n        # change server default from CURRENT_TIMESTAMP to UTC_TIMESTAMP\n        created_at: Mapped[timestamp] = mapped_column(server_default=func.UTC_TIMESTAMP())\n\nThe CREATE TABLE statement illustrates these per-attribute settings,\nadding a ``FOREIGN KEY`` constraint as well as substituting\n``UTC_TIMESTAMP`` for ``CURRENT_TIMESTAMP``:\n\n.. sourcecode:: pycon+sql\n\n    >>> from sqlalchemy.schema import CreateTable\n    >>> print(CreateTable(SomeClass.__table__))\n    {printsql}CREATE TABLE some_table (\n      id INTEGER NOT NULL,\n      created_at DATETIME DEFAULT UTC_TIMESTAMP() NOT NULL,\n      PRIMARY KEY (id),\n      FOREIGN KEY(id) REFERENCES parent (id)\n    )\n\n.. note:: The feature of :func:`_orm.mapped_column` just described, where\n   a fully constructed set of column arguments may be indicated using\n   :pep:`593` ``Annotated`` objects that contain a "template"\n   :func:`_orm.mapped_column` object to be copied into the attribute, is\n   currently not implemented for other ORM constructs such as\n   :func:`_orm.relationship` and :func:`_orm.composite`.   While this functionality\n   is in theory possible, for the moment attempting to use ``Annotated``\n   to indicate further arguments for :func:`_orm.relationship` and similar\n   will raise a ``NotImplementedError`` exception at runtime, but\n   may be implemented in future releases.\n\n\n.. _orm_declarative_mapped_column_generic_pep593:\n\nMapping Whole Column Declarations to Generic Python Types\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nUsing the ``Annotated`` approach from the previous section, we may also\ncreate a generic version that will apply particular :func:`_orm.mapped_column`\nelements across many different Python/SQL types in one step.  Below\nillustrates a plain alias against a generic form of ``Annotated`` that\nwill apply the ``primary_key=True`` option to any column to which it\'s applied::\n\n    from typing import Annotated\n    from typing import TypeVar\n\n    T = TypeVar("T", bound=Any)\n\n    PrimaryKey = Annotated[T, mapped_column(primary_key=True)]\n\nThe above type can now apply ``primary_key=True`` to any Python type::\n\n    import uuid\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class A(Base):\n        __tablename__ = "a"\n\n        # will create an Integer primary key\n        id: Mapped[PrimaryKey[int]]\n\n\n    class B(Base):\n        __tablename__ = "b"\n\n        # will create a UUID primary key\n        id: Mapped[PrimaryKey[uuid.UUID]]\n\nFor a more shorthand approach, we may opt to use the :pep:`695` ``type``\nkeyword (Python 3.12 or above) which allows us to skip having to define a\n``TypeVar`` variable::\n\n    type PrimaryKey[T] = Annotated[T, mapped_column(primary_key=True)]\n\n.. versionadded:: 2.0.44 Generic :pep:`695` types may be used with :pep:`593`\n    ``Annotated`` elements to create generic types that automatically\n    deliver :func:`_orm.mapped_column` arguments.\n\n\n.. _orm_declarative_mapped_column_enums:\n\nUsing Python ``Enum`` or pep-586 ``Literal`` types in the type map\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n\n.. versionadded:: 2.0.0b4 - Added ``Enum`` support\n\n.. versionadded:: 2.0.1 - Added ``Literal`` support\n\nUser-defined Python types which derive from the Python built-in ``enum.Enum``\nas well as the ``typing.Literal``\nclass are automatically linked to the SQLAlchemy :class:`.Enum` datatype\nwhen used in an ORM declarative mapping.  The example below uses\na custom ``enum.Enum`` within the ``Mapped[]`` constructor::\n\n    import enum\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class Status(enum.Enum):\n        PENDING = "pending"\n        RECEIVED = "received"\n        COMPLETED = "completed"\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        status: Mapped[Status]\n\nIn the above example, the mapped attribute ``SomeClass.status`` will be\nlinked to a :class:`.Column` with the datatype of ``Enum(Status)``.\nWe can see this for example in the CREATE TABLE output for the PostgreSQL\ndatabase:\n\n.. sourcecode:: sql\n\n  CREATE TYPE status AS ENUM (\'PENDING\', \'RECEIVED\', \'COMPLETED\')\n\n  CREATE TABLE some_table (\n    id SERIAL NOT NULL,\n    status status NOT NULL,\n    PRIMARY KEY (id)\n  )\n\nIn a similar way, ``typing.Literal`` may be used instead, using\na ``typing.Literal`` that consists of all strings::\n\n\n    from typing import Literal\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    Status = Literal["pending", "received", "completed"]\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        status: Mapped[Status]\n\nThe entries used in :paramref:`_orm.registry.type_annotation_map` link the base\n``enum.Enum`` Python type as well as the ``typing.Literal`` type to the\nSQLAlchemy :class:`.Enum` SQL type, using a special form which indicates to the\n:class:`.Enum` datatype that it should automatically configure itself against\nan arbitrary enumerated type. This configuration, which is implicit by default,\nwould be indicated explicitly as::\n\n    import enum\n    import typing\n\n    import sqlalchemy\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {\n            enum.Enum: sqlalchemy.Enum(enum.Enum),\n            typing.Literal: sqlalchemy.Enum(enum.Enum),\n        }\n\nThe resolution logic within Declarative is able to resolve subclasses\nof ``enum.Enum`` as well as instances of ``typing.Literal`` to match the\n``enum.Enum`` or ``typing.Literal`` entry in the\n:paramref:`_orm.registry.type_annotation_map` dictionary.  The :class:`.Enum`\nSQL type then knows how to produce a configured version of itself with the\nappropriate settings, including default string length.   If a ``typing.Literal``\nthat does not consist of only string values is passed, an informative\nerror is raised.\n\n``typing.TypeAliasType`` can also be used to create enums, by assigning them\nto a ``typing.Literal`` of strings::\n\n    from typing import Literal\n\n    type Status = Literal["on", "off", "unknown"]\n\nSince this is a ``typing.TypeAliasType``, it represents a unique type object,\nso it must be placed in the ``type_annotation_map`` for it to be looked up\nsuccessfully, keyed to the :class:`.Enum` type as follows::\n\n    import enum\n    import sqlalchemy\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {Status: sqlalchemy.Enum(enum.Enum)}\n\nSince SQLAlchemy supports mapping different ``typing.TypeAliasType``\nobjects that are otherwise structurally equivalent individually,\nthese must be present in ``type_annotation_map`` to avoid ambiguity.\n\nNative Enums and Naming\n~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe :paramref:`.sqltypes.Enum.native_enum` parameter refers to if the\n:class:`.sqltypes.Enum` datatype should create a so-called "native"\nenum, which on MySQL/MariaDB is the ``ENUM`` datatype and on PostgreSQL is\na new ``TYPE`` object created by ``CREATE TYPE``, or a "non-native" enum,\nwhich means that ``VARCHAR`` will be used to create the datatype.  For\nbackends other than MySQL/MariaDB or PostgreSQL, ``VARCHAR`` is used in\nall cases (third party dialects may have their own behaviors).\n\nBecause PostgreSQL\'s ``CREATE TYPE`` requires that there\'s an explicit name\nfor the type to be created, special fallback logic exists when working\nwith implicitly generated :class:`.sqltypes.Enum` without specifying an\nexplicit :class:`.sqltypes.Enum` datatype within a mapping:\n\n1. If the :class:`.sqltypes.Enum` is linked to an ``enum.Enum`` object,\n   the :paramref:`.sqltypes.Enum.native_enum` parameter defaults to\n   ``True`` and the name of the enum will be taken from the name of the\n   ``enum.Enum`` datatype.  The PostgreSQL backend will assume ``CREATE TYPE``\n   with this name.\n2. If the :class:`.sqltypes.Enum` is linked to a ``typing.Literal`` object,\n   the :paramref:`.sqltypes.Enum.native_enum` parameter defaults to\n   ``False``; no name is generated and ``VARCHAR`` is assumed.\n\nTo use ``typing.Literal`` with a PostgreSQL ``CREATE TYPE`` type, an\nexplicit :class:`.sqltypes.Enum` must be used, either within the\ntype map::\n\n    import enum\n    import typing\n\n    import sqlalchemy\n    from sqlalchemy.orm import DeclarativeBase\n\n    Status = Literal["pending", "received", "completed"]\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {\n            Status: sqlalchemy.Enum("pending", "received", "completed", name="status_enum"),\n        }\n\nOr alternatively within :func:`_orm.mapped_column`::\n\n    import enum\n    import typing\n\n    import sqlalchemy\n    from sqlalchemy.orm import DeclarativeBase\n\n    Status = Literal["pending", "received", "completed"]\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        status: Mapped[Status] = mapped_column(\n            sqlalchemy.Enum("pending", "received", "completed", name="status_enum")\n        )\n\nAltering the Configuration of the Default Enum\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nIn order to modify the fixed configuration of the :class:`.enum.Enum` datatype\nthat\'s generated implicitly, specify new entries in the\n:paramref:`_orm.registry.type_annotation_map`, indicating additional arguments.\nFor example, to use "non native enumerations" unconditionally, the\n:paramref:`.Enum.native_enum` parameter may be set to False for all types::\n\n    import enum\n    import typing\n    import sqlalchemy\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {\n            enum.Enum: sqlalchemy.Enum(enum.Enum, native_enum=False),\n            typing.Literal: sqlalchemy.Enum(enum.Enum, native_enum=False),\n        }\n\n.. versionchanged:: 2.0.1  Implemented support for overriding parameters\n   such as :paramref:`_sqltypes.Enum.native_enum` within the\n   :class:`_sqltypes.Enum` datatype when establishing the\n   :paramref:`_orm.registry.type_annotation_map`.  Previously, this\n   functionality was not working.\n\nTo use a specific configuration for a specific ``enum.Enum`` subtype, such\nas setting the string length to 50 when using the example ``Status``\ndatatype::\n\n    import enum\n    import sqlalchemy\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Status(enum.Enum):\n        PENDING = "pending"\n        RECEIVED = "received"\n        COMPLETED = "completed"\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {\n            Status: sqlalchemy.Enum(Status, length=50, native_enum=False)\n        }\n\nBy default :class:`_sqltypes.Enum` that are automatically generated are not\nassociated with the :class:`_sql.MetaData` instance used by the ``Base``, so if\nthe metadata defines a schema it will not be automatically associated with the\nenum. To automatically associate the enum with the schema in the metadata or\ntable they belong to the :paramref:`_sqltypes.Enum.inherit_schema` can be set::\n\n    from enum import Enum\n    import sqlalchemy as sa\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        metadata = sa.MetaData(schema="my_schema")\n        type_annotation_map = {Enum: sa.Enum(Enum, inherit_schema=True)}\n\nLinking Specific ``enum.Enum`` or ``typing.Literal`` to other datatypes\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe above examples feature the use of an :class:`_sqltypes.Enum` that is\nautomatically configuring itself to the arguments / attributes present on\nan ``enum.Enum`` or ``typing.Literal`` type object.    For use cases where\nspecific kinds of ``enum.Enum`` or ``typing.Literal`` should be linked to\nother types, these specific types may be placed in the type map also.\nIn the example below, an entry for ``Literal[]`` that contains non-string\ntypes is linked to the :class:`_sqltypes.JSON` datatype::\n\n\n    from typing import Literal\n\n    from sqlalchemy import JSON\n    from sqlalchemy.orm import DeclarativeBase\n\n    my_literal = Literal[0, 1, True, False, "true", "false"]\n\n\n    class Base(DeclarativeBase):\n        type_annotation_map = {my_literal: JSON}\n\nIn the above configuration, the ``my_literal`` datatype will resolve to a\n:class:`._sqltypes.JSON` instance.  Other ``Literal`` variants will continue\nto resolve to :class:`_sqltypes.Enum` datatypes.\n\n.. _orm_declarative_resolve_type_event:\n\nResolving Types Programmatically with Events\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n.. versionadded:: 2.1\n\nThe :paramref:`_orm.registry.type_annotation_map` is the usual\nway to customize how :func:`_orm.mapped_column` types are assigned to Python\ntypes.   But for automation of whole classes of types or other custom rules,\nthe type map resolution can be augmented and/or replaced using the\n:meth:`.RegistryEvents.resolve_type_annotation` hook.\n\nThis event hook allows for dynamic type resolution that goes beyond the static\nmappings possible with :paramref:`_orm.registry.type_annotation_map`. It\'s\nparticularly useful when working with generic types, complex type hierarchies,\nor when you need to implement custom logic for determining SQL types based\non Python type annotations.\n\nBasic Type Resolution with :meth:`.RegistryEvents.resolve_type_annotation`\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nBasic type resolution can be set up by registering the event against\na :class:`_orm.registry` or :class:`_orm.DeclarativeBase` class. The event\nreceives a single parameter that allows inspection of the type annotation\nand provides hooks for custom resolution logic.\n\nThe following example shows how to use the hook to resolve custom type aliases\nto appropriate SQL types::\n\n   from __future__ import annotations\n\n   from typing import Annotated\n   from typing import Any\n   from typing import get_args\n\n   from sqlalchemy import create_engine\n   from sqlalchemy import event\n   from sqlalchemy import Integer\n   from sqlalchemy import String\n   from sqlalchemy.orm import DeclarativeBase\n   from sqlalchemy.orm import Mapped\n   from sqlalchemy.orm import mapped_column\n   from sqlalchemy.orm import TypeResolve\n   from sqlalchemy.types import TypeEngine\n\n   # Define some custom type aliases\n   type UserId = int\n   type Username = str\n   LongText = Annotated[str, "long"]\n\n\n   class Base(DeclarativeBase):\n       pass\n\n\n   @event.listens_for(Base.registry, "resolve_type_annotation")\n   def resolve_custom_types(resolve_type: TypeResolve) -> TypeEngine[Any] | None:\n       # Handle our custom type aliases\n       if resolve_type.raw_pep_695_type is UserId:\n           return Integer()\n       elif resolve_type.raw_pep_695_type is Username:\n           return String(50)\n       elif resolve_type.raw_pep_593_type:\n           inner_type, *metadata = get_args(resolve_type.raw_pep_593_type)\n           if inner_type is str and "long" in metadata:\n               return String(1000)\n\n       # Fall back to default resolution\n       return None\n\n\n   class User(Base):\n       __tablename__ = "user"\n\n       id: Mapped[UserId] = mapped_column(primary_key=True)\n       name: Mapped[Username]\n       description: Mapped[LongText]\n\n\n   e = create_engine("sqlite://", echo=True)\n   Base.metadata.create_all(e)\n\nIn this example, the event handler checks for specific type aliases and\nreturns appropriate SQL types. When the handler returns ``None``, the\ndefault type resolution logic is used.\n\nProgrammatic Resolution of pep-695 and NewType types\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nAs detailed in :ref:`orm_declarative_type_map_pep695_types`, SQLAlchemy now\nautomatically resolves simple :pep:`695` ``type`` aliases, but does not\nautomatically resolve types made using ``typing.NewType`` without\nthese types being explicitly present in :paramref:`_orm.registry.type_annotation_map`.\n\nThe :meth:`.RegistryEvents.resolve_type_annotation` event provides a way\nto programmatically handle these types. This is particularly useful when you have\nmany ``NewType`` instances that would be cumbersome\nto list individually in the type annotation map::\n\n   from __future__ import annotations\n\n   from typing import Annotated\n   from typing import Any\n   from typing import NewType\n\n   from sqlalchemy import event\n   from sqlalchemy import String\n   from sqlalchemy.orm import DeclarativeBase\n   from sqlalchemy.orm import Mapped\n   from sqlalchemy.orm import mapped_column\n   from sqlalchemy.orm import TypeResolve\n   from sqlalchemy.types import TypeEngine\n\n   # Multiple NewType instances\n   IntPK = NewType("IntPK", int)\n   UserId = NewType("UserId", int)\n   ProductId = NewType("ProductId", int)\n   CategoryName = NewType("CategoryName", str)\n\n   # PEP 695 type alias that recursively refers to a NewType\n   type OrderId = Annotated[IntPK, mapped_column(primary_key=True)]\n\n\n   class Base(DeclarativeBase):\n       pass\n\n\n   @event.listens_for(Base.registry, "resolve_type_annotation")\n   def resolve_newtype_and_pep695(resolve_type: TypeResolve) -> TypeEngine[Any] | None:\n\n       # Handle NewType instances by checking their supertype\n       if hasattr(resolve_type.resolved_type, "__supertype__"):\n           supertype = resolve_type.resolved_type.__supertype__\n           if supertype is int:\n               # return default resolution for int\n               return resolve_type.resolve(int)\n           elif supertype is str:\n               return String(100)\n\n       # detect nested pep-695 IntPK type\n       if (\n           resolve_type.resolved_type is IntPK\n           or resolve_type.pep_593_resolved_argument is IntPK\n       ):\n           return resolve_type.resolve(int)\n\n       return None\n\n\n   class Order(Base):\n       __tablename__ = "order"\n\n       id: Mapped[OrderId]\n       user_id: Mapped[UserId]\n       product_id: Mapped[ProductId]\n       category_name: Mapped[CategoryName]\n\nThis approach allows you to handle entire categories of types programmatically\nrather than having to enumerate each one in the type annotation map.\n\n\n.. seealso::\n\n    :meth:`.RegistryEvents.resolve_type_annotation`\n\n.. _orm_imperative_table_configuration:\n\nDeclarative with Imperative Table (a.k.a. Hybrid Declarative)\n-------------------------------------------------------------\n\nDeclarative mappings may also be provided with a pre-existing\n:class:`_schema.Table` object, or otherwise a :class:`_schema.Table` or other\narbitrary :class:`_sql.FromClause` construct (such as a :class:`_sql.Join`\nor :class:`_sql.Subquery`) that is constructed separately.\n\nThis is referred to as a "hybrid declarative"\nmapping, as the class is mapped using the declarative style for everything\ninvolving the mapper configuration, however the mapped :class:`_schema.Table`\nobject is produced separately and passed to the declarative process\ndirectly::\n\n\n    from sqlalchemy import Column, ForeignKey, Integer, String\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    # construct a Table directly.  The Base.metadata collection is\n    # usually a good choice for MetaData but any MetaData\n    # collection may be used.\n\n    user_table = Table(\n        "user",\n        Base.metadata,\n        Column("id", Integer, primary_key=True),\n        Column("name", String),\n        Column("fullname", String),\n        Column("nickname", String),\n    )\n\n\n    # construct the User class using this table.\n    class User(Base):\n        __table__ = user_table\n\nAbove, a :class:`_schema.Table` object is constructed using the approach\ndescribed at :ref:`metadata_describing`.   It can then be applied directly\nto a class that is declaratively mapped.  The ``__tablename__`` and\n``__table_args__`` declarative class attributes are not used in this form.\nThe above configuration is often more readable as an inline definition::\n\n    class User(Base):\n        __table__ = Table(\n            "user",\n            Base.metadata,\n            Column("id", Integer, primary_key=True),\n            Column("name", String),\n            Column("fullname", String),\n            Column("nickname", String),\n        )\n\nA natural effect of the above style is that the ``__table__`` attribute is\nitself defined within the class definition block.   As such it may be\nimmediately referenced within subsequent attributes, such as the example\nbelow which illustrates referring to the ``type`` column in a polymorphic\nmapper configuration::\n\n    class Person(Base):\n        __table__ = Table(\n            "person",\n            Base.metadata,\n            Column("id", Integer, primary_key=True),\n            Column("name", String(50)),\n            Column("type", String(50)),\n        )\n\n        __mapper_args__ = {\n            "polymorphic_on": __table__.c.type,\n            "polymorphic_identity": "person",\n        }\n\nThe "imperative table" form is also used when a non-:class:`_schema.Table`\nconstruct, such as a :class:`_sql.Join` or :class:`_sql.Subquery` object,\nis to be mapped.  An example below::\n\n    from sqlalchemy import func, select\n\n    subq = (\n        select(\n            func.count(orders.c.id).label("order_count"),\n            func.max(orders.c.price).label("highest_order"),\n            orders.c.customer_id,\n        )\n        .group_by(orders.c.customer_id)\n        .subquery()\n    )\n\n    customer_select = (\n        select(customers, subq)\n        .join_from(customers, subq, customers.c.id == subq.c.customer_id)\n        .subquery()\n    )\n\n\n    class Customer(Base):\n        __table__ = customer_select\n\nFor background on mapping to non-:class:`_schema.Table` constructs see\nthe sections :ref:`orm_mapping_joins` and :ref:`orm_mapping_arbitrary_subqueries`.\n\nThe "imperative table" form is of particular use when the class itself\nis using an alternative form of attribute declaration, such as Python\ndataclasses.   See the section :ref:`orm_declarative_dataclasses` for detail.\n\n.. seealso::\n\n    :ref:`metadata_describing`\n\n    :ref:`orm_declarative_dataclasses`\n\n.. _orm_imperative_table_column_naming:\n\nAlternate Attribute Names for Mapping Table Columns\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe section :ref:`orm_declarative_table_column_naming` illustrated how to\nuse :func:`_orm.mapped_column` to provide a specific name for the generated\n:class:`_schema.Column` object separate from the attribute name under which\nit is mapped.\n\nWhen using Imperative Table configuration, we already have\n:class:`_schema.Column` objects present.  To map these to alternate names\nwe may assign the :class:`_schema.Column` to the desired attributes\ndirectly::\n\n    user_table = Table(\n        "user",\n        Base.metadata,\n        Column("user_id", Integer, primary_key=True),\n        Column("user_name", String),\n    )\n\n\n    class User(Base):\n        __table__ = user_table\n\n        id = user_table.c.user_id\n        name = user_table.c.user_name\n\nThe ``User`` mapping above will refer to the ``"user_id"`` and ``"user_name"``\ncolumns via the ``User.id`` and ``User.name`` attributes, in the same\nway as demonstrated at :ref:`orm_declarative_table_column_naming`.\n\nOne caveat to the above mapping is that the direct inline link to\n:class:`_schema.Column` will not be typed correctly when using\n:pep:`484` typing tools.   A strategy to resolve this is to apply the\n:class:`_schema.Column` objects within the :func:`_orm.column_property`\nfunction; while the :class:`_orm.Mapper` already generates this property\nobject for its internal use automatically, by naming it in the class\ndeclaration, typing tools will be able to match the attribute to the\n:class:`_orm.Mapped` annotation::\n\n    from sqlalchemy.orm import column_property\n    from sqlalchemy.orm import Mapped\n\n\n    class User(Base):\n        __table__ = user_table\n\n        id: Mapped[int] = column_property(user_table.c.user_id)\n        name: Mapped[str] = column_property(user_table.c.user_name)\n\n.. seealso::\n\n    :ref:`orm_declarative_table_column_naming` - applies to Declarative Table\n\n.. _column_property_options:\n\n.. _orm_imperative_table_column_options:\n\nApplying Load, Persistence and Mapping Options for Imperative Table Columns\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe section :ref:`orm_declarative_column_options` reviewed how to set load\nand persistence options when using the :func:`_orm.mapped_column` construct\nwith Declarative Table configuration.  When using Imperative Table configuration,\nwe already have existing :class:`_schema.Column` objects that are mapped.\nIn order to map these :class:`_schema.Column` objects along with additional\nparameters that are specific to the ORM mapping, we may use the\n:func:`_orm.column_property` and :func:`_orm.deferred` constructs in order to\nassociate additional parameters with the column.   Options include:\n\n* **deferred column loading** - The :func:`_orm.deferred` function is shorthand\n  for invoking :func:`_orm.column_property` with the\n  :paramref:`_orm.column_property.deferred` parameter set to ``True``;\n  this construct establishes the :class:`_schema.Column` using\n  :ref:`deferred column loading <orm_queryguide_column_deferral>` by default.  In the example\n  below, the ``User.bio`` column will not be loaded by default, but only\n  when accessed::\n\n    from sqlalchemy.orm import deferred\n\n    user_table = Table(\n        "user",\n        Base.metadata,\n        Column("id", Integer, primary_key=True),\n        Column("name", String),\n        Column("bio", Text),\n    )\n\n\n    class User(Base):\n        __table__ = user_table\n\n        bio = deferred(user_table.c.bio)\n\n .. seealso::\n\n     :ref:`orm_queryguide_column_deferral` - full description of deferred column loading\n\n* **active history** - The :paramref:`_orm.column_property.active_history`\n  ensures that upon change of value for the attribute, the previous value\n  will have been loaded and made part of the :attr:`.AttributeState.history`\n  collection when inspecting the history of the attribute.   This may incur\n  additional SQL statements::\n\n    from sqlalchemy.orm import column_property\n\n    user_table = Table(\n        "user",\n        Base.metadata,\n        Column("id", Integer, primary_key=True),\n        Column("important_identifier", String),\n    )\n\n\n    class User(Base):\n        __table__ = user_table\n\n        important_identifier = column_property(\n            user_table.c.important_identifier, active_history=True\n        )\n\n.. seealso::\n\n    The :func:`_orm.column_property` construct is also important for cases\n    where classes are mapped to alternative FROM clauses such as joins and\n    selects.  More background on these cases is at:\n\n    * :ref:`maptojoin`\n\n    * :ref:`mapper_sql_expressions`\n\n    For Declarative Table configuration with :func:`_orm.mapped_column`,\n    most options are available directly; see the section\n    :ref:`orm_declarative_column_options` for examples.\n\n\n\n.. _orm_declarative_reflected:\n\nMapping Declaratively with Reflected Tables\n--------------------------------------------\n\nThere are several patterns available which provide for producing mapped\nclasses against a series of :class:`_schema.Table` objects that were\nintrospected from the database, using the reflection process described at\n:ref:`metadata_reflection`.\n\nA simple way to map a class to a table reflected from the database is to\nuse a declarative hybrid mapping, passing the\n:paramref:`_schema.Table.autoload_with` parameter to the constructor for\n:class:`_schema.Table`::\n\n    from sqlalchemy import create_engine\n    from sqlalchemy import Table\n    from sqlalchemy.orm import DeclarativeBase\n\n    engine = create_engine("postgresql+psycopg2://user:pass@hostname/my_existing_database")\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class MyClass(Base):\n        __table__ = Table(\n            "mytable",\n            Base.metadata,\n            autoload_with=engine,\n        )\n\nA variant on the above pattern that scales for many tables is to use the\n:meth:`.MetaData.reflect` method to reflect a full set of :class:`.Table`\nobjects at once, then refer to them from the :class:`.MetaData`::\n\n\n    from sqlalchemy import create_engine\n    from sqlalchemy import Table\n    from sqlalchemy.orm import DeclarativeBase\n\n    engine = create_engine("postgresql+psycopg2://user:pass@hostname/my_existing_database")\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    Base.metadata.reflect(engine)\n\n\n    class MyClass(Base):\n        __table__ = Base.metadata.tables["mytable"]\n\nOne caveat to the approach of using ``__table__`` is that the mapped classes cannot\nbe declared until the tables have been reflected, which requires the database\nconnectivity source to be present while the application classes are being\ndeclared; it\'s typical that classes are declared as the modules of an\napplication are being imported, but database connectivity isn\'t available\nuntil the application starts running code so that it can consume configuration\ninformation and create an engine.   There are currently two approaches\nto working around this, described in the next two sections.\n\n.. _orm_declarative_reflected_deferred_reflection:\n\nUsing DeferredReflection\n^^^^^^^^^^^^^^^^^^^^^^^^^\n\nTo accommodate the use case of declaring mapped classes where reflection of\ntable metadata can occur afterwards, a simple extension called the\n:class:`.DeferredReflection` mixin is available, which alters the declarative\nmapping process to be delayed until a special class-level\n:meth:`.DeferredReflection.prepare` method is called, which will perform\nthe reflection process against a target database, and will integrate the\nresults with the declarative table mapping process, that is, classes which\nuse the ``__tablename__`` attribute::\n\n    from sqlalchemy.ext.declarative import DeferredReflection\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class Reflected(DeferredReflection):\n        __abstract__ = True\n\n\n    class Foo(Reflected, Base):\n        __tablename__ = "foo"\n        bars = relationship("Bar")\n\n\n    class Bar(Reflected, Base):\n        __tablename__ = "bar"\n\n        foo_id = mapped_column(Integer, ForeignKey("foo.id"))\n\nAbove, we create a mixin class ``Reflected`` that will serve as a base\nfor classes in our declarative hierarchy that should become mapped when\nthe ``Reflected.prepare`` method is called.   The above mapping is not\ncomplete until we do so, given an :class:`_engine.Engine`::\n\n\n    engine = create_engine("postgresql+psycopg2://user:pass@hostname/my_existing_database")\n    Reflected.prepare(engine)\n\nThe purpose of the ``Reflected`` class is to define the scope at which\nclasses should be reflectively mapped.   The plugin will search among the\nsubclass tree of the target against which ``.prepare()`` is called and reflect\nall tables which are named by declared classes; tables in the target database\nthat are not part of mappings and are not related to the target tables\nvia foreign key constraint will not be reflected.\n\nUsing Automap\n^^^^^^^^^^^^^^\n\nA more automated solution to mapping against an existing database where table\nreflection is to be used is to use the :ref:`automap_toplevel` extension. This\nextension will generate entire mapped classes from a database schema, including\nrelationships between classes based on observed foreign key constraints. While\nit includes hooks for customization, such as hooks that allow custom\nclass naming and relationship naming schemes, automap is oriented towards an\nexpedient zero-configuration style of working. If an application wishes to have\na fully explicit model that makes use of table reflection, the\n:ref:`DeferredReflection <orm_declarative_reflected_deferred_reflection>`\nclass may be preferable for its less automated approach.\n\n.. seealso::\n\n    :ref:`automap_toplevel`\n\n\n.. _mapper_automated_reflection_schemes:\n\nAutomating Column Naming Schemes from Reflected Tables\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nWhen using any of the previous reflection techniques, we have the option\nto change the naming scheme by which columns are mapped.   The\n:class:`_schema.Column` object includes a parameter\n:paramref:`_schema.Column.key` which is a string name that determines\nunder what name\nthis :class:`_schema.Column` will be present in the :attr:`_schema.Table.c`\ncollection, independently of the SQL name of the column.  This key is also\nused by :class:`_orm.Mapper` as the attribute name under which the\n:class:`_schema.Column` will be mapped, if not supplied through other\nmeans such as that illustrated at :ref:`orm_imperative_table_column_naming`.\n\nWhen working with table reflection, we can intercept the parameters that\nwill be used for :class:`_schema.Column` as they are received using\nthe :meth:`_events.DDLEvents.column_reflect` event and apply whatever\nchanges we need, including the ``.key`` attribute but also things like\ndatatypes.\n\nThe event hook is most easily\nassociated with the :class:`_schema.MetaData` object that\'s in use\nas illustrated below::\n\n    from sqlalchemy import event\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    @event.listens_for(Base.metadata, "column_reflect")\n    def column_reflect(inspector, table, column_info):\n        # set column.key = "attr_<lower_case_name>"\n        column_info["key"] = "attr_%s" % column_info["name"].lower()\n\nWith the above event, the reflection of :class:`_schema.Column` objects will be intercepted\nwith our event that adds a new ".key" element, such as in a mapping as below::\n\n    class MyClass(Base):\n        __table__ = Table("some_table", Base.metadata, autoload_with=some_engine)\n\nThe approach also works with both the :class:`.DeferredReflection` base class\nas well as with the :ref:`automap_toplevel` extension.   For automap\nspecifically, see the section :ref:`automap_intercepting_columns` for\nbackground.\n\n.. seealso::\n\n    :ref:`orm_declarative_reflected`\n\n    :meth:`_events.DDLEvents.column_reflect`\n\n    :ref:`automap_intercepting_columns` - in the :ref:`automap_toplevel` documentation\n\n\n.. _mapper_primary_key:\n\nMapping to an Explicit Set of Primary Key Columns\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe :class:`.Mapper` construct in order to successfully map a table always\nrequires that at least one column be identified as the "primary key" for\nthat selectable.   This is so that when an ORM object is loaded or persisted,\nit can be placed in the :term:`identity map` with an appropriate\n:term:`identity key`.\n\nIn those cases where a reflected table to be mapped does not include\na primary key constraint, as well as in the general case for\n:ref:`mapping against arbitrary selectables <orm_mapping_arbitrary_subqueries>`\nwhere primary key columns might not be present, the\n:paramref:`.Mapper.primary_key` parameter is provided so that any set of\ncolumns may be configured as the "primary key" for the table, as far as\nORM mapping is concerned.\n\nGiven the following example of an Imperative Table\nmapping against an existing :class:`.Table` object where the table does not\nhave any declared primary key (as may occur in reflection scenarios), we may\nmap such a table as in the following example::\n\n    from sqlalchemy import Column\n    from sqlalchemy import MetaData\n    from sqlalchemy import String\n    from sqlalchemy import Table\n    from sqlalchemy import UniqueConstraint\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    metadata = MetaData()\n    group_users = Table(\n        "group_users",\n        metadata,\n        Column("user_id", String(40), nullable=False),\n        Column("group_id", String(40), nullable=False),\n        UniqueConstraint("user_id", "group_id"),\n    )\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class GroupUsers(Base):\n        __table__ = group_users\n        __mapper_args__ = {"primary_key": [group_users.c.user_id, group_users.c.group_id]}\n\nAbove, the ``group_users`` table is an association table of some kind\nwith string columns ``user_id`` and ``group_id``, but no primary key is set up;\ninstead, there is only a :class:`.UniqueConstraint` establishing that the\ntwo columns represent a unique key.   The :class:`.Mapper` does not automatically\ninspect unique constraints for primary keys; instead, we make use of the\n:paramref:`.Mapper.primary_key` parameter, passing a collection of\n``[group_users.c.user_id, group_users.c.group_id]``, indicating that these two\ncolumns should be used in order to construct the identity key for instances\nof the ``GroupUsers`` class.\n\n\n.. _include_exclude_cols:\n\nMapping a Subset of Table Columns\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nSometimes table reflection may provide a :class:`_schema.Table` with many\ncolumns that are not important for our needs and may be safely ignored.\nFor such a table that has lots of columns that don\'t need to be referenced\nin the application, the :paramref:`_orm.Mapper.include_properties`\nor :paramref:`_orm.Mapper.exclude_properties` parameters can indicate\na subset of columns to be mapped, where other columns from the\ntarget :class:`_schema.Table` will not be considered by the ORM in any\nway.   Example::\n\n    class User(Base):\n        __table__ = user_table\n        __mapper_args__ = {"include_properties": ["user_id", "user_name"]}\n\nIn the above example, the ``User`` class will map to the ``user_table`` table, only\nincluding the ``user_id`` and ``user_name`` columns - the rest are not referenced.\n\nSimilarly::\n\n    class Address(Base):\n        __table__ = address_table\n        __mapper_args__ = {"exclude_properties": ["street", "city", "state", "zip"]}\n\nwill map the ``Address`` class to the ``address_table`` table, including\nall columns present except ``street``, ``city``, ``state``, and ``zip``.\n\nAs indicated in the two examples, columns may be referenced either\nby string name or by referring to the :class:`_schema.Column` object\ndirectly.  Referring to the object directly may be useful for explicitness as\nwell as to resolve ambiguities when\nmapping to multi-table constructs that might have repeated names::\n\n    class User(Base):\n        __table__ = user_table\n        __mapper_args__ = {\n            "include_properties": [user_table.c.user_id, user_table.c.user_name]\n        }\n\nWhen columns are not included in a mapping, these columns will not be\nreferenced in any SELECT statements emitted when executing :func:`_sql.select`\nor legacy :class:`_query.Query` objects, nor will there be any mapped attribute\non the mapped class which represents the column; assigning an attribute of that\nname will have no effect beyond that of a normal Python attribute assignment.\n\nHowever, it is important to note that **schema level column defaults WILL\nstill be in effect** for those :class:`_schema.Column` objects that include them,\neven though they may be excluded from the ORM mapping.\n\n"Schema level column defaults" refers to the defaults described at\n:ref:`metadata_defaults` including those configured by the\n:paramref:`_schema.Column.default`, :paramref:`_schema.Column.onupdate`,\n:paramref:`_schema.Column.server_default` and\n:paramref:`_schema.Column.server_onupdate` parameters. These constructs\ncontinue to have normal effects because in the case of\n:paramref:`_schema.Column.default` and :paramref:`_schema.Column.onupdate`, the\n:class:`_schema.Column` object is still present on the underlying\n:class:`_schema.Table`, thus allowing the default functions to take place when\nthe ORM emits an INSERT or UPDATE, and in the case of\n:paramref:`_schema.Column.server_default` and\n:paramref:`_schema.Column.server_onupdate`, the relational database itself\nemits these defaults as a server side behavior.\n\n\n\n.. _mypy: https://mypy.readthedocs.io/en/stable/\n\n.. _pylance: https://github.com/microsoft/pylance-release\n\n.. _generic: https://peps.python.org/pep-0484/#generics\n\n.. _dataclasses: https://docs.python.org/3/library/dataclasses.html\n',
            'doc/build/orm/join_conditions.rst': '.. _relationship_configure_joins:\n\nConfiguring how Relationship Joins\n----------------------------------\n\n:func:`_orm.relationship` will normally create a join between two tables\nby examining the foreign key relationship between the two tables\nto determine which columns should be compared.  There are a variety\nof situations where this behavior needs to be customized.\n\n.. _relationship_foreign_keys:\n\nHandling Multiple Join Paths\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nOne of the most common situations to deal with is when\nthere are more than one foreign key path between two tables.\n\nConsider a ``Customer`` class that contains two foreign keys to an ``Address``\nclass::\n\n    from sqlalchemy import Integer, ForeignKey, String, Column\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class Customer(Base):\n        __tablename__ = "customer"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n\n        billing_address_id = mapped_column(Integer, ForeignKey("address.id"))\n        shipping_address_id = mapped_column(Integer, ForeignKey("address.id"))\n\n        billing_address = relationship("Address")\n        shipping_address = relationship("Address")\n\n\n    class Address(Base):\n        __tablename__ = "address"\n        id = mapped_column(Integer, primary_key=True)\n        street = mapped_column(String)\n        city = mapped_column(String)\n        state = mapped_column(String)\n        zip = mapped_column(String)\n\nThe above mapping, when we attempt to use it, will produce the error:\n\n.. sourcecode:: text\n\n    sqlalchemy.exc.AmbiguousForeignKeysError: Could not determine join\n    condition between parent/child tables on relationship\n    Customer.billing_address - there are multiple foreign key\n    paths linking the tables.  Specify the \'foreign_keys\' argument,\n    providing a list of those columns which should be\n    counted as containing a foreign key reference to the parent table.\n\nThe above message is pretty long.  There are many potential messages\nthat :func:`_orm.relationship` can return, which have been carefully tailored\nto detect a variety of common configurational issues; most will suggest\nthe additional configuration that\'s needed to resolve the ambiguity\nor other missing information.\n\nIn this case, the message wants us to qualify each :func:`_orm.relationship`\nby instructing for each one which foreign key column should be considered, and\nthe appropriate form is as follows::\n\n    class Customer(Base):\n        __tablename__ = "customer"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n\n        billing_address_id = mapped_column(Integer, ForeignKey("address.id"))\n        shipping_address_id = mapped_column(Integer, ForeignKey("address.id"))\n\n        billing_address = relationship("Address", foreign_keys=[billing_address_id])\n        shipping_address = relationship("Address", foreign_keys=[shipping_address_id])\n\nAbove, we specify the ``foreign_keys`` argument, which is a :class:`_schema.Column` or list\nof :class:`_schema.Column` objects which indicate those columns to be considered "foreign",\nor in other words, the columns that contain a value referring to a parent table.\nLoading the ``Customer.billing_address`` relationship from a ``Customer``\nobject will use the value present in ``billing_address_id`` in order to\nidentify the row in ``Address`` to be loaded; similarly, ``shipping_address_id``\nis used for the ``shipping_address`` relationship.   The linkage of the two\ncolumns also plays a role during persistence; the newly generated primary key\nof a just-inserted ``Address`` object will be copied into the appropriate\nforeign key column of an associated ``Customer`` object during a flush.\n\nWhen specifying ``foreign_keys`` with Declarative, we can also use string\nnames to specify, however it is important that if using a list, the **list\nis part of the string**::\n\n        billing_address = relationship("Address", foreign_keys="[Customer.billing_address_id]")\n\nIn this specific example, the list is not necessary in any case as there\'s only\none :class:`_schema.Column` we need::\n\n        billing_address = relationship("Address", foreign_keys="Customer.billing_address_id")\n\n.. warning:: When passed as a Python-evaluable string, the\n    :paramref:`_orm.relationship.foreign_keys` argument is interpreted using Python\'s\n    ``eval()`` function. **DO NOT PASS UNTRUSTED INPUT TO THIS STRING**. See\n    :ref:`declarative_relationship_eval` for details on declarative\n    evaluation of :func:`_orm.relationship` arguments.\n\n\n.. _relationship_primaryjoin:\n\nSpecifying Alternate Join Conditions\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe default behavior of :func:`_orm.relationship` when constructing a join\nis that it equates the value of primary key columns\non one side to that of foreign-key-referring columns on the other.\nWe can change this criterion to be anything we\'d like using the\n:paramref:`_orm.relationship.primaryjoin`\nargument, as well as the :paramref:`_orm.relationship.secondaryjoin`\nargument in the case when a "secondary" table is used.\n\nIn the example below, using the ``User`` class\nas well as an ``Address`` class which stores a street address,  we\ncreate a relationship ``boston_addresses`` which will only\nload those ``Address`` objects which specify a city of "Boston"::\n\n    from sqlalchemy import Integer, ForeignKey, String, Column\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user"\n        id = mapped_column(Integer, primary_key=True)\n        name = mapped_column(String)\n        boston_addresses = relationship(\n            "Address",\n            primaryjoin="and_(User.id==Address.user_id, Address.city==\'Boston\')",\n        )\n\n\n    class Address(Base):\n        __tablename__ = "address"\n        id = mapped_column(Integer, primary_key=True)\n        user_id = mapped_column(Integer, ForeignKey("user.id"))\n\n        street = mapped_column(String)\n        city = mapped_column(String)\n        state = mapped_column(String)\n        zip = mapped_column(String)\n\nWithin this string SQL expression, we made use of the :func:`.and_` conjunction\nconstruct to establish two distinct predicates for the join condition - joining\nboth the ``User.id`` and ``Address.user_id`` columns to each other, as well as\nlimiting rows in ``Address`` to just ``city=\'Boston\'``.   When using\nDeclarative, rudimentary SQL functions like :func:`.and_` are automatically\navailable in the evaluated namespace of a string :func:`_orm.relationship`\nargument.\n\n.. warning:: When passed as a Python-evaluable string, the\n    :paramref:`_orm.relationship.primaryjoin` argument is interpreted using\n    Python\'s\n    ``eval()`` function. **DO NOT PASS UNTRUSTED INPUT TO THIS STRING**. See\n    :ref:`declarative_relationship_eval` for details on declarative\n    evaluation of :func:`_orm.relationship` arguments.\n\n\nThe custom criteria we use in a :paramref:`_orm.relationship.primaryjoin`\nis generally only significant when SQLAlchemy is rendering SQL in\norder to load or represent this relationship. That is, it\'s used in\nthe SQL statement that\'s emitted in order to perform a per-attribute\nlazy load, or when a join is constructed at query time, such as via\n:meth:`Select.join`, or via the eager "joined" or "subquery" styles of\nloading.   When in-memory objects are being manipulated, we can place\nany ``Address`` object we\'d like into the ``boston_addresses``\ncollection, regardless of what the value of the ``.city`` attribute\nis.   The objects will remain present in the collection until the\nattribute is expired and re-loaded from the database where the\ncriterion is applied.   When a flush occurs, the objects inside of\n``boston_addresses`` will be flushed unconditionally, assigning value\nof the primary key ``user.id`` column onto the foreign-key-holding\n``address.user_id`` column for each row.  The ``city`` criteria has no\neffect here, as the flush process only cares about synchronizing\nprimary key values into referencing foreign key values.\n\n.. _relationship_custom_foreign:\n\nCreating Custom Foreign Conditions\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nAnother element of the primary join condition is how those columns\nconsidered "foreign" are determined.  Usually, some subset\nof :class:`_schema.Column` objects will specify :class:`_schema.ForeignKey`, or otherwise\nbe part of a :class:`_schema.ForeignKeyConstraint` that\'s relevant to the join condition.\n:func:`_orm.relationship` looks to this foreign key status as it decides\nhow it should load and persist data for this relationship.   However, the\n:paramref:`_orm.relationship.primaryjoin` argument can be used to create a join condition that\ndoesn\'t involve any "schema" level foreign keys.  We can combine :paramref:`_orm.relationship.primaryjoin`\nalong with :paramref:`_orm.relationship.foreign_keys` and :paramref:`_orm.relationship.remote_side` explicitly in order to\nestablish such a join.\n\nBelow, a class ``HostEntry`` joins to itself, equating the string ``content``\ncolumn to the ``ip_address`` column, which is a PostgreSQL type called ``INET``.\nWe need to use :func:`.cast` in order to cast one side of the join to the\ntype of the other::\n\n    from sqlalchemy import cast, String, Column, Integer\n    from sqlalchemy.orm import relationship\n    from sqlalchemy.dialects.postgresql import INET\n\n    from sqlalchemy.orm import DeclarativeBase\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class HostEntry(Base):\n        __tablename__ = "host_entry"\n\n        id = mapped_column(Integer, primary_key=True)\n        ip_address = mapped_column(INET)\n        content = mapped_column(String(50))\n\n        # relationship() using explicit foreign_keys, remote_side\n        parent_host = relationship(\n            "HostEntry",\n            primaryjoin=ip_address == cast(content, INET),\n            foreign_keys=content,\n            remote_side=ip_address,\n        )\n\nThe above relationship will produce a join like:\n\n.. sourcecode:: sql\n\n    SELECT host_entry.id, host_entry.ip_address, host_entry.content\n    FROM host_entry JOIN host_entry AS host_entry_1\n    ON host_entry_1.ip_address = CAST(host_entry.content AS INET)\n\nAn alternative syntax to the above is to use the :func:`.foreign` and\n:func:`.remote` :term:`annotations`,\ninline within the :paramref:`_orm.relationship.primaryjoin` expression.\nThis syntax represents the annotations that :func:`_orm.relationship` normally\napplies by itself to the join condition given the :paramref:`_orm.relationship.foreign_keys` and\n:paramref:`_orm.relationship.remote_side` arguments.  These functions may\nbe more succinct when an explicit join condition is present, and additionally\nserve to mark exactly the column that is "foreign" or "remote" independent\nof whether that column is stated multiple times or within complex\nSQL expressions::\n\n    from sqlalchemy.orm import foreign, remote\n\n\n    class HostEntry(Base):\n        __tablename__ = "host_entry"\n\n        id = mapped_column(Integer, primary_key=True)\n        ip_address = mapped_column(INET)\n        content = mapped_column(String(50))\n\n        # relationship() using explicit foreign() and remote() annotations\n        # in lieu of separate arguments\n        parent_host = relationship(\n            "HostEntry",\n            primaryjoin=remote(ip_address) == cast(foreign(content), INET),\n        )\n\n.. _relationship_custom_operator:\n\nUsing custom operators in join conditions\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nAnother use case for relationships is the use of custom operators, such\nas PostgreSQL\'s "is contained within" ``<<`` operator when joining with\ntypes such as :class:`_postgresql.INET` and :class:`_postgresql.CIDR`.\nFor custom boolean operators we use the :meth:`.Operators.bool_op` function::\n\n    inet_column.bool_op("<<")(cidr_column)\n\nA comparison like the above may be used directly with\n:paramref:`_orm.relationship.primaryjoin` when constructing\na :func:`_orm.relationship`::\n\n    class IPA(Base):\n        __tablename__ = "ip_address"\n\n        id = mapped_column(Integer, primary_key=True)\n        v4address = mapped_column(INET)\n\n        network = relationship(\n            "Network",\n            primaryjoin="IPA.v4address.bool_op(\'<<\')(foreign(Network.v4representation))",\n            viewonly=True,\n        )\n\n\n    class Network(Base):\n        __tablename__ = "network"\n\n        id = mapped_column(Integer, primary_key=True)\n        v4representation = mapped_column(CIDR)\n\nAbove, a query such as::\n\n    select(IPA).join(IPA.network)\n\nWill render as:\n\n.. sourcecode:: sql\n\n    SELECT ip_address.id AS ip_address_id, ip_address.v4address AS ip_address_v4address\n    FROM ip_address JOIN network ON ip_address.v4address << network.v4representation\n\n.. _relationship_custom_operator_sql_function:\n\nCustom operators based on SQL functions\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nA variant to the use case for :paramref:`~.Operators.op.is_comparison` is\nwhen we aren\'t using an operator, but a SQL function.   The typical example\nof this use case is the PostgreSQL PostGIS functions however any SQL\nfunction on any database that resolves to a binary condition may apply.\nTo suit this use case, the :meth:`.FunctionElement.as_comparison` method\ncan modify any SQL function, such as those invoked from the :data:`.func`\nnamespace, to indicate to the ORM that the function produces a comparison of\ntwo expressions.  The below example illustrates this with the\n`Geoalchemy2 <https://geoalchemy-2.readthedocs.io/>`_ library::\n\n    from geoalchemy2 import Geometry\n    from sqlalchemy import Column, Integer, func\n    from sqlalchemy.orm import relationship, foreign\n\n\n    class Polygon(Base):\n        __tablename__ = "polygon"\n        id = mapped_column(Integer, primary_key=True)\n        geom = mapped_column(Geometry("POLYGON", srid=4326))\n        points = relationship(\n            "Point",\n            primaryjoin="func.ST_Contains(foreign(Polygon.geom), Point.geom).as_comparison(1, 2)",\n            viewonly=True,\n        )\n\n\n    class Point(Base):\n        __tablename__ = "point"\n        id = mapped_column(Integer, primary_key=True)\n        geom = mapped_column(Geometry("POINT", srid=4326))\n\nAbove, the :meth:`.FunctionElement.as_comparison` indicates that the\n``func.ST_Contains()`` SQL function is comparing the ``Polygon.geom`` and\n``Point.geom`` expressions. The :func:`.foreign` annotation additionally notes\nwhich column takes on the "foreign key" role in this particular relationship.\n\n.. _relationship_overlapping_foreignkeys:\n\nOverlapping Foreign Keys\n~~~~~~~~~~~~~~~~~~~~~~~~\n\nA rare scenario can arise when composite foreign keys are used, such that\na single column may be the subject of more than one column\nreferred to via foreign key constraint.\n\nConsider an (admittedly complex) mapping such as the ``Magazine`` object,\nreferred to both by the ``Writer`` object and the ``Article`` object\nusing a composite primary key scheme that includes ``magazine_id``\nfor both; then to make ``Article`` refer to ``Writer`` as well,\n``Article.magazine_id`` is involved in two separate relationships;\n``Article.magazine`` and ``Article.writer``::\n\n    class Magazine(Base):\n        __tablename__ = "magazine"\n\n        id = mapped_column(Integer, primary_key=True)\n\n\n    class Article(Base):\n        __tablename__ = "article"\n\n        article_id = mapped_column(Integer)\n        magazine_id = mapped_column(ForeignKey("magazine.id"))\n        writer_id = mapped_column(Integer)\n\n        magazine = relationship("Magazine")\n        writer = relationship("Writer")\n\n        __table_args__ = (\n            PrimaryKeyConstraint("article_id", "magazine_id"),\n            ForeignKeyConstraint(\n                ["writer_id", "magazine_id"], ["writer.id", "writer.magazine_id"]\n            ),\n        )\n\n\n    class Writer(Base):\n        __tablename__ = "writer"\n\n        id = mapped_column(Integer, primary_key=True)\n        magazine_id = mapped_column(ForeignKey("magazine.id"), primary_key=True)\n        magazine = relationship("Magazine")\n\nWhen the above mapping is configured, we will see this warning emitted:\n\n.. sourcecode:: text\n\n    SAWarning: relationship \'Article.writer\' will copy column\n    writer.magazine_id to column article.magazine_id,\n    which conflicts with relationship(s): \'Article.magazine\'\n    (copies magazine.id to article.magazine_id). Consider applying\n    viewonly=True to read-only relationships, or provide a primaryjoin\n    condition marking writable columns with the foreign() annotation.\n\nWhat this refers to originates from the fact that ``Article.magazine_id`` is\nthe subject of two different foreign key constraints; it refers to\n``Magazine.id`` directly as a source column, but also refers to\n``Writer.magazine_id`` as a source column in the context of the\ncomposite key to ``Writer``.\n\nWhen objects are added to an ORM :class:`.Session` using :meth:`.Session.add`,\nthe ORM :term:`flush` process takes on the task of reconciling object\nrefereneces that correspond to :func:`_orm.relationship` configurations and\ndelivering this state to the databse using INSERT/UPDATE/DELETE statements.  In\nthis specific example, if we associate an ``Article`` with a particular\n``Magazine``, but then associate the ``Article`` with a ``Writer`` that\'s\nassociated  with a *different* ``Magazine``, this flush process will overwrite\n``Article.magazine_id`` non-deterministically, silently changing which magazine\nto which we refer; it may also attempt to place NULL into this column if we\nde-associate a ``Writer`` from an ``Article``.  The warning lets us know that\nthis scenario may occur during ORM flush sequences.\n\nTo solve this, we need to break out the behavior of ``Article`` to include\nall three of the following features:\n\n1. ``Article`` first and foremost writes to\n   ``Article.magazine_id`` based on data persisted in the ``Article.magazine``\n   relationship only, that is a value copied from ``Magazine.id``.\n\n2. ``Article`` can write to ``Article.writer_id`` on behalf of data\n   persisted in the  ``Article.writer`` relationship, but only the\n   ``Writer.id`` column; the ``Writer.magazine_id`` column should not\n   be written into ``Article.magazine_id`` as it ultimately is sourced\n   from ``Magazine.id``.\n\n3. ``Article`` takes ``Article.magazine_id`` into account when loading\n   ``Article.writer``, even though it *doesn\'t* write to it on behalf\n   of this relationship.\n\nTo get just #1 and #2, we could specify only ``Article.writer_id`` as the\n"foreign keys" for ``Article.writer``::\n\n    class Article(Base):\n        # ...\n\n        writer = relationship("Writer", foreign_keys="Article.writer_id")\n\nHowever, this has the effect of ``Article.writer`` not taking\n``Article.magazine_id`` into account when querying against ``Writer``:\n\n.. sourcecode:: sql\n\n    SELECT article.article_id AS article_article_id,\n        article.magazine_id AS article_magazine_id,\n        article.writer_id AS article_writer_id\n    FROM article\n    JOIN writer ON writer.id = article.writer_id\n\nTherefore, to get at all of #1, #2, and #3, we express the join condition\nas well as which columns to be written by combining\n:paramref:`_orm.relationship.primaryjoin` fully, along with either the\n:paramref:`_orm.relationship.foreign_keys` argument, or more succinctly by\nannotating with :func:`_orm.foreign`::\n\n    class Article(Base):\n        # ...\n\n        writer = relationship(\n            "Writer",\n            primaryjoin="and_(Writer.id == foreign(Article.writer_id), "\n            "Writer.magazine_id == Article.magazine_id)",\n        )\n\nNon-relational Comparisons / Materialized Path\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\n.. warning::  this section details an experimental feature.\n\nUsing custom expressions means we can produce unorthodox join conditions that\ndon\'t obey the usual primary/foreign key model.  One such example is the\nmaterialized path pattern, where we compare strings for overlapping path tokens\nin order to produce a tree structure.\n\nThrough careful use of :func:`.foreign` and :func:`.remote`, we can build\na relationship that effectively produces a rudimentary materialized path\nsystem.   Essentially, when :func:`.foreign` and :func:`.remote` are\non the *same* side of the comparison expression, the relationship is considered\nto be "one to many"; when they are on *different* sides, the relationship\nis considered to be "many to one".   For the comparison we\'ll use here,\nwe\'ll be dealing with collections so we keep things configured as "one to many"::\n\n    class Element(Base):\n        __tablename__ = "element"\n\n        path = mapped_column(String, primary_key=True)\n\n        descendants = relationship(\n            "Element",\n            primaryjoin=remote(foreign(path)).like(path.concat("/%")),\n            viewonly=True,\n            order_by=path,\n        )\n\nAbove, if given an ``Element`` object with a path attribute of ``"/foo/bar2"``,\nwe seek for a load of ``Element.descendants`` to look like:\n\n.. sourcecode:: sql\n\n    SELECT element.path AS element_path\n    FROM element\n    WHERE element.path LIKE (\'/foo/bar2\' || \'/%\') ORDER BY element.path\n\n.. _self_referential_many_to_many:\n\nSelf-Referential Many-to-Many Relationship\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\n.. seealso::\n\n    This section documents a two-table variant of the "adjacency list" pattern,\n    which is documented at :ref:`self_referential`.  Be sure to review the\n    self-referential querying patterns in subsections\n    :ref:`self_referential_query` and :ref:`self_referential_eager_loading`\n    which apply equally well to the mapping pattern discussed here.\n\nMany to many relationships can be customized by one or both of :paramref:`_orm.relationship.primaryjoin`\nand :paramref:`_orm.relationship.secondaryjoin` - the latter is significant for a relationship that\nspecifies a many-to-many reference using the :paramref:`_orm.relationship.secondary` argument.\nA common situation which involves the usage of :paramref:`_orm.relationship.primaryjoin` and :paramref:`_orm.relationship.secondaryjoin`\nis when establishing a many-to-many relationship from a class to itself, as shown below::\n\n    from typing import List\n\n    from sqlalchemy import Integer, ForeignKey, Column, Table\n    from sqlalchemy.orm import DeclarativeBase, Mapped\n    from sqlalchemy.orm import mapped_column, relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    node_to_node = Table(\n        "node_to_node",\n        Base.metadata,\n        Column("left_node_id", Integer, ForeignKey("node.id"), primary_key=True),\n        Column("right_node_id", Integer, ForeignKey("node.id"), primary_key=True),\n    )\n\n\n    class Node(Base):\n        __tablename__ = "node"\n        id: Mapped[int] = mapped_column(primary_key=True)\n        label: Mapped[str]\n        right_nodes: Mapped[List["Node"]] = relationship(\n            "Node",\n            secondary=node_to_node,\n            primaryjoin=id == node_to_node.c.left_node_id,\n            secondaryjoin=id == node_to_node.c.right_node_id,\n            back_populates="left_nodes",\n        )\n        left_nodes: Mapped[List["Node"]] = relationship(\n            "Node",\n            secondary=node_to_node,\n            primaryjoin=id == node_to_node.c.right_node_id,\n            secondaryjoin=id == node_to_node.c.left_node_id,\n            back_populates="right_nodes",\n        )\n\nWhere above, SQLAlchemy can\'t know automatically which columns should connect\nto which for the ``right_nodes`` and ``left_nodes`` relationships.   The :paramref:`_orm.relationship.primaryjoin`\nand :paramref:`_orm.relationship.secondaryjoin` arguments establish how we\'d like to join to the association table.\nIn the Declarative form above, as we are declaring these conditions within the Python\nblock that corresponds to the ``Node`` class, the ``id`` variable is available directly\nas the :class:`_schema.Column` object we wish to join with.\n\nAlternatively, we can define the :paramref:`_orm.relationship.primaryjoin`\nand :paramref:`_orm.relationship.secondaryjoin` arguments using strings, which is suitable\nin the case that our configuration does not have either the ``Node.id`` column\nobject available yet or the ``node_to_node`` table perhaps isn\'t yet available.\nWhen referring to a plain :class:`_schema.Table` object in a declarative string, we\nuse the string name of the table as it is present in the :class:`_schema.MetaData`::\n\n    class Node(Base):\n        __tablename__ = "node"\n        id = mapped_column(Integer, primary_key=True)\n        label = mapped_column(String)\n        right_nodes = relationship(\n            "Node",\n            secondary="node_to_node",\n            primaryjoin="Node.id==node_to_node.c.left_node_id",\n            secondaryjoin="Node.id==node_to_node.c.right_node_id",\n            backref="left_nodes",\n        )\n\n.. warning:: When passed as a Python-evaluable string, the\n    :paramref:`_orm.relationship.primaryjoin` and\n    :paramref:`_orm.relationship.secondaryjoin` arguments are interpreted using\n    Python\'s ``eval()`` function. **DO NOT PASS UNTRUSTED INPUT TO THESE\n    STRINGS**. See :ref:`declarative_relationship_eval` for details on\n    declarative evaluation of :func:`_orm.relationship` arguments.\n\n\nA classical mapping situation here is similar, where ``node_to_node`` can be joined\nto ``node.c.id``::\n\n    from sqlalchemy import Integer, ForeignKey, String, Column, Table, MetaData\n    from sqlalchemy.orm import relationship, registry\n\n    metadata_obj = MetaData()\n    mapper_registry = registry()\n\n    node_to_node = Table(\n        "node_to_node",\n        metadata_obj,\n        Column("left_node_id", Integer, ForeignKey("node.id"), primary_key=True),\n        Column("right_node_id", Integer, ForeignKey("node.id"), primary_key=True),\n    )\n\n    node = Table(\n        "node",\n        metadata_obj,\n        Column("id", Integer, primary_key=True),\n        Column("label", String),\n    )\n\n\n    class Node:\n        pass\n\n\n    mapper_registry.map_imperatively(\n        Node,\n        node,\n        properties={\n            "right_nodes": relationship(\n                Node,\n                secondary=node_to_node,\n                primaryjoin=node.c.id == node_to_node.c.left_node_id,\n                secondaryjoin=node.c.id == node_to_node.c.right_node_id,\n                backref="left_nodes",\n            )\n        },\n    )\n\nNote that in both examples, the :paramref:`_orm.relationship.backref`\nkeyword specifies a ``left_nodes`` backref - when\n:func:`_orm.relationship` creates the second relationship in the reverse\ndirection, it\'s smart enough to reverse the\n:paramref:`_orm.relationship.primaryjoin` and\n:paramref:`_orm.relationship.secondaryjoin` arguments.\n\n.. seealso::\n\n  * :ref:`self_referential` - single table version\n  * :ref:`self_referential_query` - tips on querying with self-referential\n    mappings\n  * :ref:`self_referential_eager_loading` - tips on eager loading with self-\n    referential mapping\n\n.. _composite_secondary_join:\n\nComposite "Secondary" Joins\n~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\n.. note::\n\n    This section features far edge cases that are somewhat supported\n    by SQLAlchemy, however it is recommended to solve problems like these\n    in simpler ways whenever possible, by using reasonable relational\n    layouts and / or :ref:`in-Python attributes <mapper_hybrids>`.\n\nSometimes, when one seeks to build a :func:`_orm.relationship` between two tables\nthere is a need for more than just two or three tables to be involved in\norder to join them.  This is an area of :func:`_orm.relationship` where one seeks\nto push the boundaries of what\'s possible, and often the ultimate solution to\nmany of these exotic use cases needs to be hammered out on the SQLAlchemy mailing\nlist.\n\nIn more recent versions of SQLAlchemy, the :paramref:`_orm.relationship.secondary`\nparameter can be used in some of these cases in order to provide a composite\ntarget consisting of multiple tables.   Below is an example of such a\njoin condition (requires version 0.9.2 at least to function as is)::\n\n    class A(Base):\n        __tablename__ = "a"\n\n        id = mapped_column(Integer, primary_key=True)\n        b_id = mapped_column(ForeignKey("b.id"))\n\n        d = relationship(\n            "D",\n            secondary="join(B, D, B.d_id == D.id).join(C, C.d_id == D.id)",\n            primaryjoin="and_(A.b_id == B.id, A.id == C.a_id)",\n            secondaryjoin="D.id == B.d_id",\n            uselist=False,\n            viewonly=True,\n        )\n\n\n    class B(Base):\n        __tablename__ = "b"\n\n        id = mapped_column(Integer, primary_key=True)\n        d_id = mapped_column(ForeignKey("d.id"))\n\n\n    class C(Base):\n        __tablename__ = "c"\n\n        id = mapped_column(Integer, primary_key=True)\n        a_id = mapped_column(ForeignKey("a.id"))\n        d_id = mapped_column(ForeignKey("d.id"))\n\n\n    class D(Base):\n        __tablename__ = "d"\n\n        id = mapped_column(Integer, primary_key=True)\n\nIn the above example, we provide all three of :paramref:`_orm.relationship.secondary`,\n:paramref:`_orm.relationship.primaryjoin`, and :paramref:`_orm.relationship.secondaryjoin`,\nin the declarative style referring to the named tables ``a``, ``b``, ``c``, ``d``\ndirectly.  A query from ``A`` to ``D`` looks like:\n\n.. sourcecode:: python+sql\n\n    sess.scalars(select(A).join(A.d)).all()\n\n    {execsql}SELECT a.id AS a_id, a.b_id AS a_b_id\n    FROM a JOIN (\n        b AS b_1 JOIN d AS d_1 ON b_1.d_id = d_1.id\n            JOIN c AS c_1 ON c_1.d_id = d_1.id)\n        ON a.b_id = b_1.id AND a.id = c_1.a_id JOIN d ON d.id = b_1.d_id\n\nIn the above example, we take advantage of being able to stuff multiple\ntables into a "secondary" container, so that we can join across many\ntables while still keeping things "simple" for :func:`_orm.relationship`, in that\nthere\'s just "one" table on both the "left" and the "right" side; the\ncomplexity is kept within the middle.\n\n.. warning:: A relationship like the above is typically marked as\n   ``viewonly=True``, using :paramref:`_orm.relationship.viewonly`,\n   and should be considered as read-only.  While there are\n   sometimes ways to make relationships like the above writable, this is\n   generally complicated and error prone.\n\n.. seealso::\n\n    :ref:`relationship_viewonly_notes`\n\n\n\n.. _relationship_non_primary_mapper:\n\n.. _relationship_aliased_class:\n\nRelationship to Aliased Class\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nIn the previous section, we illustrated a technique where we used\n:paramref:`_orm.relationship.secondary` in order to place additional\ntables within a join condition.   There is one complex join case where\neven this technique is not sufficient; when we seek to join from ``A``\nto ``B``, making use of any number of ``C``, ``D``, etc. in between,\nhowever there are also join conditions between ``A`` and ``B``\n*directly*.  In this case, the join from ``A`` to ``B`` may be\ndifficult to express with just a complex\n:paramref:`_orm.relationship.primaryjoin` condition, as the intermediary\ntables may need special handling, and it is also not expressible with\na :paramref:`_orm.relationship.secondary` object, since the\n``A->secondary->B`` pattern does not support any references between\n``A`` and ``B`` directly.  When this **extremely advanced** case\narises, we can resort to creating a second mapping as a target for the\nrelationship.  This is where we use :class:`.AliasedClass` in order to make a\nmapping to a class that includes all the additional tables we need for\nthis join. In order to produce this mapper as an "alternative" mapping\nfor our class, we use the :func:`.aliased` function to produce the new\nconstruct, then use :func:`_orm.relationship` against the object as though it\nwere a plain mapped class.\n\nBelow illustrates a :func:`_orm.relationship` with a simple join from ``A`` to\n``B``, however the primaryjoin condition is augmented with two additional\nentities ``C`` and ``D``, which also must have rows that line up with\nthe rows in both ``A`` and ``B`` simultaneously::\n\n    class A(Base):\n        __tablename__ = "a"\n\n        id = mapped_column(Integer, primary_key=True)\n        b_id = mapped_column(ForeignKey("b.id"))\n\n\n    class B(Base):\n        __tablename__ = "b"\n\n        id = mapped_column(Integer, primary_key=True)\n\n\n    class C(Base):\n        __tablename__ = "c"\n\n        id = mapped_column(Integer, primary_key=True)\n        a_id = mapped_column(ForeignKey("a.id"))\n\n        some_c_value = mapped_column(String)\n\n\n    class D(Base):\n        __tablename__ = "d"\n\n        id = mapped_column(Integer, primary_key=True)\n        c_id = mapped_column(ForeignKey("c.id"))\n        b_id = mapped_column(ForeignKey("b.id"))\n\n        some_d_value = mapped_column(String)\n\n\n    # 1. set up the join() as a variable, so we can refer\n    # to it in the mapping multiple times.\n    j = join(B, D, D.b_id == B.id).join(C, C.id == D.c_id)\n\n    # 2. Create an AliasedClass to B\n    B_viacd = aliased(B, j, flat=True)\n\n    A.b = relationship(B_viacd, primaryjoin=A.b_id == j.c.b_id)\n\nWith the above mapping, a simple join looks like:\n\n.. sourcecode:: python+sql\n\n    sess.scalars(select(A).join(A.b)).all()\n\n    {execsql}SELECT a.id AS a_id, a.b_id AS a_b_id\n    FROM a JOIN (b JOIN d ON d.b_id = b.id JOIN c ON c.id = d.c_id) ON a.b_id = b.id\n\nIntegrating AliasedClass Mappings with Typing and Avoiding Early Mapper Configuration\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe creation of the :func:`_orm.aliased` construct against a mapped class\nforces the :func:`_orm.configure_mappers` step to proceed, which will resolve\nall current classes and their relationships.  This may be problematic if\nunrelated mapped classes needed by the current mappings have not yet been\ndeclared, or if the configuration of the relationship itself needs access\nto as-yet undeclared classes.  Additionally, SQLAlchemy\'s Declarative pattern\nworks with Python typing most effectively when relationships are declared\nup front.\n\nTo organize the construction of the relationship to work with these issues, a\nconfigure level event hook like :meth:`.MapperEvents.before_mapper_configured`\nmay be used, which will invoke the configuration code only when all mappings\nare ready for configuration::\n\n    from sqlalchemy import event\n\n\n    class A(Base):\n        __tablename__ = "a"\n\n        id = mapped_column(Integer, primary_key=True)\n        b_id = mapped_column(ForeignKey("b.id"))\n\n\n    @event.listens_for(A, "before_mapper_configured")\n    def _configure_ab_relationship(mapper, cls):\n        # do the above configuration in a configuration hook\n\n        j = join(B, D, D.b_id == B.id).join(C, C.id == D.c_id)\n        B_viacd = aliased(B, j, flat=True)\n        A.b = relationship(B_viacd, primaryjoin=A.b_id == j.c.b_id)\n\nAbove, the function ``_configure_ab_relationship()`` will be invoked only\nwhen a fully configured version of ``A`` is requested, at which point the\nclasses ``B``, ``D`` and ``C`` would be available.\n\nFor an approach that integrates with inline typing, a similar technique can be\nused to effectively generate a "singleton" creation pattern for the aliased\nclass where it is late-initialized as a global variable, which can then be used\nin the relationship inline::\n\n    from typing import Any\n\n    B_viacd: Any = None\n    b_viacd_join: Any = None\n\n\n    class A(Base):\n        __tablename__ = "a"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        b_id: Mapped[int] = mapped_column(ForeignKey("b.id"))\n\n        # 1. the relationship can be declared using lambdas, allowing it to resolve\n        #    to targets that are late-configured\n        b: Mapped[B] = relationship(\n            lambda: B_viacd, primaryjoin=lambda: A.b_id == b_viacd_join.c.b_id\n        )\n\n\n    # 2. configure the targets of the relationship using a before_mapper_configured\n    #    hook.\n    @event.listens_for(A, "before_mapper_configured")\n    def _configure_ab_relationship(mapper, cls):\n        # 3. set up the join() and AliasedClass as globals from within\n        #    the configuration hook.\n\n        global B_viacd, b_viacd_join\n\n        b_viacd_join = join(B, D, D.b_id == B.id).join(C, C.id == D.c_id)\n        B_viacd = aliased(B, b_viacd_join, flat=True)\n\nUsing the AliasedClass target in Queries\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nIn the previous example, the ``A.b`` relationship refers to the ``B_viacd``\nentity as the target, and **not** the ``B`` class directly. To add additional\ncriteria involving the ``A.b`` relationship, it\'s typically necessary to\nreference the ``B_viacd`` directly rather than using ``B``, especially in a\ncase where the target entity of ``A.b`` is to be transformed into an alias or a\nsubquery. Below illustrates the same relationship using a subquery, rather than\na join::\n\n    subq = select(B).join(D, D.b_id == B.id).join(C, C.id == D.c_id).subquery()\n\n    B_viacd_subquery = aliased(B, subq)\n\n    A.b = relationship(B_viacd_subquery, primaryjoin=A.b_id == subq.c.id)\n\nA query using the above ``A.b`` relationship will render a subquery:\n\n.. sourcecode:: python+sql\n\n    sess.scalars(select(A).join(A.b)).all()\n\n    {execsql}SELECT a.id AS a_id, a.b_id AS a_b_id\n    FROM a JOIN (SELECT b.id AS id, b.some_b_column AS some_b_column\n    FROM b JOIN d ON d.b_id = b.id JOIN c ON c.id = d.c_id) AS anon_1 ON a.b_id = anon_1.id\n\nIf we want to add additional criteria based on the ``A.b`` join, we must do\nso in terms of ``B_viacd_subquery`` rather than ``B`` directly:\n\n.. sourcecode:: python+sql\n\n    sess.scalars(\n        select(A)\n        .join(A.b)\n        .where(B_viacd_subquery.some_b_column == "some b")\n        .order_by(B_viacd_subquery.id)\n    ).all()\n\n    {execsql}SELECT a.id AS a_id, a.b_id AS a_b_id\n    FROM a JOIN (SELECT b.id AS id, b.some_b_column AS some_b_column\n    FROM b JOIN d ON d.b_id = b.id JOIN c ON c.id = d.c_id) AS anon_1 ON a.b_id = anon_1.id\n    WHERE anon_1.some_b_column = ? ORDER BY anon_1.id\n\n.. _relationship_to_window_function:\n\nRow-Limited Relationships with Window Functions\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nAnother interesting use case for relationships to :class:`.AliasedClass`\nobjects are situations where\nthe relationship needs to join to a specialized SELECT of any form.   One\nscenario is when the use of a window function is desired, such as to limit\nhow many rows should be returned for a relationship.  The example below\nillustrates a non-primary mapper relationship that will load the first\nten items for each collection::\n\n    class A(Base):\n        __tablename__ = "a"\n\n        id = mapped_column(Integer, primary_key=True)\n\n\n    class B(Base):\n        __tablename__ = "b"\n        id = mapped_column(Integer, primary_key=True)\n        a_id = mapped_column(ForeignKey("a.id"))\n\n\n    partition = select(\n        B, func.row_number().over(order_by=B.id, partition_by=B.a_id).label("index")\n    ).alias()\n\n    partitioned_b = aliased(B, partition)\n\n    A.partitioned_bs = relationship(\n        partitioned_b, primaryjoin=and_(partitioned_b.a_id == A.id, partition.c.index < 10)\n    )\n\nWe can use the above ``partitioned_bs`` relationship with most of the loader\nstrategies, such as :func:`.selectinload`::\n\n    for a1 in session.scalars(select(A).options(selectinload(A.partitioned_bs))):\n        print(a1.partitioned_bs)  # <-- will be no more than ten objects\n\nWhere above, the "selectinload" query looks like:\n\n.. sourcecode:: sql\n\n    SELECT\n        a_1.id AS a_1_id, anon_1.id AS anon_1_id, anon_1.a_id AS anon_1_a_id,\n        anon_1.data AS anon_1_data, anon_1.index AS anon_1_index\n    FROM a AS a_1\n    JOIN (\n        SELECT b.id AS id, b.a_id AS a_id, b.data AS data,\n        row_number() OVER (PARTITION BY b.a_id ORDER BY b.id) AS index\n        FROM b) AS anon_1\n    ON anon_1.a_id = a_1.id AND anon_1.index < %(index_1)s\n    WHERE a_1.id IN ( ... primary key collection ...)\n    ORDER BY a_1.id\n\nAbove, for each matching primary key in "a", we will get the first ten\n"bs" as ordered by "b.id".   By partitioning on "a_id" we ensure that each\n"row number" is local to the parent "a_id".\n\nSuch a mapping would ordinarily also include a "plain" relationship\nfrom "A" to "B", for persistence operations as well as when the full\nset of "B" objects per "A" is desired.\n\n.. _query_enabled_properties:\n\nBuilding Query-Enabled Properties\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nVery ambitious custom join conditions may fail to be directly persistable, and\nin some cases may not even load correctly. To remove the persistence part of\nthe equation, use the flag :paramref:`_orm.relationship.viewonly` on the\n:func:`~sqlalchemy.orm.relationship`, which establishes it as a read-only\nattribute (data written to the collection will be ignored on flush()).\nHowever, in extreme cases, consider using a regular Python property in\nconjunction with :class:`_query.Query` as follows:\n\n.. sourcecode:: python\n\n    class User(Base):\n        __tablename__ = "user"\n        id = mapped_column(Integer, primary_key=True)\n\n        @property\n        def addresses(self):\n            # query using any kind of filter() criteria\n            return (\n                object_session(self)\n                .query(Address)\n                .filter(Address.user_id == self.id)\n                .filter(...)\n                .all()\n            )\n\nIn other cases, the descriptor can be built to make use of existing in-Python\ndata.  See the section on :ref:`mapper_hybrids` for more general discussion\nof special Python attributes.\n\n.. seealso::\n\n    :ref:`mapper_hybrids`\n\n.. _relationship_viewonly_notes:\n\nNotes on using the viewonly relationship parameter\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\nThe :paramref:`_orm.relationship.viewonly` parameter when applied to a\n:func:`_orm.relationship` construct indicates that this :func:`_orm.relationship`\nwill not take part in any ORM :term:`unit of work` operations, and additionally\nthat the attribute does not expect to participate within in-Python mutations\nof its represented collection.  This means\nthat while the viewonly relationship may refer to a mutable Python collection\nlike a list or set, making changes to that list or set as present on a\nmapped instance will have **no effect** on the ORM flush process.\n\nTo explore this scenario consider this mapping::\n\n    from __future__ import annotations\n\n    import datetime\n\n    from sqlalchemy import and_\n    from sqlalchemy import ForeignKey\n    from sqlalchemy import func\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Mapped\n    from sqlalchemy.orm import mapped_column\n    from sqlalchemy.orm import relationship\n\n\n    class Base(DeclarativeBase):\n        pass\n\n\n    class User(Base):\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        name: Mapped[str | None]\n\n        all_tasks: Mapped[list[Task]] = relationship()\n\n        current_week_tasks: Mapped[list[Task]] = relationship(\n            primaryjoin=lambda: and_(\n                User.id == Task.user_account_id,\n                # this expression works on PostgreSQL but may not be supported\n                # by other database engines\n                Task.task_date >= func.now() - datetime.timedelta(days=7),\n            ),\n            viewonly=True,\n        )\n\n\n    class Task(Base):\n        __tablename__ = "task"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        user_account_id: Mapped[int] = mapped_column(ForeignKey("user_account.id"))\n        description: Mapped[str | None]\n        task_date: Mapped[datetime.datetime] = mapped_column(server_default=func.now())\n\n        user: Mapped[User] = relationship(back_populates="current_week_tasks")\n\nThe following sections will note different aspects of this configuration.\n\nIn-Python mutations including backrefs are not appropriate with viewonly=True\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nThe above mapping targets the ``User.current_week_tasks`` viewonly relationship\nas the :term:`backref` target of the ``Task.user`` attribute.  This is not\ncurrently flagged by SQLAlchemy\'s ORM configuration process, however is a\nconfiguration error.   Changing the ``.user`` attribute on a ``Task`` will not\naffect the ``.current_week_tasks`` attribute::\n\n    >>> u1 = User()\n    >>> t1 = Task(task_date=datetime.datetime.now())\n    >>> t1.user = u1\n    >>> u1.current_week_tasks\n    []\n\nThere is another parameter called :paramref:`_orm.relationship.sync_backrefs`\nwhich can be turned on here to allow ``.current_week_tasks`` to be mutated in this\ncase, however this is not considered to be a best practice with a viewonly\nrelationship, which instead should not be relied upon for in-Python mutations.\n\nIn this mapping, backrefs can be configured between ``User.all_tasks`` and\n``Task.user``, as these are both not viewonly and will synchronize normally.\n\nBeyond the issue of backref mutations being disabled for viewonly relationships,\nplain changes to the ``User.all_tasks`` collection in Python\nare also not reflected in the ``User.current_week_tasks`` collection until\nchanges have been flushed to the database.\n\nOverall, for a use case where a custom collection should respond immediately to\nin-Python mutations, the viewonly relationship is generally not appropriate.  A\nbetter approach is to use the :ref:`hybrids_toplevel` feature of SQLAlchemy, or\nfor instance-only cases to use a Python ``@property``, where a user-defined\ncollection that is generated in terms of the current Python instance can be\nimplemented.  To change our example to work this way, we repair the\n:paramref:`_orm.relationship.back_populates` parameter on ``Task.user`` to\nreference ``User.all_tasks``, and\nthen illustrate a simple ``@property`` that will deliver results in terms of\nthe immediate ``User.all_tasks`` collection::\n\n    class User(Base):\n        __tablename__ = "user_account"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        name: Mapped[str | None]\n\n        all_tasks: Mapped[list[Task]] = relationship(back_populates="user")\n\n        @property\n        def current_week_tasks(self) -> list[Task]:\n            past_seven_days = datetime.datetime.now() - datetime.timedelta(days=7)\n            return [t for t in self.all_tasks if t.task_date >= past_seven_days]\n\n\n    class Task(Base):\n        __tablename__ = "task"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        user_account_id: Mapped[int] = mapped_column(ForeignKey("user_account.id"))\n        description: Mapped[str | None]\n        task_date: Mapped[datetime.datetime] = mapped_column(server_default=func.now())\n\n        user: Mapped[User] = relationship(back_populates="all_tasks")\n\nUsing an in-Python collection calculated on the fly each time, we are guaranteed\nto have the correct answer at all times, without the need to use a database\nat all::\n\n    >>> u1 = User()\n    >>> t1 = Task(task_date=datetime.datetime.now())\n    >>> t1.user = u1\n    >>> u1.current_week_tasks\n    [<__main__.Task object at 0x7f3d699523c0>]\n\n\nviewonly=True collections / attributes do not get re-queried until expired\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nContinuing with the original viewonly attribute, if we do in fact make changes\nto the ``User.all_tasks`` collection on a :term:`persistent` object, the\nviewonly collection can only show the net result of this change after **two**\nthings occur.  The first is that the change to ``User.all_tasks`` is\n:term:`flushed`, so that the new data is available in the database, at least\nwithin the scope of the local transaction.  The second is that the ``User.current_week_tasks``\nattribute is :term:`expired` and reloaded via a new SQL query to the database.\n\nTo support this requirement, the simplest flow to use is one where the\n**viewonly relationship is consumed only in operations that are primarily read\nonly to start with**.   Such as below, if we retrieve a ``User`` fresh from\nthe database, the collection will be current::\n\n    >>> with Session(e) as sess:\n    ...     u1 = sess.scalar(select(User).where(User.id == 1))\n    ...     print(u1.current_week_tasks)\n    [<__main__.Task object at 0x7f8711b906b0>]\n\n\nWhen we make modifications to ``u1.all_tasks``, if we want to see these changes\nreflected in the ``u1.current_week_tasks`` viewonly relationship, these changes need to be flushed\nand the ``u1.current_week_tasks`` attribute needs to be expired, so that\nit will :term:`lazy load` on next access.  The simplest approach to this is\nto use :meth:`_orm.Session.commit`, keeping the :paramref:`_orm.Session.expire_on_commit`\nparameter set at its default of ``True``::\n\n    >>> with Session(e) as sess:\n    ...     u1 = sess.scalar(select(User).where(User.id == 1))\n    ...     u1.all_tasks.append(Task(task_date=datetime.datetime.now()))\n    ...     sess.commit()\n    ...     print(u1.current_week_tasks)\n    [<__main__.Task object at 0x7f8711b90ec0>, <__main__.Task object at 0x7f8711b90a10>]\n\nAbove, the call to :meth:`_orm.Session.commit` flushed the changes to ``u1.all_tasks``\nto the database, then expired all objects, so that when we accessed ``u1.current_week_tasks``,\na :term:` lazy load` occurred which fetched the contents for this attribute\nfreshly from the database.\n\nTo intercept operations without actually committing the transaction,\nthe attribute needs to be explicitly :term:`expired`\nfirst.   A simplistic way to do this is to just call it directly.  In\nthe example below, :meth:`_orm.Session.flush` sends pending changes to the\ndatabase, then :meth:`_orm.Session.expire` is used to expire the ``u1.current_week_tasks``\ncollection so that it re-fetches on next access::\n\n    >>> with Session(e) as sess:\n    ...     u1 = sess.scalar(select(User).where(User.id == 1))\n    ...     u1.all_tasks.append(Task(task_date=datetime.datetime.now()))\n    ...     sess.flush()\n    ...     sess.expire(u1, ["current_week_tasks"])\n    ...     print(u1.current_week_tasks)\n    [<__main__.Task object at 0x7fd95a4c8c50>, <__main__.Task object at 0x7fd95a4c8c80>]\n\nWe can in fact skip the call to :meth:`_orm.Session.flush`, assuming a\n:class:`_orm.Session` that keeps :paramref:`_orm.Session.autoflush` at its\ndefault value of ``True``, as the expired ``current_week_tasks`` attribute will\ntrigger autoflush when accessed after expiration::\n\n    >>> with Session(e) as sess:\n    ...     u1 = sess.scalar(select(User).where(User.id == 1))\n    ...     u1.all_tasks.append(Task(task_date=datetime.datetime.now()))\n    ...     sess.expire(u1, ["current_week_tasks"])\n    ...     print(u1.current_week_tasks)  # triggers autoflush before querying\n    [<__main__.Task object at 0x7fd95a4c8c50>, <__main__.Task object at 0x7fd95a4c8c80>]\n\nContinuing with the above approach to something more elaborate, we can apply\nthe expiration programmatically when the related ``User.all_tasks`` collection\nchanges, using :ref:`event hooks <event_toplevel>`.   This an **advanced\ntechnique**, where simpler architectures like ``@property`` or sticking to\nread-only use cases should be examined first.  In our simple example, this\nwould be configured as::\n\n    from sqlalchemy import event, inspect\n\n\n    @event.listens_for(User.all_tasks, "append")\n    @event.listens_for(User.all_tasks, "remove")\n    @event.listens_for(User.all_tasks, "bulk_replace")\n    def _expire_User_current_week_tasks(target, value, initiator):\n        inspect(target).session.expire(target, ["current_week_tasks"])\n\nWith the above hooks, mutation operations are intercepted and result in\nthe ``User.current_week_tasks`` collection to be expired automatically::\n\n    >>> with Session(e) as sess:\n    ...     u1 = sess.scalar(select(User).where(User.id == 1))\n    ...     u1.all_tasks.append(Task(task_date=datetime.datetime.now()))\n    ...     print(u1.current_week_tasks)\n    [<__main__.Task object at 0x7f66d093ccb0>, <__main__.Task object at 0x7f66d093cce0>]\n\nThe :class:`_orm.AttributeEvents` event hooks used above are also triggered\nby backref mutations, so with the above hooks a change to ``Task.user`` is\nalso intercepted::\n\n    >>> with Session(e) as sess:\n    ...     u1 = sess.scalar(select(User).where(User.id == 1))\n    ...     t1 = Task(task_date=datetime.datetime.now())\n    ...     t1.user = u1\n    ...     sess.add(t1)\n    ...     print(u1.current_week_tasks)\n    [<__main__.Task object at 0x7f3b0c070d10>, <__main__.Task object at 0x7f3b0c057d10>]\n\n',
            'doc/build/orm/persistence_techniques.rst': '=================================\nAdditional Persistence Techniques\n=================================\n\n\n\n.. _flush_embedded_sql_expressions:\n\nEmbedding SQL Insert/Update Expressions into a Flush\n====================================================\n\nThis feature allows the value of a database column to be set to a SQL\nexpression instead of a literal value. It\'s especially useful for atomic\nupdates, calling stored procedures, etc. All you do is assign an expression to\nan attribute::\n\n    class SomeClass(Base):\n        __tablename__ = "some_table"\n\n        # ...\n\n        value = mapped_column(Integer)\n\n\n    someobject = session.get(SomeClass, 5)\n\n    # set \'value\' attribute to a SQL expression adding one\n    someobject.value = SomeClass.value + 1\n\n    # issues "UPDATE some_table SET value=value+1"\n    session.commit()\n\nThis technique works both for INSERT and UPDATE statements. After the\nflush/commit operation, the ``value`` attribute on ``someobject`` above is\nexpired, so that when next accessed the newly generated value will be loaded\nfrom the database.\n\nThe feature also has conditional support to work in conjunction with\nprimary key columns.  For backends that have RETURNING support\n(including Oracle Database, SQL Server, MariaDB 10.5, SQLite 3.35) a\nSQL expression may be assigned to a primary key column as well.  This allows\nboth the SQL expression to be evaluated, as well as allows any server side\ntriggers that modify the primary key value on INSERT, to be successfully\nretrieved by the ORM as part of the object\'s primary key::\n\n\n    class Foo(Base):\n        __tablename__ = "foo"\n        pk = mapped_column(Integer, primary_key=True)\n        bar = mapped_column(Integer)\n\n\n    e = create_engine("postgresql+psycopg2://scott:tiger@localhost/test", echo=True)\n    Base.metadata.create_all(e)\n\n    session = Session(e)\n\n    foo = Foo(pk=sql.select(sql.func.coalesce(sql.func.max(Foo.pk) + 1, 1)))\n    session.add(foo)\n    session.commit()\n\nOn PostgreSQL, the above :class:`.Session` will emit the following INSERT:\n\n.. sourcecode:: sql\n\n    INSERT INTO foo (foopk, bar) VALUES\n    ((SELECT coalesce(max(foo.foopk) + %(max_1)s, %(coalesce_2)s) AS coalesce_1\n    FROM foo), %(bar)s) RETURNING foo.foopk\n\n.. _session_sql_expressions:\n\nUsing SQL Expressions with Sessions\n===================================\n\nSQL expressions and strings can be executed via the\n:class:`~sqlalchemy.orm.session.Session` within its transactional context.\nThis is most easily accomplished using the\n:meth:`~.Session.execute` method, which returns a\n:class:`~sqlalchemy.engine.CursorResult` in the same manner as an\n:class:`~sqlalchemy.engine.Engine` or\n:class:`~sqlalchemy.engine.Connection`::\n\n    Session = sessionmaker(bind=engine)\n    session = Session()\n\n    # execute a string statement\n    result = session.execute(text("select * from table where id=:id"), {"id": 7})\n\n    # execute a SQL expression construct\n    result = session.execute(select(mytable).where(mytable.c.id == 7))\n\nThe current :class:`~sqlalchemy.engine.Connection` held by the\n:class:`~sqlalchemy.orm.session.Session` is accessible using the\n:meth:`~.Session.connection` method::\n\n    connection = session.connection()\n\nThe examples above deal with a :class:`_orm.Session` that\'s\nbound to a single :class:`_engine.Engine` or\n:class:`_engine.Connection`. To execute statements using a\n:class:`_orm.Session` which is bound either to multiple\nengines, or none at all (i.e. relies upon bound metadata), both\n:meth:`_orm.Session.execute` and\n:meth:`_orm.Session.connection` accept a dictionary of bind arguments\n:paramref:`_orm.Session.execute.bind_arguments` which may include "mapper"\nwhich is passed a mapped class or\n:class:`_orm.Mapper` instance, which is used to locate the\nproper context for the desired engine::\n\n    Session = sessionmaker()\n    session = Session()\n\n    # need to specify mapper or class when executing\n    result = session.execute(\n        text("select * from table where id=:id"),\n        {"id": 7},\n        bind_arguments={"mapper": MyMappedClass},\n    )\n\n    result = session.execute(\n        select(mytable).where(mytable.c.id == 7), bind_arguments={"mapper": MyMappedClass}\n    )\n\n    connection = session.connection(MyMappedClass)\n\n.. versionchanged:: 1.4 the ``mapper`` and ``clause`` arguments to\n   :meth:`_orm.Session.execute` are now passed as part of a dictionary\n   sent as the :paramref:`_orm.Session.execute.bind_arguments` parameter.\n   The previous arguments are still accepted however this usage is\n   deprecated.\n\n.. _session_forcing_null:\n\nForcing NULL on a column with a default\n=======================================\n\nThe ORM considers any attribute that was never set on an object as a\n"default" case; the attribute will be omitted from the INSERT statement::\n\n    class MyObject(Base):\n        __tablename__ = "my_table"\n        id = mapped_column(Integer, primary_key=True)\n        data = mapped_column(String(50), nullable=True)\n\n\n    obj = MyObject(id=1)\n    session.add(obj)\n    session.commit()  # INSERT with the \'data\' column omitted; the database\n    # itself will persist this as the NULL value\n\nOmitting a column from the INSERT means that the column will\nhave the NULL value set, *unless* the column has a default set up,\nin which case the default value will be persisted.   This holds true\nboth from a pure SQL perspective with server-side defaults, as well as the\nbehavior of SQLAlchemy\'s insert behavior with both client-side and server-side\ndefaults::\n\n    class MyObject(Base):\n        __tablename__ = "my_table"\n        id = mapped_column(Integer, primary_key=True)\n        data = mapped_column(String(50), nullable=True, server_default="default")\n\n\n    obj = MyObject(id=1)\n    session.add(obj)\n    session.commit()  # INSERT with the \'data\' column omitted; the database\n    # itself will persist this as the value \'default\'\n\nHowever, in the ORM, even if one assigns the Python value ``None`` explicitly\nto the object, this is treated the **same** as though the value were never\nassigned::\n\n    class MyObject(Base):\n        __tablename__ = "my_table"\n        id = mapped_column(Integer, primary_key=True)\n        data = mapped_column(String(50), nullable=True, server_default="default")\n\n\n    obj = MyObject(id=1, data=None)\n    session.add(obj)\n    session.commit()  # INSERT with the \'data\' column explicitly set to None;\n    # the ORM still omits it from the statement and the\n    # database will still persist this as the value \'default\'\n\nThe above operation will persist into the ``data`` column the\nserver default value of ``"default"`` and not SQL NULL, even though ``None``\nwas passed; this is a long-standing behavior of the ORM that many applications\nhold as an assumption.\n\nSo what if we want to actually put NULL into this column, even though the\ncolumn has a default value?  There are two approaches.  One is that\non a per-instance level, we assign the attribute using the\n:obj:`_expression.null` SQL construct::\n\n    from sqlalchemy import null\n\n    obj = MyObject(id=1, data=null())\n    session.add(obj)\n    session.commit()  # INSERT with the \'data\' column explicitly set as null();\n    # the ORM uses this directly, bypassing all client-\n    # and server-side defaults, and the database will\n    # persist this as the NULL value\n\nThe :obj:`_expression.null` SQL construct always translates into the SQL\nNULL value being directly present in the target INSERT statement.\n\nIf we\'d like to be able to use the Python value ``None`` and have this\nalso be persisted as NULL despite the presence of column defaults,\nwe can configure this for the ORM using a Core-level modifier\n:meth:`.TypeEngine.evaluates_none`, which indicates\na type where the ORM should treat the value ``None`` the same as any other\nvalue and pass it through, rather than omitting it as a "missing" value::\n\n    class MyObject(Base):\n        __tablename__ = "my_table"\n        id = mapped_column(Integer, primary_key=True)\n        data = mapped_column(\n            String(50).evaluates_none(),  # indicate that None should always be passed\n            nullable=True,\n            server_default="default",\n        )\n\n\n    obj = MyObject(id=1, data=None)\n    session.add(obj)\n    session.commit()  # INSERT with the \'data\' column explicitly set to None;\n    # the ORM uses this directly, bypassing all client-\n    # and server-side defaults, and the database will\n    # persist this as the NULL value\n\n.. topic:: Evaluating None\n\n  The :meth:`.TypeEngine.evaluates_none` modifier is primarily intended to\n  signal a type where the Python value "None" is significant, the primary\n  example being a JSON type which may want to persist the JSON ``null`` value\n  rather than SQL NULL.  We are slightly repurposing it here in order to\n  signal to the ORM that we\'d like ``None`` to be passed into the type whenever\n  present, even though no special type-level behaviors are assigned to it.\n\n.. _orm_server_defaults:\n\nFetching Server-Generated Defaults\n===================================\n\nAs introduced in the sections :ref:`server_defaults` and :ref:`triggered_columns`,\nthe Core supports the notion of database columns for which the database\nitself generates a value upon INSERT and in less common cases upon UPDATE\nstatements.  The ORM features support for such columns regarding being\nable to fetch these newly generated values upon flush.   This behavior is\nrequired in the case of primary key columns that are generated by the server,\nsince the ORM has to know the primary key of an object once it is persisted.\n\nIn the vast majority of cases, primary key columns that have their value\ngenerated automatically by the database are  simple integer columns, which are\nimplemented by the database as either a so-called "autoincrement" column, or\nfrom a sequence associated with the column.   Every database dialect within\nSQLAlchemy Core supports a method of retrieving these primary key values which\nis often native to the Python DBAPI, and in general this process is automatic.\nThere is more documentation regarding this at\n:paramref:`_schema.Column.autoincrement`.\n\nFor server-generating columns that are not primary key columns or that are not\nsimple autoincrementing integer columns, the ORM requires that these columns\nare marked with an appropriate ``server_default`` directive that allows the ORM to\nretrieve this value.   Not all methods are supported on all backends, however,\nso care must be taken to use the appropriate method. The two questions to be\nanswered are, 1. is this column part of the primary key or not, and 2. does the\ndatabase support RETURNING or an equivalent, such as "OUTPUT inserted"; these\nare SQL phrases which return a server-generated value at the same time as the\nINSERT or UPDATE statement is invoked.   RETURNING is currently supported\nby PostgreSQL, Oracle Database, MariaDB 10.5, SQLite 3.35, and SQL Server.\n\nCase 1: non primary key, RETURNING or equivalent is supported\n-------------------------------------------------------------\n\nIn this case, columns should be marked as :class:`.FetchedValue` or with an\nexplicit :paramref:`_schema.Column.server_default`.   The ORM will\nautomatically add these columns to the RETURNING clause when performing\nINSERT statements, assuming the\n:paramref:`_orm.Mapper.eager_defaults` parameter is set to ``True``, or\nif left at its default setting of ``"auto"``, for dialects that support\nboth RETURNING as well as :ref:`insertmanyvalues <engine_insertmanyvalues>`::\n\n\n    class MyModel(Base):\n        __tablename__ = "my_table"\n\n        id = mapped_column(Integer, primary_key=True)\n\n        # server-side SQL date function generates a new timestamp\n        timestamp = mapped_column(DateTime(), server_default=func.now())\n\n        # some other server-side function not named here, such as a trigger,\n        # populates a value into this column during INSERT\n        special_identifier = mapped_column(String(50), server_default=FetchedValue())\n\n        # set eager defaults to True.  This is usually optional, as if the\n        # backend supports RETURNING + insertmanyvalues, eager defaults\n        # will take place regardless on INSERT\n        __mapper_args__ = {"eager_defaults": True}\n\nAbove, an INSERT statement that does not specify explicit values for\n"timestamp" or "special_identifier" from the client side will include the\n"timestamp" and "special_identifier" columns within the RETURNING clause so\nthey are available immediately. On the PostgreSQL database, an INSERT for the\nabove table will look like:\n\n.. sourcecode:: sql\n\n   INSERT INTO my_table DEFAULT VALUES RETURNING my_table.id, my_table.timestamp, my_table.special_identifier\n\n.. versionchanged:: 2.0.0rc1 The :paramref:`_orm.Mapper.eager_defaults` parameter now defaults\n   to a new setting ``"auto"``, which will automatically make use of RETURNING\n   to fetch server-generated default values on INSERT if the backing database\n   supports both RETURNING as well as :ref:`insertmanyvalues <engine_insertmanyvalues>`.\n\n.. note:: The ``"auto"`` value for :paramref:`_orm.Mapper.eager_defaults` only\n   applies to INSERT statements.  UPDATE statements will not use RETURNING,\n   even if available, unless :paramref:`_orm.Mapper.eager_defaults` is set to\n   ``True``.  This is because there is no equivalent "insertmanyvalues" feature\n   for UPDATE, so UPDATE RETURNING will require that UPDATE statements are\n   emitted individually for each row being UPDATEd.\n\nCase 2: Table includes trigger-generated values which are not compatible with RETURNING\n----------------------------------------------------------------------------------------\n\nThe ``"auto"`` setting of :paramref:`_orm.Mapper.eager_defaults` means that\na backend that supports RETURNING will usually make use of RETURNING with\nINSERT statements in order to retrieve newly generated default values.\nHowever there are limitations of server-generated values that are generated\nusing triggers, such that RETURNING can\'t be used:\n\n* SQL Server does not allow RETURNING to be used in an INSERT statement\n  to retrieve a trigger-generated value; the statement will fail.\n\n* SQLite has limitations in combining the use of RETURNING with triggers, such\n  that the RETURNING clause will not have the INSERTed value available\n\n* Other backends may have limitations with RETURNING in conjunction with\n  triggers, or other kinds of server-generated values.\n\nTo disable the use of RETURNING for such values, including not just for\nserver generated default values but also to ensure that the ORM will never\nuse RETURNING with a particular table, specify\n:paramref:`_schema.Table.implicit_returning`\nas ``False`` for the mapped :class:`.Table`.  Using a Declarative mapping\nthis looks like::\n\n    class MyModel(Base):\n        __tablename__ = "my_table"\n\n        id: Mapped[int] = mapped_column(primary_key=True)\n        data: Mapped[str] = mapped_column(String(50))\n\n        # assume a database trigger populates a value into this column\n        # during INSERT\n        special_identifier = mapped_column(String(50), server_default=FetchedValue())\n\n        # disable all use of RETURNING for the table\n        __table_args__ = {"implicit_returning": False}\n\nOn SQL Server with the pyodbc driver, an INSERT for the above table will\nnot use RETURNING and will use the SQL Server ``scope_identity()`` function\nto retrieve the newly generated primary key value:\n\n.. sourcecode:: sql\n\n    INSERT INTO my_table (data) VALUES (?); select scope_identity()\n\n.. seealso::\n\n    :ref:`mssql_insert_behavior` - background on the SQL Server dialect\'s\n    methods of fetching newly generated primary key values\n\nCase 3: non primary key, RETURNING or equivalent is not supported or not needed\n--------------------------------------------------------------------------------\n\nThis case is the same as case 1 above, except we typically don\'t want to\nuse :paramref:`.orm.Mapper.eager_defaults`, as its current implementation\nin the absence of RETURNING support is to emit a SELECT-per-row, which\nis not performant.  Therefore the parameter is omitted in the mapping below::\n\n    class MyModel(Base):\n        __tablename__ = "my_table"\n\n        id = mapped_column(Integer, primary_key=True)\n        timestamp = mapped_column(DateTime(), server_default=func.now())\n\n        # assume a database trigger populates a value into this column\n        # during INSERT\n        special_identifier = mapped_column(String(50), server_default=FetchedValue())\n\nAfter a record with the above mapping is INSERTed on a backend that does not\ninclude RETURNING or "insertmanyvalues" support, the "timestamp" and\n"special_identifier" columns will remain empty, and will be fetched via a\nsecond SELECT statement when they are first accessed after the flush, e.g. they\nare marked as "expired".\n\nIf the :paramref:`.orm.Mapper.eager_defaults` is explicitly provided with a\nvalue of ``True``, and the backend database does not support RETURNING or an\nequivalent, the ORM will emit a SELECT statement immediately following the\nINSERT statement in order to fetch newly generated values; the ORM does not\ncurrently have the ability to SELECT many newly inserted rows in batch if\nRETURNING was not available. This is usually undesirable as it adds additional\nSELECT statements to the flush process that may not be needed. Using the above\nmapping with the :paramref:`.orm.Mapper.eager_defaults` flag set to True\nagainst MySQL (not MariaDB) results in SQL like this upon flush:\n\n.. sourcecode:: sql\n\n    INSERT INTO my_table () VALUES ()\n\n    -- when eager_defaults **is** used, but RETURNING is not supported\n    SELECT my_table.timestamp AS my_table_timestamp, my_table.special_identifier AS my_table_special_identifier\n    FROM my_table WHERE my_table.id = %s\n\nA future release of SQLAlchemy may seek to improve the efficiency of\neager defaults in the abcense of RETURNING to batch many rows within a\nsingle SELECT statement.\n\nCase 4: primary key, RETURNING or equivalent is supported\n----------------------------------------------------------\n\nA primary key column with a server-generated value must be fetched immediately\nupon INSERT; the ORM can only access rows for which it has a primary key value,\nso if the primary key is generated by the server, the ORM needs a way\nto retrieve that new value immediately upon INSERT.\n\nAs mentioned above, for integer "autoincrement" columns, as well as\ncolumns marked with :class:`.Identity` and special constructs such as\nPostgreSQL SERIAL, these types are handled automatically by the Core; databases\ninclude functions for fetching the "last inserted id" where RETURNING\nis not supported, and where RETURNING is supported SQLAlchemy will use that.\n\nFor example, using Oracle Database with a column marked as :class:`.Identity`,\nRETURNING is used automatically to fetch the new primary key value::\n\n    class MyOracleModel(Base):\n        __tablename__ = "my_table"\n\n        id: Mapped[int] = mapped_column(Identity(), primary_key=True)\n        data: Mapped[str] = mapped_column(String(50))\n\nThe INSERT for a model as above on Oracle Database looks like:\n\n.. sourcecode:: sql\n\n    INSERT INTO my_table (data) VALUES (:data) RETURNING my_table.id INTO :ret_0\n\nSQLAlchemy renders an INSERT for the "data" field, but only includes "id" in\nthe RETURNING clause, so that server-side generation for "id" will take\nplace and the new value will be returned immediately.\n\nFor non-integer values generated by server side functions or triggers, as well\nas for integer values that come from constructs outside the table itself,\nincluding explicit sequences and triggers, the server default generation must\nbe marked in the table metadata. Using Oracle Database as the example again, we can\nillustrate a similar table as above naming an explicit sequence using the\n:class:`.Sequence` construct::\n\n    class MyOracleModel(Base):\n        __tablename__ = "my_table"\n\n        id: Mapped[int] = mapped_column(Sequence("my_oracle_seq"), primary_key=True)\n        data: Mapped[str] = mapped_column(String(50))\n\nAn INSERT for this version of the model on Oracle Database would look like:\n\n.. sourcecode:: sql\n\n    INSERT INTO my_table (id, data) VALUES (my_oracle_seq.nextval, :data) RETURNING my_table.id INTO :ret_0\n\nWhere above, SQLAlchemy renders ``my_sequence.nextval`` for the primary key\ncolumn so that it is used for new primary key generation, and also uses\nRETURNING to get the new value back immediately.\n\nIf the source of data is not represented by a simple SQL function or\n:class:`.Sequence`, such as when using triggers or database-specific datatypes\nthat produce new values, the presence of a value-generating default may be\nindicated by using :class:`.FetchedValue` within the column definition. Below\nis a model that uses a SQL Server TIMESTAMP column as the primary key; on SQL\nServer, this datatype generates new values automatically, so this is indicated\nin the table metadata by indicating :class:`.FetchedValue` for the\n:paramref:`.Column.server_default` parameter::\n\n    class MySQLServerModel(Base):\n        __tablename__ = "my_table"\n\n        timestamp: Mapped[datetime.datetime] = mapped_column(\n            TIMESTAMP(), server_default=FetchedValue(), primary_key=True\n        )\n        data: Mapped[str] = mapped_column(String(50))\n\nAn INSERT for the above table on SQL Server looks like:\n\n.. sourcecode:: sql\n\n    INSERT INTO my_table (data) OUTPUT inserted.timestamp VALUES (?)\n\nCase 5: primary key, RETURNING or equivalent is not supported\n--------------------------------------------------------------\n\nIn this area we are generating rows for a database such as MySQL\nwhere some means of generating a default is occurring on the server, but is\noutside of the database\'s usual autoincrement routine. In this case, we have to\nmake sure SQLAlchemy can "pre-execute" the default, which means it has to be an\nexplicit SQL expression.\n\n.. note::  This section will illustrate multiple recipes involving\n   datetime values for MySQL, since the datetime datatypes on this\n   backend has additional idiosyncratic requirements that are useful to\n   illustrate.  Keep in mind however that MySQL requires an explicit\n   "pre-executed" default generator for *any* auto-generated datatype used as\n   the primary key other than the usual single-column autoincrementing integer\n   value.\n\nMySQL with DateTime primary key\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nUsing the example of a :class:`.DateTime` column for MySQL, we add an explicit\npre-execute-supported default using the "NOW()" SQL function::\n\n    class MyModel(Base):\n        __tablename__ = "my_table"\n\n        timestamp = mapped_column(DateTime(), default=func.now(), primary_key=True)\n\nWhere above, we select the "NOW()" function to deliver a datetime value\nto the column.  The SQL generated by the above is:\n\n.. sourcecode:: sql\n\n    SELECT now() AS anon_1\n    INSERT INTO my_table (timestamp) VALUES (%s)\n    (\'2018-08-09 13:08:46\',)\n\nMySQL with TIMESTAMP primary key\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nWhen using the :class:`_types.TIMESTAMP` datatype with MySQL, MySQL ordinarily\nassociates a server-side default with this datatype automatically.  However\nwhen we use one as a primary key, the Core cannot retrieve the newly generated\nvalue unless we execute the function ourselves.  As :class:`_types.TIMESTAMP` on\nMySQL actually stores a binary value, we need to add an additional "CAST" to our\nusage of "NOW()" so that we retrieve a binary value that can be persisted\ninto the column::\n\n    from sqlalchemy import cast, Binary\n\n\n    class MyModel(Base):\n        __tablename__ = "my_table"\n\n        timestamp = mapped_column(\n            TIMESTAMP(), default=cast(func.now(), Binary), primary_key=True\n        )\n\nAbove, in addition to selecting the "NOW()" function, we additionally make\nuse of the :class:`.Binary` datatype in conjunction with :func:`.cast` so that\nthe returned value is binary.  SQL rendered from the above within an\nINSERT looks like:\n\n.. sourcecode:: sql\n\n    SELECT CAST(now() AS BINARY) AS anon_1\n    INSERT INTO my_table (timestamp) VALUES (%s)\n    (b\'2018-08-09 13:08:46\',)\n\n.. seealso::\n\n    :ref:`metadata_defaults_toplevel`\n\nNotes on eagerly fetching client invoked SQL expressions used for INSERT or UPDATE\n-----------------------------------------------------------------------------------\n\nThe preceding examples indicate the use of :paramref:`_schema.Column.server_default`\nto create tables that include default-generation functions within their\nDDL.\n\nSQLAlchemy also supports non-DDL server side defaults, as documented at\n:ref:`defaults_client_invoked_sql`; these "client invoked SQL expressions"\nare set up using the :paramref:`_schema.Column.default` and\n:paramref:`_schema.Column.onupdate` parameters.\n\nThese SQL expressions currently are subject to the same limitations within the\nORM as occurs for true server-side defaults; they won\'t be eagerly fetched with\nRETURNING when :paramref:`_orm.Mapper.eager_defaults` is set to ``"auto"`` or\n``True`` unless the :class:`.FetchedValue` directive is associated with the\n:class:`_schema.Column`, even though these expressions are not DDL server\ndefaults and are actively rendered by SQLAlchemy itself. This limitation may be\naddressed in future SQLAlchemy releases.\n\nThe :class:`.FetchedValue` construct can be applied to\n:paramref:`_schema.Column.server_default` or\n:paramref:`_schema.Column.server_onupdate` at the same time that a SQL\nexpression is used with :paramref:`_schema.Column.default` and\n:paramref:`_schema.Column.onupdate`, such as in the example below where the\n``func.now()`` construct is used as a client-invoked SQL expression\nfor :paramref:`_schema.Column.default` and\n:paramref:`_schema.Column.onupdate`.  In order for the behavior of\n:paramref:`_orm.Mapper.eager_defaults` to include that it fetches these\nvalues using RETURNING when available, :paramref:`_schema.Column.server_default` and\n:paramref:`_schema.Column.server_onupdate` are used with :class:`.FetchedValue`\nto ensure that the fetch occurs::\n\n    class MyModel(Base):\n        __tablename__ = "my_table"\n\n        id = mapped_column(Integer, primary_key=True)\n\n        created = mapped_column(\n            DateTime(), default=func.now(), server_default=FetchedValue()\n        )\n        updated = mapped_column(\n            DateTime(),\n            onupdate=func.now(),\n            server_default=FetchedValue(),\n            server_onupdate=FetchedValue(),\n        )\n\n        __mapper_args__ = {"eager_defaults": True}\n\nWith a mapping similar to the above, the SQL rendered by the ORM for\nINSERT and UPDATE will include ``created`` and ``updated`` in the RETURNING\nclause:\n\n.. sourcecode:: sql\n\n  INSERT INTO my_table (created) VALUES (now()) RETURNING my_table.id, my_table.created, my_table.updated\n\n  UPDATE my_table SET updated=now() WHERE my_table.id = %(my_table_id)s RETURNING my_table.updated\n\n\n\n.. _orm_dml_returning_objects:\n\n\nUsing INSERT, UPDATE and ON CONFLICT (i.e. upsert) to return ORM Objects\n==========================================================================\n\nSQLAlchemy 2.0 includes enhanced capabilities for emitting several varieties\nof ORM-enabled INSERT, UPDATE, and upsert statements.  See the\ndocument at :doc:`queryguide/dml` for documentation.  For upsert, see\n:ref:`orm_queryguide_upsert`.\n\nUsing PostgreSQL ON CONFLICT with RETURNING to return upserted ORM objects\n---------------------------------------------------------------------------\n\nThis section has moved to :ref:`orm_queryguide_upsert`.\n\n\n.. _session_partitioning:\n\nPartitioning Strategies (e.g. multiple database backends per Session)\n=====================================================================\n\nSimple Vertical Partitioning\n----------------------------\n\nVertical partitioning places different classes, class hierarchies,\nor mapped tables, across multiple databases, by configuring the\n:class:`.Session` with the :paramref:`.Session.binds` argument. This\nargument receives a dictionary that contains any combination of\nORM-mapped classes, arbitrary classes within a mapped hierarchy (such\nas declarative base classes or mixins), :class:`_schema.Table` objects,\nand :class:`_orm.Mapper` objects as keys, which then refer typically to\n:class:`_engine.Engine` or less typically :class:`_engine.Connection` objects as targets.\nThe dictionary is consulted whenever the :class:`.Session` needs to\nemit SQL on behalf of a particular kind of mapped class in order to locate\nthe appropriate source of database connectivity::\n\n    engine1 = create_engine("postgresql+psycopg2://db1")\n    engine2 = create_engine("postgresql+psycopg2://db2")\n\n    Session = sessionmaker()\n\n    # bind User operations to engine 1, Account operations to engine 2\n    Session.configure(binds={User: engine1, Account: engine2})\n\n    session = Session()\n\nAbove, SQL operations against either class will make usage of the :class:`_engine.Engine`\nlinked to that class.     The functionality is comprehensive across both\nread and write operations; a :class:`_query.Query` that is against entities\nmapped to ``engine1`` (determined by looking at the first entity in the\nlist of items requested) will make use of ``engine1`` to run the query.   A\nflush operation will make use of **both** engines on a per-class basis as it\nflushes objects of type ``User`` and ``Account``.\n\nIn the more common case, there are typically base or mixin classes that  can be\nused to distinguish between operations that are destined for different database\nconnections.  The :paramref:`.Session.binds` argument can accommodate any\narbitrary Python class as a key, which will be used if it is found to be in the\n``__mro__`` (Python method resolution order) for a particular  mapped class.\nSupposing two declarative bases are representing two different database\nconnections::\n\n    from sqlalchemy.orm import DeclarativeBase\n    from sqlalchemy.orm import Session\n\n\n    class BaseA(DeclarativeBase):\n        pass\n\n\n    class BaseB(DeclarativeBase):\n        pass\n\n\n    class User(BaseA): ...\n\n\n    class Address(BaseA): ...\n\n\n    class GameInfo(BaseB): ...\n\n\n    class GameStats(BaseB): ...\n\n\n    Session = sessionmaker()\n\n    # all User/Address operations will be on engine 1, all\n    # Game operations will be on engine 2\n    Session.configure(binds={BaseA: engine1, BaseB: engine2})\n\nAbove, classes which descend from ``BaseA`` and ``BaseB`` will have their\nSQL operations routed to one of two engines based on which superclass\nthey descend from, if any.   In the case of a class that descends from more\nthan one "bound" superclass, the superclass that is highest in the target\nclass\' hierarchy will be chosen to represent which engine should be used.\n\n.. seealso::\n\n    :paramref:`.Session.binds`\n\n\nCoordination of Transactions for a multiple-engine Session\n----------------------------------------------------------\n\nOne caveat to using multiple bound engines is in the case where a commit\noperation may fail on one backend after the commit has succeeded on another.\nThis is an inconsistency problem that in relational databases is solved\nusing a "two phase transaction", which adds an additional "prepare" step\nto the commit sequence that allows for multiple databases to agree to commit\nbefore actually completing the transaction.\n\nDue to limited support within DBAPIs,  SQLAlchemy has limited support for two-\nphase transactions across backends.  Most typically, it is known to work well\nwith the PostgreSQL backend and to  a lesser extent with the MySQL backend.\nHowever, the :class:`.Session` is fully capable of taking advantage of the two\nphase transaction feature when the backend supports it, by setting the\n:paramref:`.Session.use_twophase` flag within :class:`.sessionmaker` or\n:class:`.Session`.  See :ref:`session_twophase` for an example.\n\n\n.. _session_custom_partitioning:\n\nCustom Vertical Partitioning\n----------------------------\n\nMore comprehensive rule-based class-level partitioning can be built by\noverriding the :meth:`.Session.get_bind` method.   Below we illustrate\na custom :class:`.Session` which delivers the following rules:\n\n1. Flush operations, as well as bulk "update" and "delete" operations,\n   are delivered to the engine named ``leader``.\n\n2. Operations on objects that subclass ``MyOtherClass`` all\n   occur on the ``other`` engine.\n\n3. Read operations for all other classes occur on a random\n   choice of the ``follower1`` or ``follower2`` database.\n\n::\n\n    engines = {\n        "leader": create_engine("sqlite:///leader.db"),\n        "other": create_engine("sqlite:///other.db"),\n        "follower1": create_engine("sqlite:///follower1.db"),\n        "follower2": create_engine("sqlite:///follower2.db"),\n    }\n\n    from sqlalchemy.sql import Update, Delete\n    from sqlalchemy.orm import Session, sessionmaker\n    import random\n\n\n    class RoutingSession(Session):\n        def get_bind(self, mapper=None, clause=None):\n            if mapper and issubclass(mapper.class_, MyOtherClass):\n                return engines["other"]\n            elif self._flushing or isinstance(clause, (Update, Delete)):\n                # NOTE: this is for example, however in practice reader/writer\n                # splits are likely more straightforward by using two distinct\n                # Sessions at the top of a "reader" or "writer" operation.\n                # See note below\n                return engines["leader"]\n            else:\n                return engines[random.choice(["follower1", "follower2"])]\n\nThe above :class:`.Session` class is plugged in using the ``class_``\nargument to :class:`.sessionmaker`::\n\n    Session = sessionmaker(class_=RoutingSession)\n\nThis approach can be combined with multiple :class:`_schema.MetaData` objects,\nusing an approach such as that of using the declarative ``__abstract__``\nkeyword, described at :ref:`declarative_abstract`.\n\n.. note:: While the above example illustrates routing of specific SQL statements\n   to a so-called "leader" or "follower" database based on whether or not the\n   statement expects to write data, this is likely not a practical approach,\n   as it leads to uncoordinated transaction behavior between reading\n   and writing within the same operation.  In practice, it\'s likely best\n   to construct the :class:`_orm.Session` up front as a "reader" or "writer"\n   session, based on the overall operation / transaction that\'s proceeding.\n   That way, an operation that will be writing data will also emit its read-queries\n   within the same transaction scope.  See the example at\n   :ref:`session_transaction_isolation_enginewide` for a recipe that sets up\n   one :class:`_orm.sessionmaker` for "read only" operations using autocommit\n   connections, and another for "write" operations which will include DML /\n   COMMIT.\n\n.. seealso::\n\n    `Django-style Database Routers in SQLAlchemy <https://techspot.zzzeek.org/2012/01/11/django-style-database-routers-in-sqlalchemy/>`_  - blog post on a more comprehensive example of :meth:`.Session.get_bind`\n\nHorizontal Partitioning\n-----------------------\n\nHorizontal partitioning partitions the rows of a single table (or a set of\ntables) across multiple databases.    The SQLAlchemy :class:`.Session`\ncontains support for this concept, however to use it fully requires that\n:class:`.Session` and :class:`_query.Query` subclasses are used.  A basic version\nof these subclasses are available in the :ref:`horizontal_sharding_toplevel`\nORM extension.   An example of use is at: :ref:`examples_sharding`.\n\n.. _bulk_operations:\n\nBulk Operations\n===============\n\n.. legacy::\n\n  SQLAlchemy 2.0 has integrated the :class:`_orm.Session` "bulk insert" and\n  "bulk update" capabilities into 2.0 style :meth:`_orm.Session.execute`\n  method, making direct use of :class:`_dml.Insert` and :class:`_dml.Update`\n  constructs. See the document at :doc:`queryguide/dml` for documentation,\n  including :ref:`orm_queryguide_legacy_bulk_insert` which illustrates migration\n  from the older methods to the new methods.\n',
        }
